import type { BibleBook } from '../bibleData';

// Auto-generated from public-domain sources: World English Bible (WEB, EN)
// and João Ferreira de Almeida (Almeida, PT), via seven1m/open-bibles (USFX).
// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: '1kings',
  name: '1 Reis',
  englishName: '1 Kings',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'Now king David was old and advanced in years; and they covered him with clothes, but he couldn’t keep warm.', pt: 'Ora, o rei Davi era já velho, de idade mui avançada; e por mais que o cobrissem de roupas não se aquecia.' },
      { v: 2, en: 'Therefore his servants said to him, “Let a young virgin be sought for my lord the king. Let her stand before the king, and cherish him; and let her lie in your bosom, that my lord the king may keep warm.”', pt: 'Disseram-lhe, pois, os seus servos: Busque-se para o rei meu senhor uma jovem donzela, que esteja perante o rei, e tenha cuidado dele; e durma no seu seio, para que o rei meu senhor se aqueça.' },
      { v: 3, en: 'So they sought for a beautiful young lady throughout all the borders of Israel, and found Abishag the Shunammite, and brought her to the king.', pt: 'Assim buscaram por todos os termos de Israel uma jovem formosa; e acharam Abisague, a sunamita, e a trouxeram ao rei.' },
      { v: 4, en: 'The young lady was very beautiful; and she cherished the king, and served him; but the king didn’t know her intimately.', pt: 'Era a jovem sobremaneira formosa; e cuidava do rei, e o servia; porém o rei não a conheceu.' },
      { v: 5, en: 'Then Adonijah the son of Haggith exalted himself, saying, “I will be king.” Then he prepared him chariots and horsemen, and fifty men to run before him.', pt: 'Então Adonias, filho de Hagite, se exaltou e disse: Eu reinarei. E preparou para si carros e cavaleiros, e cinqüenta homens que corressem adiante dele.' },
      { v: 6, en: 'His father had not displeased him at any time in saying, “Why have you done so?” and he was also a very handsome man; and he was born after Absalom.', pt: 'Ora, nunca seu pai o tinha contrariado, dizendo: Por que fizeste assim? Além disso, era ele muito formoso de parecer; e era mais moço do que Absalão.' },
      { v: 7, en: 'He conferred with Joab the son of Zeruiah, and with Abiathar the priest; and they followed Adonijah and helped him.', pt: 'E teve entendimento com Joabe, filho de Zeruia, e com o sacerdote Abiatar, os quais aderiram a ele e o ajudavam.' },
      { v: 8, en: 'But Zadok the priest, Benaiah the son of Jehoiada, Nathan the prophet, Shimei, Rei, and the mighty men who belonged to David, were not with Adonijah.', pt: 'Mas Zadoque, o sacerdote, e Benaías, filho de Jeoiada, e Natã, o profeta, e Simei, e Rei, e os valentes que Davi tinha, não eram por Adonias.' },
      { v: 9, en: 'Adonijah killed sheep, cattle, and fatlings by the stone of Zoheleth, which is beside En Rogel; and he called all his brothers, the king’s sons, and all the men of Judah, the king’s servants;', pt: 'Adonias matou ovelhas, bois e animais cevados, junto à pedra de Zoelete, que está perto de En-Rogel; e convidou a todos os seus irmãos, os filhos do rei, e a todos os homens de Judá, servos do rei;' },
      { v: 10, en: 'but he didn’t call Nathan the prophet, and Benaiah, and the mighty men, and Solomon his brother.', pt: 'porém a Natã, o profeta, e a Benaías, e aos valentes, e a Salomão, seu irmão, não os convidou.' },
      { v: 11, en: 'Then Nathan spoke to Bathsheba the mother of Solomon, saying, “Haven’t you heard that Adonijah the son of Haggith reigns, and David our lord doesn’t know it?', pt: 'Então falou Natã a Bate-Seba, mãe de Salomão, dizendo: Não ouviste que Adonias, filho de Hagite, reina? e que nosso senhor Davi não o sabe?' },
      { v: 12, en: 'Now therefore come, please let me give you counsel, that you may save your own life, and your son Solomon’s life.', pt: 'Vem, pois, agora e deixa-me dar-te um conselho, para que salves a tua vida, e a de teu filho Salomão.' },
      { v: 13, en: 'Go in to king David, and tell him, ‘Didn’t you, my lord, king, swear to your servant, saying, “Assuredly Solomon your son shall reign after me, and he shall sit on my throne?” Why then does Adonijah reign?’', pt: 'Vai à presença do rei Davi, e dize-lhe: Não juraste, ó rei meu senhor, à tua serva, dizendo: Certamente teu filho Salomão reinará depois de mim, e se assentará no meu trono? Por que, pois, reina Adonias?' },
      { v: 14, en: 'Behold, while you are still talking there with the king, I will also come in after you and confirm your words.”', pt: 'Eis que, estando tu ainda a falar com o rei, eu também entrarei depois de ti, e confirmarei as tuas palavras.' },
      { v: 15, en: 'Bathsheba went in to the king in his room. The king was very old; and Abishag the Shunammite was serving the king.', pt: 'Foi, pois, Bate-Seba à presença do rei na sua câmara. Ele era mui velho; e Abisague, a sunamita, o servia.' },
      { v: 16, en: 'Bathsheba bowed, and showed respect to the king. The king said, “What would you like?”', pt: 'Bate-Seba inclinou a cabeça, e se prostrou perante o rei. Então o rei lhe perguntou: Que queres?' },
      { v: 17, en: 'She said to him, “My lord, you swore by Yahweh your God to your servant, ‘Assuredly Solomon your son shall reign after me, and he shall sit on my throne.’', pt: 'Respondeu-lhe ela: Senhor meu, tu juraste à tua serva pelo Senhor teu Deus, dizendo: Salomão, teu filho, reinará depois de mim, e se assentará no meu trono.' },
      { v: 18, en: 'Now, behold, Adonijah reigns; and you, my lord the king, don’t know it.', pt: 'E agora eis que Adonias reina; e tu, ó rei meu senhor, não o sabes.' },
      { v: 19, en: 'He has slain cattle and fatlings and sheep in abundance, and has called all the sons of the king, Abiathar the priest, and Joab the captain of the army; but he hasn’t called Solomon your servant.', pt: 'Ele matou bois, animais cevados e ovelhas em abundância, e convidou a todos os filhos do rei, e a Abiatar, o sacerdote, e a Joabe, general do exército; mas a teu servo Salomão não o convidou.' },
      { v: 20, en: 'You, my lord the king, the eyes of all Israel are on you, that you should tell them who will sit on the throne of my lord the king after him.', pt: 'Mas, ó rei meu senhor, os olhos de todo o Israel estão sobre ti, para que lhes declares quem há de assentar-se no teu trono depois de ti.' },
      { v: 21, en: 'Otherwise it will happen, when my lord the king sleeps with his fathers, that I and my son Solomon will be considered criminals.”', pt: 'Doutro modo sucederá que, quando o rei meu senhor dormir com seus pais, eu e Salomão meu filho seremos tidos por ofensores.' },
      { v: 22, en: 'Behold, while she was still talking with the king, Nathan the prophet came in.', pt: 'Enquanto ela ainda falava com o rei, eis que chegou o profeta Natã.' },
      { v: 23, en: 'They told the king, saying, “Behold, Nathan the prophet!” When he had come in before the king, he bowed himself before the king with his face to the ground.', pt: 'E o fizeram saber ao rei, dizendo: Eis aí está o profeta Natã. Entrou Natã à presença do rei, inclinou-se perante ele com o rosto em terra,' },
      { v: 24, en: 'Nathan said, “My lord, king, have you said, ‘Adonijah shall reign after me, and he shall sit on my throne?’', pt: 'e disse: ç rei meu senhor, acaso disseste: Adonias reinará depois de mim, e se assentará no meu trono?' },
      { v: 25, en: 'For he has gone down today, and has slain cattle, fatlings, and sheep in abundance, and has called all the king’s sons, the captains of the army, and Abiathar the priest. Behold, they are eating and drinking before him, and saying, ‘Long live king Adonijah!’', pt: 'Pois ele hoje desceu, e matou bois, animais cevados e ovelhas em abundância, e convidou a todos os filhos do rei, e aos chefes do exército, e ao sacerdote Abiatar; e eis que comem e bebem perante ele, e dizem: Viva o rei Adonias!' },
      { v: 26, en: 'But he hasn’t called me, even me your servant, Zadok the priest, Benaiah the son of Jehoiada, and your servant Solomon.', pt: 'Porém a mim teu servo, e ao sacerdote Zadoque, e a Benaías, filho de Jeoiada, e ao teu servo Salomão, não convidou.' },
      { v: 27, en: 'Was this thing done by my lord the king, and you haven’t shown to your servants who should sit on the throne of my lord the king after him?”', pt: 'Foi feito isso da parte do rei meu senhor? e não fizeste saber a teu servo quem havia de assentar-se no teu trono depois de ti?' },
      { v: 28, en: 'Then king David answered, “Call Bathsheba in to me.” She came into the king’s presence and stood before the king.', pt: 'Respondeu o rei Davi: Chamai-me a Bate-Seba. E ela entrou à presença do rei, e ficou de pé diante dele.' },
      { v: 29, en: 'The king swore, and said, “As Yahweh lives, who has redeemed my soul out of all adversity,', pt: 'Então o rei jurou, dizendo: Vive o Senhor, o qual remiu a minha alma de toda a angústia,' },
      { v: 30, en: 'most certainly as I swore to you by Yahweh, the God of Israel, saying, ‘Assuredly Solomon your son shall reign after me, and he shall sit on my throne in my place;’ I will most certainly do this today.”', pt: 'que, assim como te jurei pelo Senhor Deus de Israel, dizendo: Teu filho Salomão há de reinar depois de mim, e ele se assentará no meu trono, em meu lugar; assim mesmo o cumprirei hoje.' },
      { v: 31, en: 'Then Bathsheba bowed with her face to the earth, and showed respect to the king, and said, “Let my lord king David live forever!”', pt: 'Então Bate-Seba, inclinando-se com o rosto em terra perante o rei, fez-lhe reverência e disse: Viva para sempre o rei Davi meu senhor!' },
      { v: 32, en: 'King David said, “Call to me Zadok the priest, Nathan the prophet, and Benaiah the son of Jehoiada.” They came before the king.', pt: 'Depois disse o rei Davi: Chamai-me a Zadoque, o sacerdote, e a Natã, o profeta, e a Benaías, filho de Jeoiada. E estes entraram à presença do rei.' },
      { v: 33, en: 'The king said to them, “Take with you the servants of your lord, and cause Solomon my son to ride on my own mule, and bring him down to Gihon.', pt: 'E o rei lhes disse: Tomai convosco os servos de vosso senhor, fazei montar meu filho Salomão na minha mula, e levai-o a Giom.' },
      { v: 34, en: 'Let Zadok the priest and Nathan the prophet anoint him there king over Israel. Blow the trumpet, and say, ‘Long live king Solomon!’', pt: 'E Zadoque, o sacerdote, com Natã, o profeta, ali o ungirão rei sobre Israel. E tocareis a trombeta, e direis: Viva o rei Salomão!' },
      { v: 35, en: 'Then come up after him, and he shall come and sit on my throne; for he shall be king in my place. I have appointed him to be prince over Israel and over Judah.”', pt: 'Então subireis após ele, e ele virá e se assentará no meu trono; pois reinará em meu lugar, porquanto o tenho designado para ser príncipe sobre Israel e sobre Judá.' },
      { v: 36, en: 'Benaiah the son of Jehoiada answered the king, and said, “Amen. May Yahweh, the God of my lord the king, say so.', pt: 'Ao que Benaías, filho de Jeoiada, respondeu ao rei, dizendo: Amém; assim o diga também o Senhor Deus do rei meu senhor.' },
      { v: 37, en: 'As Yahweh has been with my lord the king, even so may he be with Solomon, and make his throne greater than the throne of my lord king David.”', pt: 'Como o Senhor foi com o rei meu senhor, assim seja ele com Salomão, e faça que o seu trono seja maior do que o trono do rei Davi meu senhor.' },
      { v: 38, en: 'So Zadok the priest, Nathan the prophet, Benaiah the son of Jehoiada, and the Cherethites and the Pelethites went down and had Solomon ride on king David’s mule, and brought him to Gihon.', pt: 'Pelo que desceram Zadoque, o sacerdote, e Natã, o profeta, e Benaías, filho de Jeoiada, e os quereteus, e os peleteus, e fizeram montar Salomão na mula que era do rei Davi, e o levaram a Giom.' },
      { v: 39, en: 'Zadok the priest took the horn of oil from the Tent, and anointed Solomon. They blew the trumpet; and all the people said, “Long live king Solomon!”', pt: 'Então Zadoque, o sacerdote, tomou do tabernáculo o vaso do azeite e ungiu a Salomão. Então tocaram a trombeta, e todo o povo disse: Viva o rei Salomão!' },
      { v: 40, en: 'All the people came up after him, and the people piped with pipes, and rejoiced with great joy, so that the earth shook with their sound.', pt: 'E todo o povo subiu após ele, tocando flauta e alegrando-se sobremaneira, de modo que a terra retiniu com o seu clamor.' },
      { v: 41, en: 'Adonijah and all the guests who were with him heard it as they had finished eating. When Joab heard the sound of the trumpet, he said, “Why is this noise of the city being in an uproar?”', pt: 'Adonias e todos os convidados que estavam com ele o ouviram, ao acabarem de comer. E ouvindo Joabe o soar das trombetas, disse: Que quer dizer este alvoroço na cidade?' },
      { v: 42, en: 'While he yet spoke, behold, Jonathan the son of Abiathar the priest came; and Adonijah said, “Come in; for you are a worthy man, and bring good news.”', pt: 'Ele ainda estava falando, quando chegou Jônatas, filho de Abiatar, o sacerdote; e disse Adonias: Entra, porque és homem de bem, e trazes boas novas.' },
      { v: 43, en: 'Jonathan answered Adonijah, “Most certainly our lord king David has made Solomon king.', pt: 'Respondeu Jônatas a Adonias: Deveras! O rei Davi, nosso senhor, constituiu rei a Salomão.' },
      { v: 44, en: 'The king has sent with him Zadok the priest, Nathan the prophet, Benaiah the son of Jehoiada, and the Cherethites and the Pelethites; and they have caused him to ride on the king’s mule.', pt: 'E o rei enviou com ele Zadoque, o sacerdote, e Natã, o profeta, e Benaías, filho de Jeoiada, os quereteus e os peleteus; e eles o fizeram montar na mula do rei.' },
      { v: 45, en: 'Zadok the priest and Nathan the prophet have anointed him king in Gihon. They have come up from there rejoicing, so that the city rang again. This is the noise that you have heard.', pt: 'E Zadoque, o sacerdote, e Natã, o profeta, ungiram-no rei em Giom; e dali subiram cheios de alegria, e a cidade está alvoroçada. Este é o clamor que ouvistes.' },
      { v: 46, en: 'Also, Solomon sits on the throne of the kingdom.', pt: 'E Salomão já está assentado no trono do reino.' },
      { v: 47, en: 'Moreover the king’s servants came to bless our lord king David, saying, ‘May your God make the name of Solomon better than your name, and make his throne greater than your throne;’ and the king bowed himself on the bed.', pt: 'Além disso os servos do rei vieram abençoar o nosso senhor, o rei Davi, dizendo: Faça teu Deus o nome de Salomão mais célebre do que o teu nome, e faça o seu trono maior do que o teu trono. E o rei se inclinou no leito.' },
      { v: 48, en: 'Also thus said the king, ‘Blessed be Yahweh, the God of Israel, who has given one to sit on my throne today, my eyes even seeing it.’”', pt: 'Também assim falou o rei: Bendito o Senhor Deus de Israel, que hoje tem dado quem se assente no meu trono, e que os meus olhos o vissem.' },
      { v: 49, en: 'All the guests of Adonijah were afraid, and rose up, and each man went his way.', pt: 'Então, tomados de pavor, levantaram-se todos os convidados que estavam com Adonias, e cada qual se foi seu caminho.' },
      { v: 50, en: 'Adonijah was afraid because of Solomon; and he arose, and went, and hung onto the horns of the altar.', pt: 'Adonias, porém, temeu a Salomão e, levantando-se, foi apegar-se às pontas do altar.' },
      { v: 51, en: 'Solomon was told, “Behold, Adonijah fears king Solomon; for, behold, he is hanging onto the horns of the altar, saying, ‘Let king Solomon swear to me first that he will not kill his servant with the sword.’”', pt: 'E foi dito a Salomão: Eis que Adonias teme ao rei Salomão; pois que se apegou às pontas do altar, dizendo: Jure-me hoje o rei Salomão que não matará o seu servo à espada.' },
      { v: 52, en: 'Solomon said, “If he shows himself a worthy man, not a hair of his shall fall to the earth; but if wickedness is found in him, he shall die.”', pt: 'Ao que disse Salomão: Se ele se houver como homem de bem, nem um só de seus cabelos cairá em terra; se, porém, se houver dolosamente, morrerá.' },
      { v: 53, en: 'So king Solomon sent, and they brought him down from the altar. He came and bowed down to king Solomon; and Solomon said to him, “Go to your house.”', pt: 'Então o rei Salomão deu ordem, e tiraram Adonias do altar. E vindo ele, inclinou-se perante o rei Salomão, o qual lhe disse: Vai para tua casa.' },
    ],
    2: [
      { v: 1, en: 'Now the days of David came near that he should die; and he commanded Solomon his son, saying,', pt: 'Ora, aproximando-se o dia da morte de Davi, deu ele ordem a Salomão, seu filho, dizendo:' },
      { v: 2, en: '“I am going the way of all the earth. You be strong therefore, and show yourself a man;', pt: 'Eu vou pelo caminho de toda a terra; sê forte, pois, e porta-te como homem.' },
      { v: 3, en: 'and keep the instruction of Yahweh your God, to walk in his ways, to keep his statutes, his commandments, his ordinances, and his testimonies, according to that which is written in the law of Moses, that you may prosper in all that you do, and wherever you turn yourself.', pt: 'Guarda as ordenanças do Senhor teu Deus, andando nos seus caminhos, e observando os seus estatutos, os seus mandamentos, os seus preceitos e os seus testemunhos, como está escrito na lei de Moisés, para que prosperes em tudo quanto fizeres e por onde quer que fores,' },
      { v: 4, en: 'Then Yahweh may establish his word which he spoke concerning me, saying, ‘If your children are careful of their way, to walk before me in truth with all their heart and with all their soul, there shall not fail you,’ he said, ‘a man on the throne of Israel.’', pt: 'e para que o Senhor confirme a palavra que falou acerca de mim, dizendo: Se teus filhos guardarem os seus caminhos, andando perante a minha face fielmente, com todo o seu coração e com toda a sua alma, nunca te faltará sucessor ao trono de Israel.' },
      { v: 5, en: '“Moreover you know also what Joab the son of Zeruiah did to me, even what he did to the two captains of the armies of Israel, to Abner the son of Ner, and to Amasa the son of Jether, whom he killed, and shed the blood of war in peace, and put the blood of war on his sash that was around his waist, and in his shoes that were on his feet.', pt: 'Tu sabes também o que me fez Joabe, filho de Zeruia, a saber, o que fez aos dois chefes do exército de Israel, a Abner, filho de Ner, e a Amasa, filho de Jeter, os quais ele matou, e em tempo de paz derramou o sangue de guerra, manchando com ele o cinto que tinha nos lombos, e os sapatos que trazia nos pés.' },
      { v: 6, en: 'Do therefore according to your wisdom, and don’t let his gray head go down to Sheol in peace.', pt: 'Faze, pois, segundo a tua sabedoria, e não permitas que suas cãs desçam à sepultura em paz.' },
      { v: 7, en: 'But show kindness to the sons of Barzillai the Gileadite, and let them be among those who eat at your table; for so they came to me when I fled from Absalom your brother.', pt: 'Mas para com os filhos de Barzilai, o gileadita, usa de benevolência, e estejam eles entre os que comem à tua mesa; porque assim se houveram comigo, quando eu fugia por causa de teu irmão Absalão.' },
      { v: 8, en: '“Behold, there is with you Shimei the son of Gera, the Benjamite, of Bahurim, who cursed me with a grievous curse in the day when I went to Mahanaim; but he came down to meet me at the Jordan, and I swore to him by Yahweh, saying, ‘I will not put you to death with the sword.’', pt: 'E eis que também contigo está Simei, filho de Gêra, benjamita, de Baurim, que me lançou atroz maldição, no dia em que eu ia a Maanaim; porém ele saiu a encontrar-se comigo junto ao Jordão, e eu lhe jurei pelo Senhor, dizendo: Não te matarei à espada.' },
      { v: 9, en: 'Now therefore don’t hold him guiltless, for you are a wise man; and you will know what you ought to do to him, and you shall bring his gray head down to Sheol with blood.”', pt: 'Agora, porém, não o tenhas por inocente; pois és homem sábio, e bem saberás o que lhe hás de fazer; farás com que as suas cãs desçam à sepultura com sangue.' },
      { v: 10, en: 'David slept with his fathers, and was buried in David’s city.', pt: 'Depois Davi dormiu com seus pais, e foi sepultado na cidade de Davi.' },
      { v: 11, en: 'The days that David reigned over Israel were forty years; he reigned seven years in Hebron, and he reigned thirty-three years in Jerusalem.', pt: 'E foi o tempo que Davi reinou sobre Israel quarenta anos: sete anos reinou em Hebrom, e em Jerusalém reinou trinta e três anos.' },
      { v: 12, en: 'Solomon sat on David his father’s throne; and his kingdom was firmly established.', pt: 'Salomão, pois, assentou-se no trono de Davi, seu pai; e o seu reino se fortificou sobremaneira.' },
      { v: 13, en: 'Then Adonijah the son of Haggith came to Bathsheba the mother of Solomon. She said, “Do you come peaceably?” He said, “Peaceably.', pt: 'Então Adonias, filho de Hagite, veio a Bate-Seba, mãe de Salomão; e perguntou ela: De paz é a tua vinda? Respondeu ele: É de paz.' },
      { v: 14, en: 'He said moreover, I have something to tell you.” She said, “Say on.”', pt: 'E acrescentou: Uma palavra tenho que dizer-te. Respondeu ela: Fala.' },
      { v: 15, en: 'He said, “You know that the kingdom was mine, and that all Israel set their faces on me, that I should reign. However the kingdom is turned around, and has become my brother’s; for it was his from Yahweh.', pt: 'Disse, pois, ele: Bem sabes que o reino era meu, e que todo o Israel tinha posto a vista em mim para que eu viesse a reinar; contudo o reino se transferiu e veio a ser de meu irmão, porque foi feito seu pelo Senhor.' },
      { v: 16, en: 'Now I ask one petition of you. Don’t deny me.” She said to him, “Say on.”', pt: 'Agora uma só coisa te peço; não ma recuses. Ela lhe disse: Fala.' },
      { v: 17, en: 'He said, “Please speak to Solomon the king (for he will not tell you ‘no’), that he give me Abishag the Shunammite as wife.”', pt: 'E ele disse: Peço-te que fales ao rei Salomão (porque ele não to recusará) , que me dê por mulher a Abisague, a sunamita.' },
      { v: 18, en: 'Bathsheba said, “Alright. I will speak for you to the king.”', pt: 'Respondeu Bate-Seba: Pois bem; eu falarei por ti ao rei.' },
      { v: 19, en: 'Bathsheba therefore went to king Solomon, to speak to him for Adonijah. The king rose up to meet her, and bowed himself to her, and sat down on his throne, and caused a throne to be set for the king’s mother; and she sat on his right hand.', pt: 'Foi, pois, Bate-Seba ter com o rei Salomão, para falar-lhe por Adonias. E o rei se levantou a encontrar-se com ela, e se inclinou diante dela; então, assentando-se no seu trono, mandou que pusessem um trono para a rainha-mãe; e ela se assentou à sua direita.' },
      { v: 20, en: 'Then she said, “I ask one small petition of you; don’t deny me.” The king said to her, “Ask on, my mother; for I will not deny you.”', pt: 'Então disse ela: Só uma pequena coisa te peço; não ma recuses. Respondeu-lhe o rei: Pede, minha mãe, porque não ta recusarei.' },
      { v: 21, en: 'She said, “Let Abishag the Shunammite be given to Adonijah your brother as wife.”', pt: 'E ela disse: Dê-se Abisague, a sunamita, por mulher a teu irmão Adonias.' },
      { v: 22, en: 'King Solomon answered his mother, “Why do you ask Abishag the Shunammite for Adonijah? Ask for him the kingdom also; for he is my elder brother; even for him, and for Abiathar the priest, and for Joab the son of Zeruiah.”', pt: 'Então respondeu o rei Salomão, e disse a sua mãe: E por que pedes Abisague, a sunamita, para Adonias? Pede também para ele o reino (porque é meu irmão mais velho); sim, para ele, e também para Abiatar, o sacerdote, e para Joabe, filho de Zeruia.' },
      { v: 23, en: 'Then king Solomon swore by Yahweh, saying, “God do so to me, and more also, if Adonijah has not spoken this word against his own life.', pt: 'E jurou o rei Salomão pelo Senhor, dizendo: Assim Deus me faça, e outro tanto, se não falou Adonias esta palavra contra a sua vida.' },
      { v: 24, en: 'Now therefore as Yahweh lives, who has established me, and set me on my father David’s throne, and who has made me a house as he promised, surely Adonijah shall be put to death today.”', pt: 'Agora, pois, vive o Senhor, que me confirmou e me fez assentar no trono de Davi, meu pai, e que me estabeleceu casa, como tinha dito, que hoje será morto Adonias.' },
      { v: 25, en: 'King Solomon sent Benaiah the son of Jehoiada; and he fell on him, so that he died.', pt: 'E o rei Salomão deu ordem a Benaías, filho de Jeoiada, o qual feriu a Adonias, de modo que morreu.' },
      { v: 26, en: 'To Abiathar the priest the king said, “Go to Anathoth, to your own fields; for you are worthy of death. But I will not at this time put you to death, because you bore the Lord Yahweh’s ark before David my father, and because you were afflicted in all in which my father was afflicted.”', pt: 'Também a Abiatar, o sacerdete, disse o rei: Vai para Anatote, para os teus campos, porque és homem digno de morte; porém hoje não te matarei, porquanto levaste a arca do Senhor Deus diante de Davi, meu pai, e porquanto participaste de todas as aflições de meu pai.' },
      { v: 27, en: 'So Solomon thrust Abiathar out from being priest to Yahweh, that he might fulfill Yahweh’s word, which he spoke concerning the house of Eli in Shiloh.', pt: 'Salomão, pois, expulsou Abiatar, para que não fosse sacerdote do Senhor, assim cumprindo a palavra que o Senhor tinha dito acerca da casa de Eli em Siló.' },
      { v: 28, en: 'This news came to Joab; for Joab had followed Adonijah, although he didn’t follow Absalom. Joab fled to Yahweh’s Tent, and held onto the horns of the altar.', pt: 'Ora, veio esta notícia a Joabe (pois Joabe se desviara após Adonias, ainda que não se tinha desviado após Absalão) ; pelo que Joabe fugiu para o tabernáculo do Senhor, e apegou-se as pontas do altar.' },
      { v: 29, en: 'King Solomon was told, “Joab has fled to Yahweh’s Tent, and behold, he is by the altar.” Then Solomon sent Benaiah the son of Jehoiada, saying, “Go, fall on him.”', pt: 'E disseram ao rei Salomão: Joabe fugiu para o tabernáculo do Senhor; e eis que está junto ao altar. Então Salomão enviou Benaías, filho de Jeoiada, dizendo: Vai, mata-o.' },
      { v: 30, en: 'Benaiah came to Yahweh’s Tent, and said to him, “Thus says the king, ‘Come out!’” He said, “No; but I will die here.” Benaiah brought the king word again, saying, “Thus said Joab, and thus he answered me.”', pt: 'Foi, pois, Benaías ao tabernáculo do Senhor, e disse a Joabe: Assim diz o rei: Sai daí. Respondeu Joabe: Não! porém aqui morrerei. E Benaías tornou com a resposta ao rei, dizendo: Assim falou Joabe, e assim me respondeu.' },
      { v: 31, en: 'The king said to him, “Do as he has said, and fall on him, and bury him; that you may take away the blood, which Joab shed without cause, from me and from my father’s house.', pt: 'Ao que lhe disse o rei: Faze como ele disse; mata-o, e sepulta-o, para que tires de sobre mim e de sobre a casa de meu pai o sangue que Joabe sem causa derramou.' },
      { v: 32, en: 'Yahweh will return his blood on his own head, because he fell on two men more righteous and better than he, and killed them with the sword, and my father David didn’t know it: Abner the son of Ner, captain of the army of Israel, and Amasa the son of Jether, captain of the army of Judah.', pt: 'Assim o Senhor fará recair o sangue dele sobre a sua cabeça, porque deu sobre dois homens mais justos e melhores do que ele, e os matou à espada, sem que meu pai Davi o soubesse, a saber: a Abner, filho de Ner, chefe do exército de Israel, e a Amasa, filho de Jeter, chefe do exército de Judá.' },
      { v: 33, en: 'So their blood will return on the head of Joab, and on the head of his offspring forever. But for David, for his offspring, for his house, and for his throne, there will be peace forever from Yahweh.”', pt: 'Assim recairá o sangue destes sobre a cabeça de Joabe e sobre a cabeça da sua descendência para sempre; mas a Davi, e à sua descendência, e à sua casa, e ao seu trono, o Senhor dará paz para sempre.' },
      { v: 34, en: 'Then Benaiah the son of Jehoiada went up and fell on him, and killed him; and he was buried in his own house in the wilderness.', pt: 'Então Benaías, filho de Jeoiada, subiu e, arremetendo contra Joabe, o matou. E foi sepultado em sua casa, no deserto.' },
      { v: 35, en: 'The king put Benaiah the son of Jehoiada in his place over the army; and the king put Zadok the priest in the place of Abiathar.', pt: 'Em lugar dele o rei pôs a Benaías, filho de Jeoiada, sobre o exército; e a Zadoque, o sacerdote, pôs em lugar de Abiatar.' },
      { v: 36, en: 'The king sent and called for Shimei, and said to him, “Build yourself a house in Jerusalem, and live there, and don’t go anywhere else.', pt: 'Depois o rei mandou chamar a Simei e lhe disse: Edifica para ti uma casa em Jerusalém, habita aí, e daí não saias, nem para uma nem para outra parte.' },
      { v: 37, en: 'For on the day you go out and pass over the brook Kidron, know for certain that you will surely die. Your blood will be on your own head.”', pt: 'E fica sabendo que, no dia em que saíres e passares o ribeiro de Cedrom, de certo hás de morrer. O teu sangue será sobre a tua cabeça.' },
      { v: 38, en: 'Shimei said to the king, “What you say is good. As my lord the king has said, so will your servant do.” Shimei lived in Jerusalem many days.', pt: 'Respondeu Simei ao rei: Boa é essa palavra; como tem dito o rei meu senhor, assim fará o teu servo. E Simei habitou em Jerusalém muitos dias.' },
      { v: 39, en: 'At the end of three years, two of Shimei’s slaves ran away to Achish, son of Maacah, king of Gath. They told Shimei, saying, “Behold, your slaves are in Gath.”', pt: 'Sucedeu porém que, ao cabo de três anos, dois servos de Simei fugiram para Aquis, filho de Maacá, rei de Gate. E deram parte a Simei, dizendo: Eis que teus servos estão em Gate.' },
      { v: 40, en: 'Shimei arose, saddled his donkey, and went to Gath to Achish, to seek his slaves; and Shimei went, and brought his slaves from Gath.', pt: 'Então Simei se levantou, albardou o seu jumento e foi a Gate ter com Aquis, em busca dos seus servos; assim foi Simei, e os trouxe de Gate.' },
      { v: 41, en: 'Solomon was told that Shimei had gone from Jerusalem to Gath, and had come again.', pt: 'Disseram a Salomão que Simei fora de Jerusalém a Gate, e já havia voltado.' },
      { v: 42, en: 'The king sent and called for Shimei, and said to him, “Didn’t I adjure you by Yahweh, and warn you, saying, ‘Know for certain, that on the day you go out, and walk anywhere else, you shall surely die?’ You said to me, ‘The saying that I have heard is good.’', pt: 'Então o rei mandou chamar a Simei e lhe disse: Não te conjurei pelo Senhor e não te protestei, dizendo: No dia em que saíres para qualquer parte, sabe de certo que hás de morrer? E tu me disseste: Boa é essa palavra que ouvi.' },
      { v: 43, en: 'Why then have you not kept the oath of Yahweh, and the commandment that I have instructed you with?”', pt: 'Por que, então, não guardaste o juramento do Senhor, e a ordem que te dei?' },
      { v: 44, en: 'The king said moreover to Shimei, “You know in your heart all the wickedness that you did to David my father. Therefore Yahweh will return your wickedness on your own head.', pt: 'Disse-lhe mais: Bem sabes tu, e o teu coração reconhece toda a maldade que fizeste a Davi, meu pai; pelo que o Senhor fará recair a tua maldade sobre a tua cabeça.' },
      { v: 45, en: 'But king Solomon will be blessed, and David’s throne will be established before Yahweh forever.”', pt: 'Mas o rei Salomão será abençoado, e o trono de Davi será confirmado perante o Senhor para sempre:' },
      { v: 46, en: 'So the king commanded Benaiah the son of Jehoiada; and he went out, and fell on him, so that he died. The kingdom was established in the hand of Solomon.', pt: 'E o rei deu ordem a Benaías, filho de Jeoiada, o qual saiu, e feriu a Simei, de modo que morreu. Assim foi confirmado o reino na mão de Salomão.' },
    ],
    3: [
      { v: 1, en: 'Solomon made an alliance with Pharaoh king of Egypt, and took Pharaoh’s daughter, and brought her into David’s city, until he had finished building his own house, Yahweh’s house, and the wall around Jerusalem.', pt: 'Ora, Salomão aparentou-se com Faraó, rei do Egito, pois tomou por mulher a filha dele; e a trouxe à cidade de Davi, até que acabasse de edificar a sua casa, e a casa do Senhor, e a muralha de Jerusalém em redor.' },
      { v: 2, en: 'However the people sacrificed in the high places, because there was not yet a house built for Yahweh’s name.', pt: 'Entretanto o povo oferecia sacrifícios sobre os altos, porque até aqueles dias ainda não se havia edificado casa ao nome do Senhor.' },
      { v: 3, en: 'Solomon loved Yahweh, walking in the statutes of David his father; except that he sacrificed and burned incense in the high places.', pt: 'E Salomão amava ao Senhor, andando nos estatutos de Davi, seu pai; exceto que nos altos oferecia sacrifícios e queimava incenso.' },
      { v: 4, en: 'The king went to Gibeon to sacrifice there; for that was the great high place. Solomon offered a thousand burnt offerings on that altar.', pt: 'Foi, pois, o rei a Gibeão para oferecer sacrifícios ali, porque aquele era o principal dentre os altos; mil holocaustos sacrificou Salomão naquele altar.' },
      { v: 5, en: 'In Gibeon, Yahweh appeared to Solomon in a dream by night; and God said, “Ask for what I should give you.”', pt: 'Em Gibeão apareceu o Senhor a Salomão de noite em sonhos, e disse-lhe: Pede o que queres que eu te dê.' },
      { v: 6, en: 'Solomon said, “You have shown to your servant David my father great loving kindness, because he walked before you in truth, in righteousness, and in uprightness of heart with you. You have kept for him this great loving kindness, that you have given him a son to sit on his throne, as it is today.', pt: 'Respondeu Salomão: De grande benevolência usaste para com teu servo Dai, meu pai, porquanto ele andou diante de ti em verdade, em justiça, e em retidão de coração para contigo; e guardaste-lhe esta grande benevolência, e lhe deste um filho, que se assentasse no seu trono, como se vê neste dia.' },
      { v: 7, en: 'Now, Yahweh my God, you have made your servant king instead of David my father. I am just a little child. I don’t know how to go out or come in.', pt: 'Agora, pois, ó Senhor meu Deus, tu fizeste reinar teu servo em lugar de Davi, meu pai. E eu sou apenas um menino pequeno; nao sei como sair, nem como entrar.' },
      { v: 8, en: 'Your servant is among your people which you have chosen, a great people, that can’t be numbered or counted for multitude.', pt: 'Teu servo está no meio do teu povo que elegeste, povo grande, que nem se pode contar, nem numerar, pela sua multidão.' },
      { v: 9, en: 'Give your servant therefore an understanding heart to judge your people, that I may discern between good and evil; for who is able to judge this great people of yours?”', pt: 'Dá, pois, a teu servo um coração entendido para julgar o teu povo, para que prudentemente discirna entre o bem e o mal; porque, quem poderia julgar a este teu tão grande povo?' },
      { v: 10, en: 'This request pleased the Lord, that Solomon had asked this thing.', pt: 'E pareceu bem aos olhos do Senhor o ter Salomão pedido tal coisa.' },
      { v: 11, en: 'God said to him, “Because you have asked this thing, and have not asked for yourself long life, nor have you asked for riches for yourself, nor have you asked for the life of your enemies, but have asked for yourself understanding to discern justice;', pt: 'Pelo que Deus lhe disse: Porquanto pediste isso, e não pediste para ti muitos dias, nem riquezas, nem a vida de teus inimigos, mas pediste entendimento para discernires o que é justo,' },
      { v: 12, en: 'behold, I have done according to your word. Behold, I have given you a wise and understanding heart; so that there has been no one like you before you, and after you none will arise like you.', pt: 'eis que faço segundo as tuas palavras. Eis que te dou um coração tão sábio e entendido, que antes de ti teu igual não houve, e depois de ti teu igual não se levantará.' },
      { v: 13, en: 'I have also given you that which you have not asked, both riches and honor, so that there will not be any among the kings like you for all your days.', pt: 'Também te dou o que não pediste, assim riquezas como glória; de modo que não haverá teu igual entre os reis, por todos os teus dias.' },
      { v: 14, en: 'If you will walk in my ways, to keep my statutes and my commandments, as your father David walked, then I will lengthen your days.”', pt: 'E ainda, se andares nos meus caminhos, guardando os meus estatutos e os meus mandamentos, como andou Davi,' },
      { v: 15, en: 'Solomon awoke; and behold, it was a dream. Then he came to Jerusalem, and stood before the ark of Yahweh’s covenant, and offered up burnt offerings, offered peace offerings, and made a feast for all his servants.', pt: 'Então Salomão acordou, e eis que era sonho. E, voltando ele a Jerusalém, pôs-se diante da arca do pacto do Senhor, sacrificou holocaustos e preparou sacrifícios pacíficos, e deu um banquete a todos os seus servos.' },
      { v: 16, en: 'Then two women who were prostitutes came to the king, and stood before him.', pt: 'Então vieram duas mulheres prostitutas ter com o rei, e se puseram diante dele.' },
      { v: 17, en: 'The one woman said, “Oh, my lord, I and this woman dwell in one house. I delivered a child with her in the house.', pt: 'E disse-lhe uma das mulheres: Ah, meu senhor! eu e esta mulher moramos na mesma casa; e tive um filho, estando com ela naquela casa.' },
      { v: 18, en: 'The third day after I delivered, this woman delivered also. We were together. There was no stranger with us in the house, just us two in the house.', pt: 'E sucedeu que, no terceiro dia depois de meu parto, também esta mulher teve um filho. Estávamos juntas; nenhuma pessoa estranha estava conosco na casa; somente nós duas estávamos ali.' },
      { v: 19, en: 'This woman’s child died in the night, because she lay on it.', pt: 'Ora, durante a noite morreu o filho desta mulher, porquanto se deitara sobre ele.' },
      { v: 20, en: 'She arose at midnight, and took my son from beside me, while your servant slept, and laid it in her bosom, and laid her dead child in my bosom.', pt: 'E ela se levantou no decorrer da noite, tirou do meu lado o meu filho, enquanto a tua serva dormia, e o deitou no seu seio, e a seu filho morto deitou-o no meu seio.' },
      { v: 21, en: 'When I rose in the morning to nurse my child, behold, it was dead; but when I had looked at it in the morning, behold, it was not my son, whom I bore.”', pt: 'Quando me levantei pela manhã, para dar de mamar a meu filho, eis que estava morto; mas, atentando eu para ele à luz do dia, eis que não era o filho que me nascera.' },
      { v: 22, en: 'The other woman said, “No; but the living one is my son, and the dead one is your son.” The first one said, “No; but the dead one is your son, and the living one is my son.” Thus they spoke before the king.', pt: 'Então disse a outra mulher: Não, mas o vivo é meu filho, e teu filho o morto. Replicou a primeira: Não; o morto é teu filho, e meu filho o vivo. Assim falaram perante o rei.' },
      { v: 23, en: 'Then the king said, “One says, ‘This is my son who lives, and your son is the dead;’ and the other says, ‘No; but your son is the dead one, and my son is the living one.’”', pt: 'Então disse o rei: Esta diz : Este que vive é meu filho, e teu filho o morto; e esta outra diz: Não; o morto é teu filho, e meu filho o vivo.' },
      { v: 24, en: 'The king said, “Get me a sword.” So they brought a sword before the king.', pt: 'Disse mais o rei: Trazei-me uma espada. E trouxeram uma espada diante dele.' },
      { v: 25, en: 'The king said, “Divide the living child in two, and give half to the one, and half to the other.”', pt: 'E disse o rei: Dividi em duas partes o menino vivo, e dai a metade a uma, e metade a outra.' },
      { v: 26, en: 'Then the woman whose the living child was spoke to the king, for her heart yearned over her son, and she said, “Oh, my lord, give her the living child, and in no way kill him!” But the other said, “He shall be neither mine nor yours. Divide him.”', pt: 'Mas a mulher cujo filho er suas entranhas se lhe enterneceram por seu filho), e disse: Ah, meu senhor! dai-lhe o menino vivo, e de modo nenhum o mateis. A outra, porém, disse: Não será meu, nem teu; dividi-o.' },
      { v: 27, en: 'Then the king answered, “Give her the living child, and definitely do not kill him. She is his mother.”', pt: 'Respondeu, então, o rei: Dai à primeira o menino vivo, e de modo nenhum o mateis; ela é sua mãe.' },
      { v: 28, en: 'All Israel heard of the judgment which the king had judged; and they feared the king; for they saw that the wisdom of God was in him, to do justice.', pt: 'E todo o Israel ouviu a sentença que o rei proferira, e temeu ao rei; porque viu que havia nele a sabedoria de Deus para fazer justiça.' },
    ],
    4: [
      { v: 1, en: 'King Solomon was king over all Israel.', pt: 'Assim foi Salomão rei sobre todo o Israel.' },
      { v: 2, en: 'These were the princes whom he had: Azariah the son of Zadok, the priest;', pt: 'E estes eram os príncipes que tinha: Azarias, filho de Zadoque, era sacerdote;' },
      { v: 3, en: 'Elihoreph and Ahijah, the sons of Shisha, scribes; Jehoshaphat the son of Ahilud, the recorder;', pt: 'Eliorefe e Aías, filhos de Sisa, secretários; Jeosafá, filho de Ailude, cronista;' },
      { v: 4, en: 'Benaiah the son of Jehoiada was over the army; Zadok and Abiathar were priests;', pt: 'Benaías, filho de Jeoiada, estava sobre o exército; Zadoque e Abiatar eram sacerdotes;' },
      { v: 5, en: 'Azariah the son of Nathan was over the officers; Zabud the son of Nathan was chief minister, the king’s friend;', pt: 'Azarias, filho de Natã, estava sobre os intendentes; Zabude, filho de Natã, era o oficial-mor, amigo do rei;' },
      { v: 6, en: 'Ahishar was over the household; and Adoniram the son of Abda was over the men subject to forced labor.', pt: 'Aisar, o mordomo; e Adonirão, filho de Abda, estava sobre a gente de trabalhos forçados.' },
      { v: 7, en: 'Solomon had twelve officers over all Israel, who provided food for the king and his household. Each man had to make provision for a month in the year.', pt: 'Salomão tinha doze intendentes sobre todo o Israel, que proviam de mantimentos ao rei e à sua casa; e cada um tinha que prover mantimentos para um mês no ano.' },
      { v: 8, en: 'These are their names: Ben Hur, in the hill country of Ephraim;', pt: 'São estes os seus nomes: Bene-Hur, na região montanhosa de Efraim.' },
      { v: 9, en: 'Ben Deker, in Makaz, in Shaalbim, Beth Shemesh, and Elon Beth Hanan;', pt: 'Bene-Dequer, em Macaz, Saalabim, Bete-Semes e Elom-Bete-Hanã;' },
      { v: 10, en: 'Ben Hesed, in Arubboth (Socoh and all the land of Hepher belonged to him);', pt: 'Bene-Hesede, em Arubote; também este tinha Socó e toda a terra de Jefer;' },
      { v: 11, en: 'Ben Abinadab, in all the height of Dor (he had Taphath, Solomon’s daughter, as wife);', pt: 'Bene-Abinadabe, em toda a região alta de Dor; tinha este a Tafate, filha de Salomão, por mulher;' },
      { v: 12, en: 'Baana the son of Ahilud, in Taanach and Megiddo, and all Beth Shean which is beside Zarethan, beneath Jezreel, from Beth Shean to Abel Meholah, as far as beyond Jokmeam;', pt: 'Baaná, filho de Ailude, em Taanaque e Megido, e em toda a Bete-Seã, que está junto a Zaretã, abaixo de Jizreel, desde Bete-Seã até Abel-Meolá, para além de Jocmeão;' },
      { v: 13, en: 'Ben Geber, in Ramoth Gilead (the towns of Jair the son of Manasseh, which are in Gilead, belonged to him; and the region of Argob, which is in Bashan, sixty great cities with walls and bronze bars, belonged to him);', pt: 'o filho de Geber, em Ramote-Gileade; tinha este as aldeias de Jair, filho de Manassés, as quais estão em Gileade; também tinha a região de Argobe, o qual está em Basã, sessenta grandes cidades com muros e ferrolhos de bronze:' },
      { v: 14, en: 'Ahinadab the son of Iddo, in Mahanaim;', pt: 'Ainadabe, filho de Ido, em Maanaim;' },
      { v: 15, en: 'Ahimaaz, in Naphtali (he also took Basemath the daughter of Solomon as wife);', pt: 'Aimaaz, em Naftali; também este tomou a Basemate, filha de Salomão, por mulher;' },
      { v: 16, en: 'Baana the son of Hushai, in Asher and Bealoth;', pt: 'Baaná, filho de Hasai, em Aser e em Alote;' },
      { v: 17, en: 'Jehoshaphat the son of Paruah, in Issachar;', pt: 'Jeosafá, filho de Paruá, em Issacar;' },
      { v: 18, en: 'Shimei the son of Ela, in Benjamin;', pt: 'Simei, filho de Elá, em Benjamim;' },
      { v: 19, en: 'Geber the son of Uri, in the land of Gilead, the country of Sihon king of the Amorites and of Og king of Bashan; and he was the only officer who was in the land.', pt: 'Geber, filho de Uri, na terra de Gileade, a terra de Siom, rei dos amorreus, e de Ogue, rei de Basã; havia um só intendente naquela terra.' },
      { v: 20, en: 'Judah and Israel were numerous as the sand which is by the sea in multitude, eating and drinking and making merry.', pt: 'Eram, pois, os de Judá e Israel numerosos, como a areia que está à beira do mar; e, comendo e bebendo, se alegravam.' },
      { v: 21, en: 'Solomon ruled over all the kingdoms from the River to the land of the Philistines, and to the border of Egypt. They brought tribute and served Solomon all the days of his life.', pt: 'E dominava Salomão sobre todos os reinos, desde o rio até a terra dos filisteus e até o termo do Egito; eles pagavam tributo, e serviram a Salomão todos os dias da sua vida.' },
      { v: 22, en: 'Solomon’s provision for one day was thirty cors of fine flour, sixty measures of meal,', pt: 'O provimento diário de Salomão era de trinta coros de flor de farinha, e sessenta coros e farinha;' },
      { v: 23, en: 'ten head of fat cattle, twenty head of cattle out of the pastures, and one hundred sheep, besides deer, and gazelles, and roebucks, and fattened fowl.', pt: 'dez bois cevados, vinte bois de pasto e cem ovelhas, afora os veados, gazelas, cabras montesas e aves cevadas.' },
      { v: 24, en: 'For he had dominion over all on this side the River, from Tiphsah even to Gaza, over all the kings on this side the River: and he had peace on all sides around him.', pt: 'Pois dominava ele sobre toda a região e sobre todos os reis daquém do rio, desde Tifsa até Gaza; e tinha paz por todos os lados em redor.' },
      { v: 25, en: 'Judah and Israel lived safely, every man under his vine and under his fig tree, from Dan even to Beersheba, all the days of Solomon.', pt: 'Judá e Israel habitavam seguros, desde Dã até Berseba, cada um debaixo da sua videira, e debaixo da sua figueira, por todos os dias de Salomão.' },
      { v: 26, en: 'Solomon had forty thousand stalls of horses for his chariots, and twelve thousand horsemen.', pt: 'Salomão tinha também quarenta mil manjedouras para os cavalos dos seus carros, e doze mil cavaleiros.' },
      { v: 27, en: 'Those officers provided food for king Solomon, and for all who came to king Solomon’s table, every man in his month. They let nothing be lacking.', pt: 'Aqueles intendentes, pois, cada um no seu mês, proviam de mantimentos o rei Salomão e todos quantos se chegavam à sua mesa; coisa nenhuma deixavam faltar.' },
      { v: 28, en: 'They also brought Barley and straw for the horses and swift steeds to the place where the officers were, each man according to his duty.', pt: 'Também traziam, cada um segundo seu cargo, a cevada e a palha para os cavalos e os ginetes, para o lugar em que estivessem.' },
      { v: 29, en: 'God gave Solomon abundant wisdom and understanding, and very great understanding, even as the sand that is on the seashore.', pt: 'Ora, Deus deu a Salomão sabedoria, e muitíssimo entendimento, e conhecimentos multiplos, como a areia que está na praia do mar.' },
      { v: 30, en: 'Solomon’s wisdom excelled the wisdom of all the children of the east and all the wisdom of Egypt.', pt: 'A sabedoria de Salomão era maior do que a de todos os do Oriente e do que toda a sabedoria dos egípcios.' },
      { v: 31, en: 'For he was wiser than all men; than Ethan the Ezrahite, Heman, Calcol, and Darda, the sons of Mahol: and his fame was in all the nations all around.', pt: 'Era ele ainda mais sábio do que todos os homens, mais sábio do que Etã, o ezraíta, e do que Hemã, Calcol e Darda, filhos de Maol; e a sua fama correu por todas as nações em redor.' },
      { v: 32, en: 'He spoke three thousand proverbs; and his songs numbered one thousand five.', pt: 'Proferiu ele três mil provérbios, e foram os seus cânticos mil e cinco.' },
      { v: 33, en: 'He spoke of trees, from the cedar that is in Lebanon even to the hyssop that grows out of the wall; he also spoke of animals, of birds, of creeping things, and of fish.', pt: 'Dissertou a respeito das árvores, desde o cedro que está no Líbano até o hissopo que brota da parede; também dissertou sobre os animais, as aves, os répteis e os peixes.' },
      { v: 34, en: 'People of all nations came to hear the wisdom of Solomon, sent by all kings of the earth, who had heard of his wisdom.', pt: 'De todos os povos vinha gente para ouvir a sabedoria de Salomão, e da parte de todos os reis da terra que tinham ouvido da sua sabedoria.' },
    ],
    5: [
      { v: 1, en: 'Hiram king of Tyre sent his servants to Solomon; for he had heard that they had anointed him king in the place of his father, and Hiram had always loved David.', pt: 'Hirão, rei de Tiro, enviou os seus servos a Salomão, quando ouviu que o haviam ungido rei em lugar de seu pai; porquanto Hirão fora sempre muito amigo de Davi.' },
      { v: 2, en: 'Solomon sent to Hiram, saying,', pt: 'Salomão, pois, mandou dizer a Hirão.' },
      { v: 3, en: '“You know that David my father could not build a house for the name of Yahweh his God because of the wars which were around him on every side, until Yahweh put his enemies under the soles of his feet.', pt: 'Bem sabes tu que Davi, meu pai, não pôde edificar uma casa ao nome do Senhor seu Deus, por causa das guerras com que o cercaram, até que o Senhor lhe pôs os inimigos debaixo dos seus pés.' },
      { v: 4, en: 'But now Yahweh my God has given me rest on every side. There is no enemy and no evil occurrence.', pt: 'Agora, porém, o Senhor meu Deus me tem dado descanso de todos os lados: adversário não há, nem calamidade alguma.' },
      { v: 5, en: 'Behold, I intend to build a house for the name of Yahweh my God, as Yahweh spoke to David my father, saying, ‘Your son, whom I will set on your throne in your place shall build the house for my name.’', pt: 'Pretendo, pois, edificar uma casa ao nome do Senhor meu Deus, como falou o senhor a Davi, meu pai, dizendo: Teu filho, que porei em teu lugar no teu trono, ele edificará uma casa ao meu nome.' },
      { v: 6, en: 'Now therefore command that cedar trees be cut for me out of Lebanon. My servants will be with your servants; and I will give you wages for your servants according to all that you say. For you know that there is nobody among us who knows how to cut timber like the Sidonians.”', pt: 'Portanto, dá ordem agora que do Líbano me cortem cedros; os meus servos estarão com os teus servos; eu te pagarei o salário dos teus servos, conforme tudo o que disseres; porque tu sabes que entre nós ninguém há que saiba cortar madeira como os sidônios.' },
      { v: 7, en: 'When Hiram heard the words of Solomon, he rejoiced greatly, and said, “Blessed is Yahweh today, who has given to David a wise son to rule over this great people.”', pt: 'Quando Hirão ouviu as palavras de Salomão, muito se alegrou, e disse: Bendito seja hoje o Senhor, que deu a Davi um filho sábio sobre este tão grande povo.' },
      { v: 8, en: 'Hiram sent to Solomon, saying, “I have heard the message which you have sent to me. I will do all your desire concerning timber of cedar, and concerning cypress timber.', pt: 'E Hirão mandou dizer a Salomão: Ouvi o que me mandaste dizer. Eu farei tudo quanto desejas acerca das madeiras de cedro e de cipreste.' },
      { v: 9, en: 'My servants will bring them down from Lebanon to the sea. I will make them into rafts to go by sea to the place that you specify to me, and will cause them to be broken up there, and you will receive them. You will accomplish my desire, in giving food for my household.”', pt: 'Os meus servos as levarão do Líbano até o mar, e farei conduzi-las em jangadas pelo mar até o lugar que me designares; ali as desamarrarei, e tu as receberás; também farás o meu desejo, dando sustento à minha casa.' },
      { v: 10, en: 'So Hiram gave Solomon cedar timber and cypress timber according to all his desire.', pt: 'Assim dava Hirão a Salomão madeira de cedro e madeira de cipreste, conforme todo o seu desejo.' },
      { v: 11, en: 'Solomon gave Hiram twenty thousand cors of wheat for food to his household, and twenty cors of pure oil. Solomon gave this to Hiram year by year.', pt: 'E Salomão dava a Hirão vinte mil coros de trigo, para sustento da sua casa, e vinte , coros de azeite batido; isso fazia anualmente.' },
      { v: 12, en: 'Yahweh gave Solomon wisdom, as he promised him. There was peace between Hiram and Solomon, and the two of them made a treaty together.', pt: 'Deu, pois, o Senhor a Salomão sabedoria, como lhe tinha prometido. E houve paz entre Hirão e Salomão; e fizeram aliança entre si.' },
      { v: 13, en: 'King Solomon raised a levy out of all Israel; and the levy was thirty thousand men.', pt: 'Também e rei Salomão fez, dentre todo o Israel, uma leva de gente para trabalho forçado; e a leva se compunha de trinta mil homens.' },
      { v: 14, en: 'He sent them to Lebanon, ten thousand a month by courses; for a month they were in Lebanon, and two months at home; and Adoniram was over the men subject to forced labor.', pt: 'E os enviava ao Líbano por turnos, cada mês dez mil; um mês estavam no Líbano, e dois meses cada um em sua casa; e Adonirão estava sobre a leva.' },
      { v: 15, en: 'Solomon had seventy thousand who bore burdens, and eighty thousand who were stone cutters in the mountains;', pt: 'Tinha também Salomão setenta mil que levavam as cargas, e oitenta mil que talhavam pedras nas montanhas,' },
      { v: 16, en: 'besides Solomon’s chief officers who were over the work, three thousand and three hundred, who ruled over the people who labored in the work.', pt: 'afora os mestres de obra que estavam sobre aquele serviço, três mil e trezentes, os quais davam as ordens aos trabalhadores.' },
      { v: 17, en: 'The king commanded, and they cut out large stones, costly stones, to lay the foundation of the house with worked stone.', pt: 'Por ordem do rei eles cortaram grandes pedras, de grande preço, para fundarem a casa em pedras lavradas.' },
      { v: 18, en: 'Solomon’s builders and Hiram’s builders and the Gebalites cut them, and prepared the timber and the stones to build the house.', pt: 'Lavraram-nas, pois, os edificadores de Salomão, e os de Hirão, e os gebalitas, e prepararam as madeiras e as pedras para edificar a casa.' },
    ],
    6: [
      { v: 1, en: 'In the four hundred and eightieth year after the children of Israel had come out of the land of Egypt, in the fourth year of Solomon’s reign over Israel, in the month Ziv, which is the second month, he began to build Yahweh’s house.', pt: 'Sucedeu, pois, que no ano quatrocentos e oitenta depois de saírem os filhos de Israel da terra do Egito, no quarto ano do reinado de Salomão sobre Israel, no mês de zive, que é o segundo mês, começou-se a edificar a casa do Senhor.' },
      { v: 2, en: 'The house which king Solomon built for Yahweh had a length of sixty cubits, and its width twenty, and its height thirty cubits.', pt: 'Ora, a casa que e rei Salomão edificou ao Senhor era de sessenta côvados de comprimento, vinte côvados de largura, e trinta côvados de altura.' },
      { v: 3, en: 'The porch in front of the temple of the house had a length of twenty cubits, which was along the width of the house. Ten cubits was its width in front of the house.', pt: 'E o pórtico diante do templo da casa era de vinte côvados de comprimento, segundo a largura da casa, e de dez côvados de largura.' },
      { v: 4, en: 'He made windows of fixed lattice work for the house.', pt: 'E fez para a casa janelas de gelósias fixas.' },
      { v: 5, en: 'Against the wall of the house, he built floors all around, against the walls of the house all around, both of the temple and of the inner sanctuary; and he made side rooms all around.', pt: 'Edificou andares em torno da casa, contra a parede, tanto do templo como do oráculo, fazendo assim câmaras laterais ao seu redor.' },
      { v: 6, en: 'The lowest floor was five cubits wide, and the middle was six cubits wide, and the third was seven cubits wide; for on the outside he made offsets in the wall of the house all around, that the beams should not be inserted into the walls of the house.', pt: 'A câmara de baixo era de cinco côvados, a do meio de seis côvados, e a terceira de sete côvados de largura. E do lado de fora, ao redor da casa, fez pilastras de reforço, para que as vigas não se apoiassem nas paredes da casa.' },
      { v: 7, en: 'The house, when it was under construction, was built of stone prepared at the quarry; and no hammer or ax or any tool of iron was heard in the house while it was under construction.', pt: 'E edificava-se a casa com pedras lavradas na pedreira; de maneira que nem martelo, nem machado, nem qualquer outro instrumento de ferro se ouviu na casa enquanto estava sendo edificada.' },
      { v: 8, en: 'The door for the middle side rooms was in the right side of the house. They went up by winding stairs into the middle floor, and out of the middle into the third.', pt: 'A porta para as câmaras laterais do meio estava à banda direita da casa; e por escadas espirais subia-se ao andar do meio, e deste ao terceiro.' },
      { v: 9, en: 'So he built the house, and finished it; and he covered the house with beams and planks of cedar.', pt: 'Assim, pois, edificou a casa, e a acabou, cobrindo-a com traves e pranchas de cedro.' },
      { v: 10, en: 'He built the floors all along the house, each five cubits high; and they rested on the house with timber of cedar.', pt: 'Também edificou os andares, contra toda a casa, de cinco côvados de altura, e os ligou à casa com madeira de cedro.' },
      { v: 11, en: 'Yahweh’s word came to Solomon, saying,', pt: 'Então veio a palavra do Senhor a Salomão, dizendo:' },
      { v: 12, en: '“Concerning this house which you are building, if you will walk in my statutes, and execute my ordinances, and keep all my commandments to walk in them; then I will establish my word with you, which I spoke to David your father.', pt: 'Quanto a esta casa que tu estás edificando, se andares nos meus estatutos, e executares os meus preceitos, e guardares todos os meus mandamentos, andando neles, confirmarei para contigo a minha palavra, que falei a Davi, teu pai;' },
      { v: 13, en: 'I will dwell among the children of Israel, and will not forsake my people Israel.”', pt: 'e habitarei no meio dos filhos de Israel, e não desampararei o meu povo de Israel.' },
      { v: 14, en: 'So Solomon built the house, and finished it.', pt: 'Salomão, pois, edificou aquela casa, e a acabou.' },
      { v: 15, en: 'He built the walls of the house within with boards of cedar: from the floor of the house to the walls of the ceiling, he covered them on the inside with wood; and he covered the floor of the house with cypress boards.', pt: 'Também cobriu as paredes da casa por dentro com tábuas de cedro; desde o soalho da casa até e teto, tudo cobriu com madeira por dentro; e cobriu o soalho da casa com tábuas de cipreste.' },
      { v: 16, en: 'He built twenty cubits on the back part of the house with boards of cedar from the floor to the ceiling. He built them for it within, for an inner sanctuary, even for the most holy place.', pt: 'A vinte côvados do fundo da casa fez de tábuas de cedro uma divisão, de altura igual à do teto; e por dentro a preparou para o oráculo, isto é, para a lugar santíssimo.' },
      { v: 17, en: 'In front of the temple sanctuary was forty cubits.', pt: 'E era a casa, isto é, o templo fronteiro ao oráculo, de quarenta côvados de comprido.' },
      { v: 18, en: 'There was cedar on the house within, carved with buds and open flowers. All was cedar. No stone was visible.', pt: 'O cedro da casa por dentro era lavrado de botões e flores abertas; tudo era cedro; pedra nenhuma se via.' },
      { v: 19, en: 'He prepared an inner sanctuary in the middle of the house within, to set the ark of Yahweh’s covenant there.', pt: 'No meio da casa, na parte mais interior, preparou o oráculo, para pôr ali a arca do pacto do Senhor.' },
      { v: 20, en: 'Within the inner sanctuary was twenty cubits in length, and twenty cubits in width, and twenty cubits in its height; and he overlaid it with pure gold; and he covered the altar with cedar.', pt: 'E o oráculo era, por dentro, de vinte côvados de comprimento, vinte de largura e vinte de altura; e o cobriu de ouro puro. Também cobriu de cedro o altar.' },
      { v: 21, en: 'So Solomon overlaid the house within with pure gold. He drew chains of gold across before the inner sanctuary, and he overlaid it with gold.', pt: 'Salomão, pois, cobriu a casa por dentro de ouro puro; e estendeu cadeias de ouro diante do oráculo, que cobriu também de ouro.' },
      { v: 22, en: 'He overlaid the whole house with gold, until all the house was finished. He also overlaid the whole altar that belonged to the inner sanctuary with gold.', pt: 'Assim cobriu inteiramente de ouro a casa toda; também cobriu de ouro todo oe altar doe oráculo.' },
      { v: 23, en: 'In the inner sanctuary he made two cherubim of olive wood, each ten cubits high.', pt: 'No oráculo fez dois querubins de madeira de oliveira, cada um com dez côvados de altura.' },
      { v: 24, en: 'Five cubits was the one wing of the cherub, and five cubits the other wing of the cherub. From the tip of one wing to the tip of the other was ten cubits.', pt: 'Uma asa de um querubim era de cinco côvados, e a outra de cinco côvados; dez côvados havia desde a extremidade de uma das suas asas até a extremidade da outra.' },
      { v: 25, en: 'The other cherub was ten cubits. Both the cherubim were of one measure and one form.', pt: 'Assim era também o outro querubim; ambos os querubins eram da mesma medida e do mesmo talho.' },
      { v: 26, en: 'One cherub was ten cubits high, and so was the other cherub.', pt: 'Um querubim tinha dez côvados de altura, e assim também o outro.' },
      { v: 27, en: 'He set the cherubim within the inner house. The wings of the cherubim were stretched out, so that the wing of the one touched the one wall, and the wing of the other cherub touched the other wall; and their wings touched one another in the middle of the house.', pt: 'E pôs os querubins na parte mais interior da casa. As asas dos querubins se estendiam de maneira que a asa de um tocava numa parede, e a do outro na outra parede, e as suas asas no meio da casa tocavam uma na outra.' },
      { v: 28, en: 'He overlaid the cherubim with gold.', pt: 'Também cobriu de ouro os querubins.' },
      { v: 29, en: 'He carved all the walls of the house around with carved figures of cherubim, palm trees, and open flowers, inside and outside.', pt: 'Quanto a todas as paredes da casa em redor, entalhou-as de querubins, de palmas e de palmas abertas, tanto na parte mais interior como na mais exterior.' },
      { v: 30, en: 'He overlaid the floor of the house with gold, inside and outside.', pt: 'Também cobriu de ouro o soalho da casa, de uma e de outra parte.' },
      { v: 31, en: 'For the entrance of the inner sanctuary, he made doors of olive wood. The lintel and door posts were a fifth part of the wall.', pt: 'E para a entrada do oráculo fez portas de madeira de oliveira; a verga com os umbrais faziam a quinta parte da parede.' },
      { v: 32, en: 'So he made two doors of olive wood; and he carved on them carvings of cherubim, palm trees, and open flowers, and overlaid them with gold. He spread the gold on the cherubim and on the palm trees.', pt: 'Assim fez as duas portas de madeira de oliveira; e entalhou-as de querubins, de palmas e de flores abertas, que cobriu de ouro também estendeu ouro sobre os querubins e sobre as palmas.' },
      { v: 33, en: 'He also did so for the entrance of the temple door posts of olive wood, out of a fourth part of the wall;', pt: 'Assim também fez para a porta do templo umbrais de madeira de oliveira, que constituíam a quarta parte da parede;' },
      { v: 34, en: 'and two doors of cypress wood. The two leaves of the one door were folding, and the two leaves of the other door were folding.', pt: 'E eram as duas partes de madeira de cipreste; e as duas folhas duma porta eram dobradiças, como também as duas folhas da outra porta.' },
      { v: 35, en: 'He carved cherubim, palm trees, and open flowers; and he overlaid them with gold fitted on the engraved work.', pt: 'E as lavrou de querubins, de palmas e de flores abertas; e as cobriu de ouro acomodado ao lavor.' },
      { v: 36, en: 'He built the inner court with three courses of cut stone and a course of cedar beams.', pt: 'Também edificou o átrio interior de três ordens de pedras lavradas e de uma ordem de vigas de cedro.' },
      { v: 37, en: 'The foundation of Yahweh’s house was laid in the fourth year, in the month Ziv.', pt: 'No quarto ano se pôs o fundamento da casa do Senhor, no mês de zive.' },
      { v: 38, en: 'In the eleventh year, in the month Bul, which is the eighth month, the house was finished throughout all its parts, and according to all its specifications. So he spent seven years building it.', pt: 'E no undécimo ano, no mês de bul, que é o oitavo mês, se acabou esta casa com todas as suas dependências, e com tudo o que lhe convinha. Assim levou sete anos para edificá-la.' },
    ],
    7: [
      { v: 1, en: 'Solomon was building his own house thirteen years, and he finished all his house.', pt: 'Salomão edificou também a sua casa, levando treze anos para acabá-la.' },
      { v: 2, en: 'For he built the House of the Forest of Lebanon. Its length was one hundred cubits, its width fifty cubits, and its height thirty cubits, on four rows of cedar pillars, with cedar beams on the pillars.', pt: 'Edificou ainda a casa do bosque de Líbano, de cem côvados de comprimento, cinqüenta de largura e trinta de altura, sobre quatro ordens de colunas de cedros, e vigas de cedro sobre as colunas.' },
      { v: 3, en: 'It was covered with cedar above over the forty-five beams, that were on the pillars, fifteen in a row.', pt: 'E por cima estava coberta de cedro sobre as câmaras, que estavam sobre quarenta e cinco colunas, quinze em cada ordem.' },
      { v: 4, en: 'There were beams in three rows, and window was facing window in three ranks.', pt: 'E havia três ordens de janelas, e uma janela estava defronte da outra janela, em três fileiras.' },
      { v: 5, en: 'All the doors and posts were made square with beams: and window was facing window in three ranks.', pt: 'Todas as portas e esquadrias eram quadradas; e uma janela estava defronte da outra, em três fileiras.' },
      { v: 6, en: 'He made the porch of pillars. Its length was fifty cubits and its width thirty cubits; with a porch before them, and pillars and a threshold before them.', pt: 'Depois fez um pórtico de colunas, de cinqüenta côvados de comprimento e trinta de largura; e defronte dele outro pórtico, com suas respectivas colunas e degraus.' },
      { v: 7, en: 'He made the porch of the throne where he was to judge, even the porch of judgment; and it was covered with cedar from floor to floor.', pt: 'Também fez o pórtico para o trono onde julgava, isto é, o pórtico do juízo, o qual era coberto de cedro desde o soalho até o teto.' },
      { v: 8, en: 'His house where he was to dwell, the other court within the porch, was of the like work. He made also a house for Pharaoh’s daughter (whom Solomon had taken as wife), like this porch.', pt: 'E em sua casa, em que morava, havia outro átrio por dentro do pórtico, de obra semelhante à deste; também para a filha de Faraó, que ele tomara por mulher, fez uma casa semelhante àquele pórtico.' },
      { v: 9, en: 'All these were of costly stones, even of cut stone, according to measure, sawed with saws, inside and outside, even from the foundation to the coping, and so on the outside to the great court.', pt: 'Todas estas casas eram de pedras de grande preço, cortadas sob medida, tendo as suas faces por dentro e por fora serradas à serra; e isto desde o fundamento até as beiras do teto, e por fora até o grande átrio.' },
      { v: 10, en: 'The foundation was of costly stones, even great stones, stones of ten cubits, and stones of eight cubits.', pt: 'Os fundamentos eram de pedras de grande preço, pedras grandes, de dez e de oito côvados,' },
      { v: 11, en: 'Above were costly stones, even cut stone, according to measure, and cedar wood.', pt: 'e por cima delas havia pedras de grande preço, lavradas sob medida, e madeira de cedro.' },
      { v: 12, en: 'The great court around had three courses of cut stone, and a course of cedar beams; like the inner court of Yahweh’s house and the porch of the house.', pt: 'O átrio grande tinha em redor três ordens de pedras lavradas, com uma ordem de vigas de cedro; assim era também o átrio interior da casa do Senhor e o pórtico da casa.' },
      { v: 13, en: 'King Solomon sent and brought Hiram out of Tyre.', pt: 'O rei Salomão mandou trazer de Tiro a Hirão.' },
      { v: 14, en: 'He was the son of a widow of the tribe of Naphtali, and his father was a man of Tyre, a worker in brass; and he was filled with wisdom and understanding and skill, to work all works in brass. He came to king Solomon, and performed all his work.', pt: 'Era ele filho de uma viúva, da tribo de Naftali, e fora seu pai um homem de Tiro, que trabalhava em bronze; ele era cheio de sabedoria, de entendimento e de ciência para fazer toda sorte de obras de bronze. Este veio ter com o rei Salomão, e executou todas as suas obras.' },
      { v: 15, en: 'For he fashioned the two pillars of brass, eighteen cubits high apiece; and a line of twelve cubits encircled either of them.', pt: 'Formou as duas colunas de bronze; a altura de cada coluna era de dezoito côvados; e um fio de doze côvados era a medida da circunferência de cada uma das colunas;' },
      { v: 16, en: 'He made two capitals of molten brass, to set on the tops of the pillars. The height of the one capital was five cubits, and the height of the other capital was five cubits.', pt: 'também fez dois capitéis de bronze fundido para pôr sobre o alto das colunas; de cinco côvados era a altura dum capitel, e de cinco côvados também a altura do outro.' },
      { v: 17, en: 'There were nets of checker work, and wreaths of chain work, for the capitals which were on the top of the pillars; seven for the one capital, and seven for the other capital.', pt: 'Havia redes de malha, e grinaldas entrelaçadas, para os capitéis que estavam sobre o alto das colunas: sete para um capitel e sete para o outro.' },
      { v: 18, en: 'So he made the pillars; and there were two rows around on the one network, to cover the capitals that were on the top of the pillars: and he did so for the other capital.', pt: 'Assim fez as colunas; e havia duas fileiras de romãs em redor sobre uma rede, para cobrir os capitéis que estavam sobre o alto das colunas; assim fez com um e outro capitel.' },
      { v: 19, en: 'The capitals that were on the top of the pillars in the porch were of lily work, four cubits.', pt: 'Os capitéis que estavam sobre o alto das colunas, no pórtico, figuravam lírios, e eram de quatro covados.' },
      { v: 20, en: 'There were capitals above also on the two pillars, close by the belly which was beside the network. There were two hundred pomegranates in rows around the other capital.', pt: 'Os capitéis, pois, sobre as duas colunas estavam também justamente em cima do bojo que estava junto à rede; e havia duzentas romãs, em fileiras em redor, sobre um e outro capitel.' },
      { v: 21, en: 'He set up the pillars at the porch of the temple. He set up the right pillar, and called its name Jachin; and he set up the left pillar, and called its name Boaz.', pt: 'Depois levantou as colunas no pórtico do templo; levantando a coluna direita, pôs-lhe o nome de Jaquim; e levantando a caluna esquerda, pôs-lhe o nome de Boaz.' },
      { v: 22, en: 'On the top of the pillars was lily work: so the work of the pillars was finished.', pt: 'Sobre o alto das colunas estava a obra de lírios. E assim se acabou a obra das colunas.' },
      { v: 23, en: 'He made the molten sea of ten cubits from brim to brim, round in shape. Its height was five cubits; and a line of thirty cubits encircled it.', pt: 'Fez também o mar de fundição; era redondo e media dez côvados duma borda à outra, cinco côvados de altura e trinta de circunferência.' },
      { v: 24, en: 'Under its brim around there were buds which encircled it for ten cubits, encircling the sea. The buds were in two rows, cast when it was cast.', pt: 'Por baixo da sua borda em redor havia betões que o cingiam, dez em cada côvado, cercando aquele mar em redor; duas eram as fileiras destes botões, fundidas juntamente com o mar.' },
      { v: 25, en: 'It stood on twelve oxen, three looking toward the north, and three looking toward the west, and three looking toward the south, and three looking toward the east; and the sea was set on them above, and all their hindquarters were inward.', pt: 'E firmava-se sobre doze bois, três dos quais olhavam para o norte, três para o ocidente, três para o sul e três para o oriente; e o mar descansava sobre eles, e as partes posteriores deles estavam para a banda de dentro.' },
      { v: 26, en: 'It was a hand width thick. Its brim was worked like the brim of a cup, like the flower of a lily. It held two thousand baths.', pt: 'A sua grossura era de três polegadas, e a borda era como a de um copo, como flor de lírio; ele levava dois mil batos.' },
      { v: 27, en: 'He made the ten bases of brass. The length of one base was four cubits, four cubits its width, and three cubits its height.', pt: 'Fez também as dez bases de bronze; cada uma tinha quatro côvados de comprimento, quatro de largura e três de altura.' },
      { v: 28, en: 'The work of the bases was like this: they had panels; and there were panels between the ledges;', pt: 'E a estrutura das bases era esta: tinham elas almofadas, as quais estavam entre as junturas;' },
      { v: 29, en: 'and on the panels that were between the ledges were lions, oxen, and cherubim; and on the ledges there was a pedestal above; and beneath the lions and oxen were wreaths of hanging work.', pt: 'e sobre as almofadas que estavam entre as junturas havia leões, bois, e querubins, bem como os havia sobre as junturas em cima; e debaixo dos leões e dos bois havia grinaldas pendentes.' },
      { v: 30, en: 'Every base had four bronze wheels, and axles of brass; and the four feet of it had supports. The supports were cast beneath the basin, with wreaths at the side of each.', pt: 'Cada base tinha quatro rodas de bronze, e eixos de bronze; e os seus quatro cantos tinham suportes; debaixo da pia estavam estes suportes de fundição, tendo eles grinaldas de cada lado.' },
      { v: 31, en: 'Its mouth within the capital and above was a cubit. Its mouth was round after the work of a pedestal, a cubit and a half; and also on its mouth were engravings, and their panels were square, not round.', pt: 'A sua boca, dentro da coroa, e em cima, era de um côvado; e era redonda segundo a obra dum pedestal, de côvado e meio; e também sobre a sua boca havia entalhes, e as suas almofadas eram quadradas, não redondas.' },
      { v: 32, en: 'The four wheels were underneath the panels; and the axles of the wheels were in the base. The height of a wheel was a cubit and half a cubit.', pt: 'As quatro rodas estavam debaixo das almofadas, e os seus eixos estavam na base; e era a altura de cada roda de côvado e meio.' },
      { v: 33, en: 'The work of the wheels was like the work of a chariot wheel. Their axles, and their rims, and their spokes, and their naves, were all of cast metal.', pt: 'O feitio das rodas era como o de uma roda de carro; seus eixos, suas cambas, seus raios e seus cubos, todos eram fundidos.' },
      { v: 34, en: 'There were four supports at the four corners of each base. Its supports were of the base itself.', pt: 'Havia quatro suportes aos quatro cantos de cada base, os quais faziam parte da própria base.' },
      { v: 35, en: 'In the top of the base there was a round band half a cubit high; and on the top of the base its supports and its panels were of the same.', pt: 'No alto de cada base havia um cinto redondo, de meio côvado de altura; também sobre o topo de cada base havia esteios e almofadas que faziam parte dela.' },
      { v: 36, en: 'On the plates of its supports, and on its panels, he engraved cherubim, lions, and palm trees, each in its space, with wreaths all around.', pt: 'E nas placas dos seus esteios e nas suas almofadas lavrou querubins, leões e palmas, segundo o espaço que havia em cada uma, com grinaldas em redor.' },
      { v: 37, en: 'He made the ten bases in this way: all of them had one casting, one measure, and one form.', pt: 'Deste modo fez as dez bases: todas com a mesma fundição, a mesma medida e o mesmo entalhe.' },
      { v: 38, en: 'He made ten basins of brass. One basin contained forty baths; and every basin was four cubits; and on every one of the ten bases one basin.', pt: 'Também fez dez pias de bronze; em cada uma cabiam quarenta batos, e cada pia era de quatro côvados; e cada uma delas estava sobre uma das dez bases.' },
      { v: 39, en: 'He set the bases, five on the right side of the house, and five on the left side of the house. He set the sea on the right side of the house eastward and toward the south.', pt: 'E pôs cinco bases à direita da casa, e cinco à esquerda; porém o mar pôs ao lado direito da casa para a banda do oriente, na direção do sul.' },
      { v: 40, en: 'Hiram made the basins, the shovels, and the basins. So Hiram finished doing all the work that he worked for king Solomon in Yahweh’s house:', pt: 'Hirão fez também as caldeiras, as pás e as bacias; assim acabou de fazer toda a obra que executou para o rei Salomão, para a casa do Senhor,' },
      { v: 41, en: 'the two pillars; the two bowls of the capitals that were on the top of the pillars; the two networks to cover the two bowls of the capitals that were on the top of the pillars;', pt: 'a saber: as duas colunas, os globos dos capitéis que estavam sobre o alto das colunas, e as duas redes para cobrir os dois globos dos capitéis que estavam sobre o alto das colunas,' },
      { v: 42, en: 'the four hundred pomegranates for the two networks; two rows of pomegranates for each network, to cover the two bowls of the capitals that were on the pillars;', pt: 'e as quatrocentas romãs para as duas redes, a saber, duas carreiras de romãs para cada rede, para cobrirem os dois globos dos capitéis que estavam em cima das colunas;' },
      { v: 43, en: 'the ten bases; the ten basins on the bases;', pt: 'as dez bases, e as dez pias sobre as bases;' },
      { v: 44, en: 'the one sea; the twelve oxen under the sea;', pt: 'o mar, e os doze bois debaixo do mesmo;' },
      { v: 45, en: 'the pots; the shovels; and the basins: even all these vessels, which Hiram made for king Solomon, in Yahweh’s house, were of burnished brass.', pt: 'as caldeiras, as pás e as bacias; todos estes objetos que Hirão fez para o rei Salomão, para a casa do Senhor, eram de bronze polido.' },
      { v: 46, en: 'The king cast them in the plain of the Jordan, in the clay ground between Succoth and Zarethan.', pt: 'O rei os fez fundir na planície do Jordão, num terreno argiloso que havia entre Sucote e Zaretã.' },
      { v: 47, en: 'Solomon left all the vessels unweighed, because there were so many of them. The weight of the brass could not be determined.', pt: 'E Salomão deixou de pesar esses objetos devido ao seu excessivo número; não se averiguou o peso do bronze.' },
      { v: 48, en: 'Solomon made all the vessels that were in Yahweh’s house: the golden altar and the table that the show bread was on, of gold;', pt: 'Também fez Salomão todos os utensílios para a casa do Senhor: o altar de ouro, e a mesa de ouro, sobre a qual estavam os pães da proposição;' },
      { v: 49, en: 'and the lamp stands, five on the right side, and five on the left, before the inner sanctuary, of pure gold; and the flowers, the lamps, and the tongs, of gold;', pt: 'os castiçais, cinco à direita e cinco esquerda, diante do oráculo, de ouro puro; as flores, as lâmpadas e as tenazes, também de ouro;' },
      { v: 50, en: 'the cups, the snuffers, the basins, the spoons, and the fire pans, of pure gold; and the hinges, both for the doors of the inner house, the most holy place, and for the doors of the house, of the temple, of gold.', pt: 'e as taças, as espevitadeiras, as bacias, as colheres e os braseiros, de ouro puro; e os gonzos para as portas da casa interior, para o lugar santíssimo, e os das portas da casa, isto é, do templo, também de ouro.' },
      { v: 51, en: 'Thus all the work that king Solomon did in Yahweh’s house was finished. Solomon brought in the things which David his father had dedicated, the silver, the gold, and the vessels, and put them in the treasuries of Yahweh’s house.', pt: 'Assim se acabou toda a obra que o rei Salomão fez para a casa do Senhor. Então trouxe Salomão as coisas que seu pai Davi tinha consagrado, a saber, a prata, o ouro e os vasos; e os depositou nos tesouros da casa do senhor.' },
    ],
    8: [
      { v: 1, en: 'Then Solomon assembled the elders of Israel, with all the heads of the tribes, the princes of the fathers’ households of the children of Israel, to king Solomon in Jerusalem, to bring up the ark of Yahweh’s covenant out of David’s city, which is Zion.', pt: 'Então congregou Salomão diante de si em Jerusalém os anciãos de Israel, e todos os cabeças das tribos, os chefes das casas paternas, dentre os filhos de Israel, para fazerem subir da cidade de Davi, que é Sião, a arca do pacto do Senhor:' },
      { v: 2, en: 'All the men of Israel assembled themselves to king Solomon at the feast, in the month Ethanim, which is the seventh month.', pt: 'De maneira que todos os homens de Israel se congregaram ao rei Salomão, na ocasião da festa, no mês de etanim, que é o sétimo mes.' },
      { v: 3, en: 'All the elders of Israel came, and the priests picked up the ark.', pt: 'E tendo chegado todos os anciãos de Israel, os sacerdotes alçaram a arca;' },
      { v: 4, en: 'They brought up Yahweh’s ark, the Tent of Meeting, and all the holy vessels that were in the Tent. The priests and the Levites brought these up.', pt: 'e trouxeram para cima a arca do Senhor, e a tenda da revelação, juntamente com todos os utensílios sagrados que havia na tenda; foram os sacerdotes e os levitas que os trouxeram para cima.' },
      { v: 5, en: 'King Solomon and all the congregation of Israel, who were assembled to him, were with him before the ark, sacrificing sheep and cattle, that could not be counted or numbered for multitude.', pt: 'E o rei Salomão, e toda a congregação de Israel, que se ajuntara diante dele, estavam diante da arca, imolando ovelhas e bois, os quais não se podiam contar nem numerar, pela sua multidão.' },
      { v: 6, en: 'The priests brought in the ark of Yahweh’s covenant to its place, into the inner sanctuary of the house, to the most holy place, even under the cherubim’s wings.', pt: 'E os sacerdotes introduziram a arca do pacto do Senhor no seu lugar, no oráculo da casa, no lugar santíssimo, debaixo das asas dos querubins.' },
      { v: 7, en: 'For the cherubim spread their wings out over the place of the ark, and the cherubim covered the ark and its poles above.', pt: 'Pois os querubins estendiam ambas as asas sobre o lugar da arca, e cobriam por cima a arca e os seus varais.' },
      { v: 8, en: 'The poles were so long that the ends of the poles were seen from the holy place before the inner sanctuary; but they were not seen outside. They are there to this day.', pt: 'Os varais sobressaíam tanto que as suas pontas se viam desde o santuário diante do oráculo, porém de fora não se viam; e ali estão até o dia de hoje.' },
      { v: 9, en: 'There was nothing in the ark except the two stone tablets which Moses put there at Horeb, when Yahweh made a covenant with the children of Israel, when they came out of the land of Egypt.', pt: 'Nada havia na arca, senão as duas tábuas de pedra, que Moisés ali pusera, junto a Horebe, quando o Senhor, fez u pacto com os filhos de Israel, ao sairem eles da terra do Egito.' },
      { v: 10, en: 'It came to pass, when the priests had come out of the holy place, that the cloud filled Yahweh’s house,', pt: 'E sucedeu que, saindo os sacerdotes do santuário, uma nuvem encheu a casa do Senhor;' },
      { v: 11, en: 'so that the priests could not stand to minister by reason of the cloud; for Yahweh’s glory filled Yahweh’s house.', pt: 'de modo que os sacerdotes não podiam ter-se em pé para ministrarem, por causa da nuvem; porque a glória do Senhor enchera a casa do Senhor.' },
      { v: 12, en: 'Then Solomon said, “Yahweh has said that he would dwell in the thick darkness.', pt: 'Então falou Salomão: O Senhor disse que habitaria na escuridão.' },
      { v: 13, en: 'I have surely built you a house of habitation, a place for you to dwell in forever.”', pt: 'Certamente te edifiquei uma casa para morada, assento para a tua eterna habitação.' },
      { v: 14, en: 'The king turned his face around, and blessed all the assembly of Israel; and all the assembly of Israel stood.', pt: 'Então o rei virou o rosto, e abençoou toda a congregação de Israel; e toda a congregação ficou em pe.' },
      { v: 15, en: 'He said, “Blessed is Yahweh, the God of Israel, who spoke with his mouth to David your father, and has with his hand fulfilled it, saying,', pt: 'E disse Salomão: Bendito seja e Senhor, Deus de Israel, que falou pela sua boca a Davi, meu pai, e pela sua mão cumpriu a palavra que disse:' },
      { v: 16, en: '‘Since the day that I brought my people Israel out of Egypt, I chose no city out of all the tribes of Israel to build a house, that my name might be there; but I chose David to be over my people Israel.’', pt: 'Desde o dia em que eu tirei do Egito o meu povo Israel, não escolhi cidade alguma de todas as tribos de Israel para se edificar ali uma casa em que estivesse o meu nome; porém escolhi a Davi, para que presidisse sobre o meu povo Israel.' },
      { v: 17, en: '“Now it was in the heart of David my father to build a house for the name of Yahweh, the God of Israel.', pt: 'Ora, Davi, meu pai, propusera em seu coração edificar uma casa ao nome de Senhor, Deus de Israel.' },
      { v: 18, en: 'But Yahweh said to David my father, ‘Whereas it was in your heart to build a house for my name, you did well that it was in your heart.', pt: 'Mas o Senhor disse a Davi, meu pai: Quanto ao teres proposto no teu coração o edificar casa ao meu nome, bem fizeste em o propor no teu coração.' },
      { v: 19, en: 'Nevertheless, you shall not build the house; but your son who shall come out of your body, he shall build the house for my name.’', pt: 'Todavia, tu não edificarás a casa; porém teu filho, que sair de teus lombos, esse edificará a casa ao meu nome.' },
      { v: 20, en: 'Yahweh has established his word that he spoke; for I have risen up in the place of David my father, and I sit on the throne of Israel, as Yahweh promised, and have built the house for the name of Yahweh, the God of Israel.', pt: 'E o Senhor cumpriu a palavra que falou; porque me levantei em lugar de Davi, meu pai, e me assentei no trono de Israel, como falou o Senhor, e edifiquei uma casa, ao nome do Senhor, Deus de Israel.' },
      { v: 21, en: 'There I have set a place for the ark, in which is Yahweh’s covenant, which he made with our fathers, when he brought them out of the land of Egypt.”', pt: 'E ali constituí lugar para a arca em que está o pacto do Senhor, que ele fez com nossos pais quando os tirou da terra de Egito.' },
      { v: 22, en: 'Solomon stood before Yahweh’s altar in the presence of all the assembly of Israel, and spread out his hands toward heaven;', pt: 'Depois Salomão se pôs diante do altar do Senhor, em frente de toda a congregação de Israel e, estendendo as mãos para os céus,' },
      { v: 23, en: 'and he said, “Yahweh, the God of Israel, there is no God like you, in heaven above, or on earth beneath; who keeps covenant and loving kindness with your servants, who walk before you with all their heart;', pt: 'disse: ç Senhor, Deus de Israel, não há Deus como tu, em cima no céu nem em baixo na terra, que guardas o pacto e a benevolência para com os teus servos que andam diante de ti com inteireza de coração;' },
      { v: 24, en: 'who has kept with your servant David my father that which you promised him. Yes, you spoke with your mouth, and have fulfilled it with your hand, as it is today.', pt: 'que cumpriste com teu servo Davi, meu pai, o que lhe prometeste; porque com a tua boca o disseste, e com a tua mão o cumpriste, como neste dia se vê.' },
      { v: 25, en: 'Now therefore, may Yahweh, the God of Israel, keep with your servant David my father that which you have promised him, saying, ‘There shall not fail from you a man in my sight to sit on the throne of Israel, if only your children take heed to their way, to walk before me as you have walked before me.’', pt: 'Agora, pois, ó Senhor, Deus de Israel, faz a teu servo Davi, meu pai, o que lhe prometeste ao dizeres: Não te faltará diante de mim sucessor, que se assente no trono de Israel; contanto que teus filhos guardem o seu caminho, para andarem diante e mim como tu andaste.' },
      { v: 26, en: '“Now therefore, God of Israel, please let your word be verified, which you spoke to your servant David my father.', pt: 'Agora também, ó Deus de Israel, cumpra-se a tua palavra, que disseste a teu servo Davi, meu pai.' },
      { v: 27, en: 'But will God in very deed dwell on the earth? Behold, heaven and the heaven of heavens can’t contain you; how much less this house that I have built!', pt: 'Mas, na verdade, habitaria Deus na terra? Eis que o céu, e até o céu dos céus, não te podem conter; quanto menos esta casa que edifiquei!' },
      { v: 28, en: 'Yet have respect for the prayer of your servant, and for his supplication, Yahweh my God, to listen to the cry and to the prayer which your servant prays before you today;', pt: 'Contudo atende à oração de teu servo, e à sua súplica, ó Senhor meu Deus, para ouvires o clamor e a oração que o teu servo hoje faz diante de ti;' },
      { v: 29, en: 'that your eyes may be open toward this house night and day, even toward the place of which you have said, ‘My name shall be there;’ to listen to the prayer which your servant prays toward this place.', pt: 'para que os teus olhos estejam abertos noite e dia sobre esta casa, sobre este lugar, do qual disseste: O meu nome estará ali; para ouvires a oração que o teu servo fizer, voltado para este lugar.' },
      { v: 30, en: 'Listen to the supplication of your servant, and of your people Israel, when they pray toward this place. Yes, hear in heaven, your dwelling place; and when you hear, forgive.', pt: 'Ouve, pois, a súplica do teu servo, e do teu povo Israel, quando orarem voltados para este lugar. Sim, ouve tu do lugar da tua habitação no céu; ouve, e perdoa.' },
      { v: 31, en: '“If a man sins against his neighbor, and an oath is laid on him to cause him to swear, and he comes and swears before your altar in this house;', pt: 'Se alguém pecar contra o seu próximo e lhe for exigido que jure, e ele vier jurar diante do teu altar nesta casa,' },
      { v: 32, en: 'then hear in heaven, and act, and judge your servants, condemning the wicked, to bring his way on his own head, and justifying the righteous, to give him according to his righteousness.', pt: 'ouve então do céu, age, e julga os teus servos; condena ao culpado, fazendo recair sobre a sua cabeça e seu proceder, e justifica ao reto, retribuindo-lhe segundo a sua retidão.' },
      { v: 33, en: '“When your people Israel are struck down before the enemy, because they have sinned against you; if they turn again to you, and confess your name, and pray and make supplication to you in this house;', pt: 'Quando o teu povo Israel for derrotado diante do inimigo, por ter pecado contra ti; se eles voltarem a ti, e confessarem o teu nome, e orarem e fizerem súplicas a ti nesta casa,' },
      { v: 34, en: 'then hear in heaven, and forgive the sin of your people Israel, and bring them again to the land which you gave to their fathers.', pt: 'ouve então do céu, e perdoa a pecado do teu povo Israel, e torna a levá-lo à terra que deste a seus pais.' },
      { v: 35, en: '“When the sky is shut up, and there is no rain, because they have sinned against you; if they pray toward this place, and confess your name, and turn from their sin, when you afflict them,', pt: 'Quando o céu se fechar e não houver chuva, por terem pecado contra ti, e orarem, voltados para este lugar, e confessarem o teu nome, e se converterem dos seus pecados, quando tu os afligires,' },
      { v: 36, en: 'then hear in heaven, and forgive the sin of your servants, and of your people Israel, when you teach them the good way in which they should walk; and send rain on your land, which you have given to your people for an inheritance.', pt: 'ouve então do céu, e perdoa o pecado dos teus servos e do teu povo Israel, ensinando-lhes o bom caminho em que devem andar; e envia chuva sobre a tua terra que deste ao teu povo em herança.' },
      { v: 37, en: '“If there is famine in the land, if there is pestilence, if there is blight, mildew, locust or caterpillar; if their enemy besieges them in the land of their cities; whatever plague, whatever sickness there is;', pt: 'Se houver na terra fome ou peste, se houver crestamento ou ferrugem, gafanhotos ou lagarta; se o seu inimigo os cercar na terra das suas cidades; seja qual for a praga ou doença que houver;' },
      { v: 38, en: 'whatever prayer and supplication is made by any man, or by all your people Israel, who shall each know the plague of his own heart, and spread out his hands toward this house,', pt: 'toda oração, toda súplica que qualquer homem ou todo o teu povo Israel fizer, conhecendo cada um a chaga do seu coração, e estendendo as suas mãos para esta casa,' },
      { v: 39, en: 'then hear in heaven, your dwelling place, and forgive, and act, and give to every man according to all his ways, whose heart you know (for you, even you only, know the hearts of all the children of men);', pt: 'ouve então do céu, lugar da tua habitação, perdoa, e age, retribuindo a cada um conforme todos os seus caminhos, segundo vires o seu coração (pois tu, só tu conheces o coração de todos os filhos dos homens);' },
      { v: 40, en: 'that they may fear you all the days that they live in the land which you gave to our fathers.', pt: 'para que te temam todos os dias que viverem na terra que deste a nossos pais.' },
      { v: 41, en: '“Moreover concerning the foreigner, who is not of your people Israel, when he comes out of a far country for your name’s sake', pt: 'Também quando o estrangeiro, que não é do teu povo Israel, vier de terras remotas por amor do teu nome' },
      { v: 42, en: '(for they shall hear of your great name, and of your mighty hand, and of your outstretched arm); when he comes and prays toward this house;', pt: '(porque ouvirão do teu grande nome, e da tua forte mão, e do teu braço estendido), quando vier orar voltado para esta casa,' },
      { v: 43, en: 'hear in heaven, your dwelling place, and do according to all that the foreigner calls to you for; that all the peoples of the earth may know your name, to fear you, as do your people Israel, and that they may know that this house which I have built is called by your name.', pt: 'ouve do céu, lugar da tua habitação, e faze conforme tudo o que o estrangeiro a ti clamar, a fim de que todos os povos da terra conheçam o teu nome, e te temam como o teu povo Israel, e saibam que pelo teu nome é chamada esta casa que edifiquei.' },
      { v: 44, en: '“If your people go out to battle against their enemy, by whatever way you shall send them, and they pray to Yahweh toward the city which you have chosen, and toward the house which I have built for your name;', pt: 'Quando o teu povo sair à guerra contra os seus inimigos, seja qual for o caminho por que os enviares, e orarem ao Senhor, voltados para a cidade que escolheste, e para a casa que edifiquei ao teu nome,' },
      { v: 45, en: 'then hear in heaven their prayer and their supplication, and maintain their cause.', pt: 'ouve então do céu a sua oração e a sua súplica, e defende a sua causa.' },
      { v: 46, en: 'If they sin against you (for there is no man who doesn’t sin), and you are angry with them, and deliver them to the enemy, so that they carry them away captive to the land of the enemy, far off or near;', pt: 'Quando pecarem contra ti (pois não há homem que não peque), e tu te indignares contra eles, e os entregares ao inimigo, de modo que os levem em cativeiro para a terra inimiga, longínqua ou próxima;' },
      { v: 47, en: 'yet if they repent in the land where they are carried captive, and turn again, and make supplication to you in the land of those who carried them captive, saying, ‘We have sinned, and have done perversely; we have dealt wickedly;’', pt: 'se na terra aonde forem levados em cativeiro caírem em si, e se converterem, e na terra do seu cativeiro te suplicarem, dizendo: Pecamos e procedemos perversamente, cometemos iniqüidade;' },
      { v: 48, en: 'if they return to you with all their heart and with all their soul in the land of their enemies, who carried them captive, and pray to you toward their land, which you gave to their fathers, the city which you have chosen, and the house which I have built for your name;', pt: 'se voltarem a ti de todo o seu coração e de toda a sua alma, na terra de seus inimigos que os tenham levado em cativeiro, e orarem a ti, voltados para a sua terra, que deste a seus pais, para a cidade que escolheste, e para a casa que edifiquei ao teu nome,' },
      { v: 49, en: 'then hear their prayer and their supplication in heaven, your dwelling place, and maintain their cause;', pt: 'ouve então do céu, lugar da tua habitação, a sua oração e a sua súplica, e defende a sua causa;' },
      { v: 50, en: 'and forgive your people who have sinned against you, and all their transgressions in which they have transgressed against you; and give them compassion before those who carried them captive, that they may have compassion on them', pt: 'perdoa ao teu povo que houver pecado contra ti, perdoa todas as transgressões que houverem cometido contra ti, e dá-lhes alcançar misericórdia da parte dos que os levarem cativos, para que se compadeçam deles;' },
      { v: 51, en: '(for they are your people, and your inheritance, which you brought out of Egypt, from the middle of the iron furnace);', pt: 'porque são o teu povo e a tua herança, que tiraste da terra do Egito, do meio da fornalha de ferro.' },
      { v: 52, en: 'that your eyes may be open to the supplication of your servant, and to the supplication of your people Israel, to listen to them whenever they cry to you.', pt: 'Estejam abertos os teus olhos à súplica do teu servo e à súplica do teu povo Israel, a fim de os ouvires sempre que clamarem a ti.' },
      { v: 53, en: 'For you separated them from among all the peoples of the earth, to be your inheritance, as you spoke by Moses your servant, when you brought our fathers out of Egypt, Lord Yahweh.”', pt: 'Pois tu, ó Senhor Jeová, os separaste dentre todos os povos da terra, para serem a tua herança como falaste por intermédio de Moisés, teu servo, quando tiraste do Egito nossos pais.' },
      { v: 54, en: 'It was so, that when Solomon had finished praying all this prayer and supplication to Yahweh, he arose from before Yahweh’s altar, from kneeling on his knees with his hands spread out toward heaven.', pt: 'Sucedeu pois que, acabando Salomão de fazer ao Senhor esta oração e esta súplica, estando de joelhos e com as mãos estendidas para o céu, se levantou de diante do altar do Senhor,' },
      { v: 55, en: 'He stood, and blessed all the assembly of Israel with a loud voice, saying,', pt: 'pôs-se em pé, e abençoou em alta voz a toda a congregação de Israel, dizendo:' },
      { v: 56, en: '“Blessed be Yahweh, who has given rest to his people Israel, according to all that he promised. There has not failed one word of all his good promise, which he promised by Moses his servant.', pt: 'Bendito seja o Senhor, que deu repouso ao seu povo Israel, segundo tudo o que disse; não falhou nem sequer uma de todas as boas palavras que falou por intermédio de Moisés, seu servo.' },
      { v: 57, en: 'May Yahweh our God be with us, as he was with our fathers. Let him not leave us or forsake us;', pt: 'O Senhor nosso Deus seja conosco, como foi com nossos pais; não nos deixe, nem nos abandone;' },
      { v: 58, en: 'that he may incline our hearts to him, to walk in all his ways, and to keep his commandments, and his statutes, and his ordinances, which he commanded our fathers.', pt: 'mas incline a si os nossos corações, a fim de andarmos em todos os seus caminhos, e guardarmos os seus mandamentos, e os seus estatutos, e os seus preceitos, que ordenou a nossos pais.' },
      { v: 59, en: 'Let these my words, with which I have made supplication before Yahweh, be near to Yahweh our God day and night, that he may maintain the cause of his servant, and the cause of his people Israel, as every day requires;', pt: 'E que estas minhas palavras, com que supliquei perante o Senhor, estejam perto, diante do Senhor nosso Deus, de dia e de noite, para que defenda ele a causa do seu servo e a causa do seu povo Israel, como cada dia o exigir,' },
      { v: 60, en: 'that all the peoples of the earth may know that Yahweh himself is God. There is no one else.', pt: 'para que todos os povos da terra, saibam que o Senhor é Deus, e que não há outro.' },
      { v: 61, en: '“Let your heart therefore be perfect with Yahweh our God, to walk in his statutes, and to keep his commandments, as it is today.”', pt: 'E seja o vosso coração perfeito para com o Senhor nosso Deus, para andardes nos seus estatutos, e guardardes os seus mandamentos, como hoje o fazeis.' },
      { v: 62, en: 'The king, and all Israel with him, offered sacrifice before Yahweh.', pt: 'Então o rei e todo o Israel com ele ofereceram sacrifícios perante o Senhor.' },
      { v: 63, en: 'Solomon offered for the sacrifice of peace offerings, which he offered to Yahweh, twenty two thousand head of cattle, and one hundred twenty thousand sheep. So the king and all the children of Israel dedicated Yahweh’s house.', pt: 'Ora, Salomão deu, para o sacrifício pacífico que ofereceu ao Senhor, vinte e dois mil bois e cento e vinte mil ovelhas. Assim o rei e todos os filhos de Israel consagraram a casa do Senhor.' },
      { v: 64, en: 'The same day the king made the middle of the court holy that was before Yahweh’s house; for there he offered the burnt offering, and the meal offering, and the fat of the peace offerings, because the bronze altar that was before Yahweh was too little to receive the burnt offering, the meal offering, and the fat of the peace offerings.', pt: 'No mesmo dia o rei santificou o meio do átrio que estava diante da casa do Senhor; porquanto ali ofereceu o holocausto, a oferta de cereais e a gordura das ofertas pacíficas, porque o altar de bronze que está diante do Senhor era muito pequeno para nele caberem o holocausto, a oferta de cereais, e a gordura das ofertas pacíficas.' },
      { v: 65, en: 'So Solomon held the feast at that time, and all Israel with him, a great assembly, from the entrance of Hamath to the brook of Egypt, before Yahweh our God, seven days and seven more days, even fourteen days.', pt: 'No mesmo tempo celebrou Salomão a festa, e todo o Israel com ele, uma grande congregação, vinda desde a entrada de Hamate e desde o rio do Egito, perante a face do Senhor nosso Deus, por sete dias, e mais sete dias (catorze dias ao todo).' },
      { v: 66, en: 'On the eighth day he sent the people away; and they blessed the king, and went to their tents joyful and glad in their hearts for all the goodness that Yahweh had shown to David his servant, and to Israel his people.', pt: 'E no oitavo dia despediu o povo, e todos bendisseram ao rei; então se foram às suas tendas, alegres e de coração contente, por causa de todo o bem que o Senhor fizera a Davi seu servo, e a Israel seu povo.' },
    ],
    9: [
      { v: 1, en: 'When Solomon had finished the building of Yahweh’s house, the king’s house, and all Solomon’s desire which he was pleased to do,', pt: 'Sucedera pois que, tendo Salomão acabado de edificar a casa do Senhor, e a casa do rei, e tudo quanto lhe aprouve fazer,' },
      { v: 2, en: 'Yahweh appeared to Solomon the second time, as he had appeared to him at Gibeon.', pt: 'apareceu-lhe o Senhor segunda vez, como lhe tinha aparecido em Gibeão.' },
      { v: 3, en: 'Yahweh said to him, “I have heard your prayer and your supplication, that you have made before me. I have made this house holy, which you have built, to put my name there forever; and my eyes and my heart shall be there perpetually.', pt: 'E o Senhor lhe disse: Ouvi a tua oração e a tua súplica, que fizeste perante mim; santifiquei esta casa que edificaste, a fim de pôr ali o meu nome para sempre; e os meus olhos e o meu coração estarão ali todos os dias.' },
      { v: 4, en: 'As for you, if you will walk before me, as David your father walked, in integrity of heart, and in uprightness, to do according to all that I have commanded you, and will keep my statutes and my ordinances;', pt: 'Ora, se tu andares perante mim como andou Davi, teu pai, com inteireza de coração e com eqüidade, fazendo conforme tudo o que te ordenei, e guardando os meus estatutos e as minhas ordenanças,' },
      { v: 5, en: 'then I will establish the throne of your kingdom over Israel forever, as I promised to David your father, saying, ‘There shall not fail from you a man on the throne of Israel.’', pt: 'então confirmarei o trono de teu reino sobre Israel para sempre, como prometi a teu pai Davi, dizendo: Não te faltará varão sobre o trono de Israel.' },
      { v: 6, en: 'But if you turn away from following me, you or your children, and not keep my commandments and my statutes which I have set before you, but go and serve other gods, and worship them;', pt: 'Se, porém, vós e vossos filhos de qualquer maneira vos desviardes e nao me seguirdes, nem guadardardes os meus mandamentos e os meus estatutos, que vos tenho proposto, mas fordes, e servirdes a outros deuses, curvando-vos perante eles,' },
      { v: 7, en: 'then I will cut off Israel out of the land which I have given them; and I will cast this house, which I have made holy for my name, out of my sight; and Israel will be a proverb and a byword among all peoples.', pt: 'então exterminarei a Israel da terra que lhe dei; e a esta casa, que santifiquei a meu nome, lançarei longe da minha presença, e Israel será por provérbio e motejo entre todos os povos.' },
      { v: 8, en: 'Though this house is so high, yet everyone who passes by it will be astonished and hiss; and they will say, ‘Why has Yahweh done this to this land, and to this house?’', pt: 'E desta casa, que é tão exaltada, todo aquele que por ela passar pasmará e assobiará, e dirá: Por que fez o Senhor assim a esta terra e a esta casa?' },
      { v: 9, en: 'and they will answer, ‘Because they abandoned Yahweh their God, who brought their fathers out of the land of Egypt, and laid hold of other gods, and worshiped them, and served them. Therefore Yahweh has brought all this evil on them.’”', pt: 'E lhe responderão: E porque deixaram ao Senhor seu Deus, que tirou da terra do Egito a seus pais, e se apegaram a deuses alheios, e perante eles se encurvaram, e os serviram; por isso o Senhor trouxe sobre eles todo este mal.' },
      { v: 10, en: 'At the end of twenty years, in which Solomon had built the two houses, Yahweh’s house and the king’s house', pt: 'Ao fim dos vinte anos em que Salomão edificara as duas casas, a casa do Senhor e a casa do rei,' },
      { v: 11, en: '(now Hiram the king of Tyre had furnished Solomon with cedar trees and cypress trees, and with gold, according to all his desire), King Solomon gave Hiram twenty cities in the land of Galilee.', pt: 'como Hirão, rei de Tiro, trouxera a Salomão madeira de cedro e de cipreste, e ouro segundo todo o seu desejo, deu o rei Salomão a Hirão vinte cidades na terra da Galiléia.' },
      { v: 12, en: 'Hiram came out of Tyre to see the cities which Solomon had given him; and they didn’t please him.', pt: 'Hirão, pois, saiu de Tiro para ver as cidades que Salomão lhe dera; porém não lhe agradaram.' },
      { v: 13, en: 'He said, “What cities are these which you have given me, my brother?” He called them the land of Cabul to this day.', pt: 'Pelo que disse: Que cidades são estas que me deste, irmão meu? De sorte que são chamadas até hoje terra de Cabul.' },
      { v: 14, en: 'Hiram sent to the king one hundred twenty talents of gold.', pt: 'Hirão enviara ao rei cento e vinte talentos de ouro.' },
      { v: 15, en: 'This is the reason of the levy which king Solomon raised, to build Yahweh’s house, his own house, Millo, Jerusalem’s wall, Hazor, Megiddo, and Gezer.', pt: 'A razão da leva de gente para trabalho forçado que o rei Salomão fez é esta: edificar a casa do Senhor e a sua própria casa, e Milo, e o muro de Jerusalém, como também Hazor, e Megido, e Gezer.' },
      { v: 16, en: 'Pharaoh king of Egypt had gone up, taken Gezer, burned it with fire, killed the Canaanites who lived in the city, and given it for a wedding gift to his daughter, Solomon’s wife.', pt: 'Pois Faraó, rei do Egito, tendo subido, tomara a Gezer e a queimara a fogo, e matando os cananeus que moravam na cidade, dera-a em dote a sua filha, mulher de Salomão.' },
      { v: 17, en: 'Solomon built in the land Gezer, Beth Horon the lower,', pt: 'Salomão edificou Gezer, Bete-Horom a baixa,' },
      { v: 18, en: 'Baalath, Tamar in the wilderness,', pt: 'Baalate, Tamar no deserto daquela terra,' },
      { v: 19, en: 'all the storage cities that Solomon had, the cities for his chariots, the cities for his horsemen, and that which Solomon desired to build for his pleasure in Jerusalem, and in Lebanon, and in all the land of his dominion.', pt: 'como também todas as cidades-armazéns que Salomão tinha, as cidades dos carros as cidades dos cavaleiros, e tudo o que Salomão quis edificar em Jerusalém, no Líbano, e em toda a terra de seu domínio.' },
      { v: 20, en: 'As for all the people who were left of the Amorites, the Hittites, the Perizzites, the Hivites, and the Jebusites, who were not of the children of Israel;', pt: 'Quanto a todo o povo que restou dos amorreus, dos heteus, dos perizeus, dos heveus e dos jebuseus, que não eram dos filhos de Israel,' },
      { v: 21, en: 'their children who were left after them in the land, whom the children of Israel were not able utterly to destroy, of them Solomon raised a levy of bondservants to this day.', pt: 'a seus filhos, que restaram depois deles na terra, os quais os filhos de Israel não puderam destruir totalmente, Salomão lhes impôs tributo de trabalho forçado, até hoje.' },
      { v: 22, en: 'But of the children of Israel Solomon made no bondservants; but they were the men of war, his servants, his princes, his captains, and rulers of his chariots and of his horsemen.', pt: 'Mas dos filhos de Israel não fez Salomão escravo algum; porém eram homens de guerra, e seus servos, e seus príncipes, e seus capitães, e chefes dos seus carros e dos seus cavaleiros.' },
      { v: 23, en: 'These were the five hundred fifty chief officers who were over Solomon’s work, who ruled over the people who labored in the work.', pt: 'Estes eram os chefes dos oficiais que estavam sobre a obra de Salomão, quinhentos e cinqüenta, que davam ordens ao povo que trabalhava na obra.' },
      { v: 24, en: 'But Pharaoh’s daughter came up out of David’s city to her house which Solomon had built for her. Then he built Millo.', pt: 'Subiu, porém, a filha de Faraó da cidade de Davi à sua casa, que Salomão lhe edificara; então ele edificou Milo.' },
      { v: 25, en: 'Solomon offered burnt offerings and peace offerings on the altar which he built to Yahweh three times per year, burning incense with them, on the altar that was before Yahweh. So he finished the house.', pt: 'E Salomão oferecia três vezes por ano holocaustos e ofertas pacíficas sobre a altar que edificara ao Senhor, queimando com eles incenso sobre o altar que estava perante o Senhor, depois que acabou de edificar a casa.' },
      { v: 26, en: 'King Solomon made a fleet of ships in Ezion Geber, which is beside Eloth, on the shore of the Red Sea, in the land of Edom.', pt: 'Também o rei Salomão fez uma frota em Eziom-Geber, que está junto a Elote, na praia do Mar Vermelho, na terra de Edom.' },
      { v: 27, en: 'Hiram sent in the fleet his servants, sailors who had knowledge of the sea, with the servants of Solomon.', pt: 'Hirão mandou com aquela frota, em companhia dos servos de Salomão, os seus próprios servos, marinheiros que conheciam o mar;' },
      { v: 28, en: 'They came to Ophir, and fetched from there gold, four hundred and twenty talents, and brought it to king Solomon.', pt: 'os quais foram a Ofir, e tomaram de lá quatrocentos e vinte talentos de ouro, que trouxeram ao rei Salomão.' },
    ],
    10: [
      { v: 1, en: 'When the queen of Sheba heard of the fame of Solomon concerning Yahweh’s name, she came to test him with hard questions.', pt: 'Tendo a rainha de Sabá ouvido da fama de Salomão, no que concerne ao nome do Senhor, veio prová-lo por enigmas.' },
      { v: 2, en: 'She came to Jerusalem with a very great caravan, with camels that bore spices, very much gold, and precious stones; and when she had come to Solomon, she talked with him about all that was in her heart.', pt: 'E chegou a Jerusalém com uma grande comitiva, com camelos carregados de especiarias, e muitíssimo ouro, e pedras preciosas; e, tendo-se apresentado a Salomão, conversou com ele acerca de tudo o que tinha ne coração.' },
      { v: 3, en: 'Solomon answered all her questions. There was not anything hidden from the king which he didn’t tell her.', pt: 'E Salomão lhe deu resposta a todas as suas perguntas; não houve nada que o rei não lhe soubesse explicar.' },
      { v: 4, en: 'When the queen of Sheba had seen all the wisdom of Solomon, the house that he had built,', pt: 'Vendo, pois, a rainha de Sabá toda a sabedoria de Salomão, a casa que edificara,' },
      { v: 5, en: 'the food of his table, the sitting of his servants, the attendance of his officials, their clothing, his cup bearers, and his ascent by which he went up to Yahweh’s house; there was no more spirit in her.', pt: 'as iguarias da sua mesa, o assentar dos seus oficiais, as funções e os trajes dos seus servos, e os seus copeiros, e os holocaustos que ele oferecia na casa do Senhor, ficou estupefata,' },
      { v: 6, en: 'She said to the king, “It was a true report that I heard in my own land of your acts, and of your wisdom.', pt: 'e disse ao rei: Era verdade o que ouvi na minha terra, acerca des teus feitos e da tua sabedoria.' },
      { v: 7, en: 'However I didn’t believe the words until I came and my eyes had seen it. Behold, not even half was told me! Your wisdom and prosperity exceed the fame which I heard.', pt: 'Contudo eu não o acreditava, até que vim e os meus olhos o viram. Eis que não me disseram metade; sobrepujaste em sabedoria e bens a fama que ouvi.' },
      { v: 8, en: 'Happy are your men, happy are these your servants, who stand continually before you, who hear your wisdom.', pt: 'Bem-aventurados os teus homens! Bem-aventuradas estes teus servos, que estão sempre diante de ti, que ouvem a tua sabedoria!' },
      { v: 9, en: 'Blessed is Yahweh your God, who delighted in you, to set you on the throne of Israel. Because Yahweh loved Israel forever, therefore he made you king, to do justice and righteousness.”', pt: 'Bendito seja o Senhor teu Deus, que se agradou de ti e te colocou no trono de Israel! Porquanto o Senhor amou Israel para sempre, por isso te estabeleceu rei, para executares juízo e justiça.' },
      { v: 10, en: 'She gave the king one hundred twenty talents of gold, and a very great quantity of spices, and precious stones. Never again was there such an abundance of spices as these which the queen of Sheba gave to king Solomon.', pt: 'E deu ela ao rei cento e vinte talentos de ouro, especiarias em grande quantidade e pedras preciosas; nunca mais apareceu tamanha abundância de especiarias como a que a rainha de Sabá deu ao rei Salomão.' },
      { v: 11, en: 'The fleet of Hiram that brought gold from Ophir, also brought in from Ophir great quantities of almug trees and precious stones.', pt: 'Também a frota de Hirão, que de Ofir trazia ouro, trouxe dali madeira de almugue em quantidade, e pedras preciosas.' },
      { v: 12, en: 'The king made of the almug trees pillars for Yahweh’s house, and for the king’s house, harps also and stringed instruments for the singers; no such almug trees came or were seen, to this day.', pt: 'Desta madeira de almugue fez e rei balaústres para a casa do Senhor, e para a casa de rei, como também harpas e alaúdes para os cantores; não se trouxe nem se viu mais tal madeira de almugue, até o dia de hoje.' },
      { v: 13, en: 'King Solomon gave to the queen of Sheba all her desire, whatever she asked, besides that which Solomon gave her of his royal bounty. So she turned and went to her own land, she and her servants.', pt: 'E o rei salomão deu à rainha de Sabà tudo o que ela desejou, tudo quanto pediu, além de que lhe dera espontaneamente, da sua munificência real. Então voltou e foi para a sua terra, ela e os seus servos.' },
      { v: 14, en: 'Now the weight of gold that came to Solomon in one year was six hundred sixty-six talents of gold,', pt: 'Ora, o peso do ouro que se trazia a Salomão cada ano era de seiscentos e sessenta e seis talentos de ouro,' },
      { v: 15, en: 'besides that which the traders brought, and the traffic of the merchants, and of all the kings of the mixed people, and of the governors of the country.', pt: 'além do que vinha dos vendedores ambulantes, e do tráfico dos negociantes, e de todos as reis da Arábia, e dos governadores do país.' },
      { v: 16, en: 'King Solomon made two hundred bucklers of beaten gold; six hundred shekels of gold went to one buckler.', pt: 'Também o rei Salomão fez duzentos paveses de ouro batido; de seiscentos siclos de ouro mandou fazer cada pavês;' },
      { v: 17, en: 'he made three hundred shields of beaten gold; three minas of gold went to one shield; and the king put them in the House of the Forest of Lebanon.', pt: 'do mesmo modo fez também trezentos escudos de ouro batido; de três minas de auro mandou fazer cada escudo. Então e rei os pôs na casa do bosque de Líbano.' },
      { v: 18, en: 'Moreover the king made a great throne of ivory, and overlaid it with the finest gold.', pt: 'Fez mais o rei um grande trono de marfim, e o revestiu de ouro puríssimo.' },
      { v: 19, en: 'There were six steps to the throne, and the top of the throne was round behind; and there were armrests on either side by the place of the seat, and two lions standing beside the armrests.', pt: 'Tinha o trono seis degraus, e o alto do trono era redondo pelo espaldar; de ambos os lados tinha braços junto ao assento, e dois leões em pé junto aos braços.' },
      { v: 20, en: 'Twelve lions stood there on the one side and on the other on the six steps. Nothing like it was made in any kingdom.', pt: 'E sobre os seis degraus havia doze leões de ambos os lados; outro tal não se fizera em reino algum.' },
      { v: 21, en: 'All king Solomon’s drinking vessels were of gold, and all the vessels of the House of the Forest of Lebanon were of pure gold. None were of silver, because it was considered of little value in the days of Solomon.', pt: 'Também todos os vasos de beber de rei Salomão eram de ouro, e todos os vasos da casa do bosque do Líbano eram de ouro puro; não havia nenhum de prata, porque nos dias de Salomão a prata não tinha estimação alguma.' },
      { v: 22, en: 'For the king had a fleet of Tarshish at sea with Hiram’s fleet. Once every three years the fleet of Tarshish came, bringing gold, silver, ivory, apes, and peacocks.', pt: 'Porque o rei tinha no mar uma frota de Társis, com a de Hirão; de três em três anos a frota de Társis voltava, trazendo ouro e prata, marfim, bugios e pavões.' },
      { v: 23, en: 'So king Solomon exceeded all the kings of the earth in riches and in wisdom.', pt: 'Assim o rei Salomão excedeu a todos os reis da terra, tanto em riquezas como em sabedoria.' },
      { v: 24, en: 'All the earth sought the presence of Solomon, to hear his wisdom, which God had put in his heart.', pt: 'E toda a terra buscava a presença de Salomão para ouvir a sabedoria que Deus lhe tinha posto no coração.' },
      { v: 25, en: 'Year after year, every man brought his tribute, vessels of silver, vessels of gold, clothing, armor, spices, horses, and mules.', pt: 'Cada um trazia seu presente, vasos de prata, vasos de ouro, vestidos, armaduras, especiarias, cavalos e mulas; isso faziam cada ano.' },
      { v: 26, en: 'Solomon gathered together chariots and horsemen. He had one thousand four hundred chariots, and twelve thousand horsemen, that he kept in the chariot cities and with the king at Jerusalem.', pt: 'Também ajuntou Salomão carros e cavaleiros, de sorte que tinha mil e quatrocentos carros e doze mil cavaleiros, e os distribuiu pelas cidades dos carros, e junto ao rei em Jerusalém.' },
      { v: 27, en: 'The king made silver as common as stones in Jerusalem, and cedars as common as the sycamore trees that are in the lowland.', pt: 'E o rei tornou a prata tão comum em Jerusalém como as pedras, e os cedros tantos em abundância como os sicômoros que há pelas campinas.' },
      { v: 28, en: 'The horses which Solomon had were brought out of Egypt. The king’s merchants received them in droves, each drove at a price.', pt: 'Os cavalos que Salomão tinha eram trazidos do Egito e de Coa; os mercadores do rei os recebiam de Coa por preço determinado.' },
      { v: 29, en: 'A chariot came up and went out of Egypt for six hundred shekels of silver, and a horse for one hundred fifty shekels; and so they exported them to all the kings of the Hittites, and to the kings of Syria.', pt: 'E subia e saía um carro do Egito por seiscentos siclos de prata, e um cavalo por cento e cinqüenta; e assim, por intermédio desses mercadores, eram exportados para todos os reis dos heteus e para os reis da Síria.' },
    ],
    11: [
      { v: 1, en: 'Now king Solomon loved many foreign women, together with the daughter of Pharaoh, women of the Moabites, Ammonites, Edomites, Sidonians, and Hittites;', pt: 'Ora, o rei Salomão amou muitas mulheres estrangeiras, além da filha de Faraó: moabitas, amonitas, edomitas, sidônias e heteias,' },
      { v: 2, en: 'of the nations concerning which Yahweh said to the children of Israel, “You shall not go among them, neither shall they come among you; for surely they will turn away your heart after their gods.” Solomon joined to these in love.', pt: 'das nações de que o Senhor dissera aos filhos de Israel: Não ireis para elas, nem elas virão para vós; doutra maneira perverterão o vosso coração para seguirdes os seus deuses. A estas se apegou Salomão, levado pelo amor.' },
      { v: 3, en: 'He had seven hundred wives, princesses, and three hundred concubines; and his wives turned away his heart.', pt: 'Tinha ele setecentas mulheres, princesas, e trezentas concubinas; e suas mulheres lhe perverteram o coração.' },
      { v: 4, en: 'When Solomon was old, his wives turned away his heart after other gods; and his heart was not perfect with Yahweh his God, as the heart of David his father was.', pt: 'Pois sucedeu que, no tempo da velhice de Salomão, suas mulheres lhe perverteram o coração para seguir outros deuses; e e seu coração já não era perfeito para com o Senhor seu Deus, como fora o de Davi, seu pai;' },
      { v: 5, en: 'For Solomon went after Ashtoreth the goddess of the Sidonians, and after Milcom the abomination of the Ammonites.', pt: 'Salomão seguiu a Astarete, deusa dos sidônios, e a Milcom, abominação dos amonitas.' },
      { v: 6, en: 'Solomon did that which was evil in Yahweh’s sight, and didn’t go fully after Yahweh, as David his father did.', pt: 'Assim fez Salomão o que era mau aos olhos do Senhor, e não perseverou em seguir, como fizera Davi, seu pai.' },
      { v: 7, en: 'Then Solomon built a high place for Chemosh the abomination of Moab, on the mountain that is before Jerusalem, and for Molech the abomination of the children of Ammon.', pt: 'Nesse tempo edificou Salomão um alto a Quemós, abominação dos moabitas, sobre e monte que está diante de Jerusalém, e a Moleque, abominação dos amonitas.' },
      { v: 8, en: 'So he did for all his foreign wives, who burned incense and sacrificed to their gods.', pt: 'E assim fez para todas as suas mulheres estrangeiras, as quais queimavam incenso e ofereciam sacrifícios a seus deuses.' },
      { v: 9, en: 'Yahweh was angry with Solomon, because his heart was turned away from Yahweh, the God of Israel, who had appeared to him twice,', pt: 'Pelo que o Senhor se indignou contra Salomão, porquanto e seu coração se desviara do Senhor Deus de Israel, o qual duas vezes lhe aparecera,' },
      { v: 10, en: 'and had commanded him concerning this thing, that he should not go after other gods; but he didn’t keep that which Yahweh commanded.', pt: 'e lhe ordenara expressamente que não seguisse a outros deuses. Ele, porém, não guardou o que o Senhor lhe ordenara.' },
      { v: 11, en: 'Therefore Yahweh said to Solomon, “Because this is done by you, and you have not kept my covenant and my statutes, which I have commanded you, I will surely tear the kingdom from you, and will give it to your servant.', pt: 'Disse, pois, o Senhor a Salomão: Porquanto houve isto em ti, que não guardaste a meu pacto e os meus estatutos que te ordenei, certamente rasgarei de ti este reino, e o darei a teu servo.' },
      { v: 12, en: 'Nevertheless, I will not do it in your days, for David your father’s sake; but I will tear it out of your son’s hand.', pt: 'Contudo não o farei nos teus dias, por amor de Davi, teu pai; da mão de teu filho o rasgarei.' },
      { v: 13, en: 'However I will not tear away all the kingdom; but I will give one tribe to your son, for David my servant’s sake, and for Jerusalem’s sake which I have chosen.”', pt: 'Todavia não rasgarei o reino todo; mas uma tribo darei a teu filho, por amor de meu servo Davi, e por amor de Jerusalém, que escolhi.' },
      { v: 14, en: 'Yahweh raised up an adversary to Solomon: Hadad the Edomite. He was one of the king’s offspring in Edom.', pt: 'O Senhor levantou contra Salomão um adversário, Hadade, o edomeu; o qual era da estirpe real de Edom.' },
      { v: 15, en: 'For when David was in Edom, and Joab the captain of the army had gone up to bury the slain, and had struck every male in Edom', pt: 'Porque sucedeu que, quando Davi esteve em guerra contra Edom, tendo Jeabe, o chefe do exército, subido a enterrar os mortos, e ferido a todo varão em Edom' },
      { v: 16, en: '(for Joab and all Israel remained there six months, until he had cut off every male in Edom);', pt: '(porque Joabe ficou ali seis meses com todo o Israel, até que destruiu a todo varão em Edom),' },
      { v: 17, en: 'Hadad fled, he and certain Edomites of his father’s servants with him, to go into Egypt, when Hadad was still a little child.', pt: 'Hadade, que era ainda menino, fugiu para o Egito com alguns edemeus, servos de seu pai.' },
      { v: 18, en: 'They arose out of Midian, and came to Paran; and they took men with them out of Paran, and they came to Egypt, to Pharaoh king of Egypt, who gave him a house, and appointed him food, and gave him land.', pt: 'Levantando-se, pois, de Midiã, foram a Parã; e tomando consigo homens de Parã, foram ao Egito ter com Faraó, rei do Egito, o qual deu casa a Hadade, proveu-lhe a subsistência, e lhe deu terras.' },
      { v: 19, en: 'Hadad found great favor in the sight of Pharaoh, so that he gave him as wife the sister of his own wife, the sister of Tahpenes the queen.', pt: 'E Hadade caiu tanto em graça a Faraó, que este lhe deu por mulher a irmã de sua mulher, a irmã da rainha Tafnes.' },
      { v: 20, en: 'The sister of Tahpenes bore him Genubath his son, whom Tahpenes weaned in Pharaoh’s house; and Genubath was in Pharaoh’s house among the sons of Pharaoh.', pt: 'Ora, desta irmã de Tafnes nasceu a Hadade seu filho Genubate, a qual Tafnes criou na casa de Faraó, onde Genubate esteve entre os filhos de rei.' },
      { v: 21, en: 'When Hadad heard in Egypt that David slept with his fathers, and that Joab the captain of the army was dead, Hadad said to Pharaoh, “Let me depart, that I may go to my own country.”', pt: 'Ouvindo, pois, Hadade no Egito que Davi adormecera com seus pais, e que Jeabe, chefe do exército, era morto, disse o Faraó: Deixa-me ir, para que eu volte à minha terra.' },
      { v: 22, en: 'Then Pharaoh said to him, “But what have you lacked with me, that behold, you seek to go to your own country?” He answered, “Nothing, however only let me depart.”', pt: 'Perguntou-lhe Faraó: Que te falta em minha companhia, que procuras partir para a tua terra? Respondeu ele: Nada; todavia, peço que me deixes ir.' },
      { v: 23, en: 'God raised up an adversary to him, Rezon the son of Eliada, who had fled from his lord Hadadezer king of Zobah.', pt: 'Deus levantou contra Salomão ainda outro adversário, Rezom, filho de Eliadá, que tinha fugido de seu senhor Hadadézer, rei de Zobá.' },
      { v: 24, en: 'He gathered men to himself, and became captain over a troop, when David killed them of Zobah. They went to Damascus, and lived there, and reigned in Damascus.', pt: 'Pois ele ajuntara a si homens, e se fizera capitão de uma tropa, quando Davi matou os de Zebá; e, indo-se para Damasco, habitaram ali; e fizeram-no rei em Damasco.' },
      { v: 25, en: 'He was an adversary to Israel all the days of Solomon, besides the mischief of Hadad. He abhorred Israel, and reigned over Syria.', pt: 'E foi adversário de Israel por todos os dias de Salomão, e isto além do mal que Hadade fazia; detestava a Israel, e reinava sobre a Síria.' },
      { v: 26, en: 'Jeroboam the son of Nebat, an Ephraimite of Zeredah, a servant of Solomon, whose mother’s name was Zeruah, a widow, also lifted up his hand against the king.', pt: 'Também Jeroboão, filho de Nebate, efrateu de Zeredá, servo de Salomão, cuja mãe era viúva, por nome Zeruá, levantou a mão contra o rei.' },
      { v: 27, en: 'This was the reason why he lifted up his hand against the king: Solomon built Millo, and repaired the breach of his father David’s city.', pt: 'E esta foi a causa por que levantou a mão contra o rei: Salomão tinha edificado a Milo, e cerrado a brecha da cidade de Davi, seu pai.' },
      { v: 28, en: 'The man Jeroboam was a mighty man of valor; and Solomon saw the young man that he was industrious, and he put him in charge of all the labor of the house of Joseph.', pt: 'Ora, Jeroboão era homem forte e valente; e vendo Salomão que este mancebo era laborioso, colocou-o sobre toda a carga imposta à casa de José.' },
      { v: 29, en: 'At that time, when Jeroboam went out of Jerusalem, the prophet Ahijah the Shilonite found him on the way; now Ahijah had clad himself with a new garment; and they two were alone in the field.', pt: 'E sucedeu naquele tempo que, saindo Jeroboão de Jerusalém, o profeta Aías, o silonita, o encontrou no caminho; este se tinha vestido duma capa nova; e os dois estavam sós no campo.' },
      { v: 30, en: 'Ahijah laid hold of the new garment that was on him, and tore it in twelve pieces.', pt: 'Então Aías pegou na capa nova que tinha sobre si, e a rasgou em doze pedaços.' },
      { v: 31, en: 'He said to Jeroboam, “Take ten pieces; for Yahweh, the God of Israel, says, ‘Behold, I will tear the kingdom out of the hand of Solomon, and will give ten tribes to you', pt: 'E disse a Jeroboão: Toma estes dez pedaços para ti, porque assim diz e Senhor Deus de Israel: Eis que rasgarei o reino da mão de Salomão, e a ti darei dez tribos.' },
      { v: 32, en: '(but he shall have one tribe, for my servant David’s sake and for Jerusalem’s sake, the city which I have chosen out of all the tribes of Israel);', pt: 'Ele, porém, terá uma tribo, por amor de Davi, meu servo, e por amor de Jerusalém, a cidade que escolhi dentre todas as tribos de Israel.' },
      { v: 33, en: 'because that they have forsaken me, and have worshiped Ashtoreth the goddess of the Sidonians, Chemosh the god of Moab, and Milcom the god of the children of Ammon. They have not walked in my ways, to do that which is right in my eyes, and to keep my statutes and my ordinances, as David his father did.', pt: 'Porque me deixaram, e se encurvaram a Astarote, deusa dos sidônios, a Quemés, deus dos moabitas, e a Milcom, deus dos amonitas; e não andaram pelos meus caminhos, para fazerem o que parece reto aos meus olhos, e para guardarem os meus estatutos e os meus preceitos, como o fez Davi, seu pai.' },
      { v: 34, en: '“‘However I will not take the whole kingdom out of his hand; but I will make him prince all the days of his life, for David my servant’s sake whom I chose, who kept my commandments and my statutes;', pt: 'Todavia não tomarei da sua mão o reino todo; mas deixá-lo-ei governar por todos os dias da sua vida, por amor de Davi, meu servo, a quem escolhi, o qual guardou os meus mandamentos e os meus estatutos.' },
      { v: 35, en: 'but I will take the kingdom out of his son’s hand, and will give it to you, even ten tribes.', pt: 'Mas da mão de seu filho tomarei e reino e to darei a ti, isto é, as dez tribos.' },
      { v: 36, en: 'To his son will I give one tribe, that David my servant may have a lamp always before me in Jerusalem, the city which I have chosen for myself to put my name there.', pt: 'Todavia a seu filho darei uma tribo, para que Davi, meu servo, sempre tenha uma lâmpada diante de mim em Jerusalém, a cidade que escolhi para ali pôr o meu nome.' },
      { v: 37, en: 'I will take you, and you shall reign according to all that your soul desires, and shall be king over Israel.', pt: 'Então te tomarei, e reinarás sobre tudo o que desejar a tua alma, e serás rei sobre Israel.' },
      { v: 38, en: 'It shall be, if you will listen to all that I command you, and will walk in my ways, and do that which is right in my eyes, to keep my statutes and my commandments, as David my servant did; that I will be with you, and will build you a sure house, as I built for David, and will give Israel to you.', pt: 'E há de ser que, se ouvires tudo o que eu te ordenar, e andares polos meus caminhos, e fizeres o que é reto aos meus olhos, guardando os meus estatutos e os meus mandamentos, como o fez Davi, meu servo, eu serei contigo, e te edificarei uma casa firme, como o fiz para Davi, e te darei Israel.' },
      { v: 39, en: 'I will afflict the offspring of David for this, but not forever.’”', pt: 'E por isso afligirei a descendência de Davi, todavia não para sempre.' },
      { v: 40, en: 'Therefore Solomon sought to kill Jeroboam; but Jeroboam arose, and fled into Egypt, to Shishak king of Egypt, and was in Egypt until the death of Solomon.', pt: 'Pelo que Salomão procurou matar Jeroboão; porém este se levantou, e fugiu para o Egito, a ter com Sisaque, rei de Egito, onde esteve até a morte de Salomão.' },
      { v: 41, en: 'Now the rest of the acts of Solomon, and all that he did, and his wisdom, aren’t they written in the book of the acts of Solomon?', pt: 'Quanto ao restante dos atos de Salomão, e a tudo o que ele fez, e à sua sabedoria, porventura não está escrito no livro dos atos de Salomão?' },
      { v: 42, en: 'The time that Solomon reigned in Jerusalem over all Israel was forty years.', pt: 'O tempo que Salomão reinou em Jerusalém sobre todo o Israel foi quarenta anos.' },
      { v: 43, en: 'Solomon slept with his fathers, and was buried in his father David’s city; and Rehoboam his son reigned in his place.', pt: 'E Salomão dormiu com seus pais, e foi sepultado na cidade de Davi, seu pai; e Roboão, seu filho, reinou em seu lugar.' },
    ],
    12: [
      { v: 1, en: 'Rehoboam went to Shechem, for all Israel had come to Shechem to make him king.', pt: 'Foi então Roboão para Siquém, porque todo o Israel se congregara ali para fazê-lo rei.' },
      { v: 2, en: 'When Jeroboam the son of Nebat heard of it (for he was yet in Egypt, where he had fled from the presence of king Solomon, and Jeroboam lived in Egypt,', pt: 'E Jeroboão, filho de Nebate, que estava ainda no Egito, para onde fugira da presença do rei Salomão, ouvindo isto, voltou do Egito.' },
      { v: 3, en: 'and they sent and called him), Jeroboam and all the assembly of Israel came, and spoke to Rehoboam, saying,', pt: 'E mandaram chamá-lo; Jeroboão e toda a congregação de Israel vieram, e falaram a Roboão, dizendo:' },
      { v: 4, en: '“Your father made our yoke difficult. Now therefore make the hard service of your father, and his heavy yoke which he put on us, lighter, and we will serve you.”', pt: 'Teu pai agravou o nosso jugo; agora, pois, alivia a dura servidão e o pesado juro que teu pai nos impôs, e nós te serviremos.' },
      { v: 5, en: 'He said to them, “Depart for three days, then come back to me.” The people departed.', pt: 'Ele lhes respondeu: Ide-vos até o terceiro dia, e então voltai a mim. E o povo se foi.' },
      { v: 6, en: 'King Rehoboam took counsel with the old men, who had stood before Solomon his father while he yet lived, saying, “What counsel do you give me to answer these people?”', pt: 'Teve o rei Roboão conselho com os anciãos que tinham assistido diante de Salomão, seu pai, quando este ainda vivia, e perguntou-lhes: como aconselhais vós que eu responda a este povo?' },
      { v: 7, en: 'They replied, “If you will be a servant to this people today, and will serve them, and answer them with good words, then they will be your servants forever.”', pt: 'Eles lhe disseram: Se hoje te tornares servo deste povo, e o servires, e, respondendo-lhe, lhe falares boas palavras, eles serão para sempre teus servos.' },
      { v: 8, en: 'But he abandoned the counsel of the old men which they had given him, and took counsel with the young men who had grown up with him, who stood before him.', pt: 'Ele, porém, deixou o conselho que os anciãos lhe deram, e teve conselho com os mancebos que haviam crescido com ele, e que assistiam diante dele,' },
      { v: 9, en: 'He said to them, “What counsel do you give, that we may answer these people, who have spoken to me, saying, ‘Make the yoke that your father put on us lighter?’”', pt: 'perguntando-lhes: Que aconselhais vós que respondamos a este povo, que me disse: Alivia o jugo que teu pai nos impôs?' },
      { v: 10, en: 'The young men who had grown up with him said to him, “Tell these people who spoke to you, saying, ‘Your father made our yoke heavy, but make it lighter to us;’ tell them, ‘My little finger is thicker than my father’s waist.', pt: 'E os mancebos que haviam crescido com ele responderam-lhe: A este povo que te falou, dizendo: Teu pai fez pesado o nosso jugo, mas tu o alivia de sobre nós; assim lhe falarás: Meu dedo mínimo é mais grosso do que os lombos de meu pai.' },
      { v: 11, en: 'Now my father burdened you with a heavy yoke, but I will add to your yoke. My father chastised you with whips, but I will chastise you with scorpions.’”', pt: 'Assim que, se meu pai vos carregou dum jugo pesado, eu ainda aumentarei o vosso jugo; meu pai vos castigou com açoites; eu, porém, vos castigarei com escorpiões.' },
      { v: 12, en: 'So Jeroboam and all the people came to Rehoboam the third day, as the king asked, saying, “Come to me again the third day.”', pt: 'Veio, pois, Jeroboão com todo o povo a Roboão ao terceiro dia, como o rei havia ordenado, dizendo: Voltai a mim ao terceiro dia.' },
      { v: 13, en: 'The king answered the people roughly, and abandoned the counsel of the old men which they had given him,', pt: 'E o rei respondeu ao povo asperamente e, deixando o conselho que os anciãos lhe haviam dado,' },
      { v: 14, en: 'and spoke to them according to the counsel of the young men, saying, “My father made your yoke heavy, but I will add to your yoke. My father chastised you with whips, but I will chastise you with scorpions.”', pt: 'falou-lhe conforme o conselho dos mancebos, dizendo: Meu pai agravou o vosso jugo, porém eu ainda o aumentarei; meu pai vos castigou com açoites, porém eu vos castigarei com escorpiões.' },
      { v: 15, en: 'So the king didn’t listen to the people; for it was a thing brought about from Yahweh, that he might establish his word, which Yahweh spoke by Ahijah the Shilonite to Jeroboam the son of Nebat.', pt: 'O rei, pois, não deu ouvidos ao povo; porque esta mudança vinha do Senhor, para confirmar a palavra que o Senhor dissera por intermédio de Aías, o silonita, a Jeroboão, filho de Nebate.' },
      { v: 16, en: 'When all Israel saw that the king didn’t listen to them, the people answered the king, saying, “What portion have we in David? We don’t have an inheritance in the son of Jesse. To your tents, Israel! Now see to your own house, David.” So Israel departed to their tents.', pt: 'Vendo, pois, todo o Israel que o rei não lhe dava ouvidos, respondeu-lhe, dizendo: Que parte temos nós em Davi? Não temos herança no filho de Jessé. Âs tuas tendas, ó Israel! Agora olha por tua casa, ó Davi! Então Israel se foi para as suas tendas.' },
      { v: 17, en: 'But as for the children of Israel who lived in the cities of Judah, Rehoboam reigned over them.', pt: '(Mas quanto aos filhos de Israel que habitavam nas cidades de Judá, sobre eles reinou Roboão.)' },
      { v: 18, en: 'Then king Rehoboam sent Adoram, who was over the men subject to forced labor; and all Israel stoned him to death with stones. King Rehoboam hurried to get himself up to his chariot, to flee to Jerusalem.', pt: 'Então o rei Roboão enviou-lhes Adorão, que estava sobre a leva de tributários servis; e todo o Israel o apedrejou, e ele morreu. Pelo que o rei Roboão se apressou a subir ao seu carro e fugiu para Jerusalém.' },
      { v: 19, en: 'So Israel rebelled against David’s house to this day.', pt: 'Assim Israel se rebelou contra a casa de Davi até o dia de hoje.' },
      { v: 20, en: 'When all Israel heard that Jeroboam had returned, they sent and called him to the congregation, and made him king over all Israel. There was no one who followed David’s house, except for the tribe of Judah only.', pt: 'Sucedeu então que, ouvindo todo o Israel que Jeroboão tinha voltado, mandaram chamá-lo para a congregação, e o fizeram rei sobre todo o Israel; e não houve ninguém que seguisse a casa de Davi, senão somente a tribo de Judá.' },
      { v: 21, en: 'When Rehoboam had come to Jerusalem, he assembled all the house of Judah and the tribe of Benjamin, a hundred and eighty thousand chosen men, who were warriors, to fight against the house of Israel, to bring the kingdom again to Rehoboam the son of Solomon.', pt: 'Tendo Roboão chegado a Jerusalém, convocou toda a casa de Judá e a tribo de Benjamim, cento e oitenta mil homens escolhidos, destros para a guerra, para pelejarem contra a casa de Israel a fim de restituírem o reino a Roboãa, filho de Salomão.' },
      { v: 22, en: 'But the word of God came to Shemaiah the man of God, saying,', pt: 'Veio, porém, a palavra de Deus a Semaías, homem de Deus, dizendo:' },
      { v: 23, en: '“Speak to Rehoboam the son of Solomon, king of Judah, and to all the house of Judah and Benjamin, and to the rest of the people, saying,', pt: 'Fala a Roboão, filho de Salomão, rei de Judá, e a toda a casa de Judá e de Benjamim, e ao resto do povo, dizendo:' },
      { v: 24, en: '‘Yahweh says, “You shall not go up or fight against your brothers, the children of Israel. Everyone return to his house; for this thing is from me.”’” So they listened to Yahweh’s word, and returned and went their way, according to Yahweh’s word.', pt: 'Assim diz o Senhor: Não subireis, nem pelejareis contra vossos irmãos, os filhos de Israel; volte cada um para a sua casa, porque de mim proveio isto. E ouviram a palavra do Senhor, e voltaram segundo o seu mandado.' },
      { v: 25, en: 'Then Jeroboam built Shechem in the hill country of Ephraim, and lived in it; and he went out from there, and built Penuel.', pt: 'Jeroboão edificou Siquém, na região montanhosa de Efraim, e habitou ali; depois, saindo dali, edificou Penuel.' },
      { v: 26, en: 'Jeroboam said in his heart, “Now the kingdom will return to David’s house.', pt: 'Disse Jeroboão no seu coração: Agora tornará o reino para a casa de Davi.' },
      { v: 27, en: 'If this people goes up to offer sacrifices in Yahweh’s house at Jerusalem, then the heart of this people will turn again to their lord, even to Rehoboam king of Judah; and they will kill me, and return to Rehoboam king of Judah.”', pt: 'Se este povo subir para fazer sacrifícios na casa do Senhor, em Jerusalém, o seu coração se tornará para o seu senhor, Roboão, rei de Judá; e, matando-me, voltarão para Roboão, rei de Judá.' },
      { v: 28, en: 'So the king took counsel, and made two calves of gold; and he said to them, “It is too much for you to go up to Jerusalem. Look and behold your gods, Israel, which brought you up out of the land of Egypt!”', pt: 'Pelo que o rei, tendo tomado conselho, fez doisvado e meio. ouro; e disse ao povo: Basta de subires a Jerusalém; eis aqui teus deuses, ó Israel, que te fizeram subir da terra do Egito.' },
      { v: 29, en: 'He set the one in Bethel, and the other put he in Dan.', pt: 'E pôs um em Betel, e o outro em Dã.' },
      { v: 30, en: 'This thing became a sin; for the people went even as far as Dan to worship before the one there.', pt: 'Ora, isto se tornou em pecado; pois que o povo ia até Dã para adorar o ídolo.' },
      { v: 31, en: 'He made houses of high places, and made priests from among all the people, who were not of the sons of Levi.', pt: 'Também fez casas nos altos, e constituiu sacerdotes dentre o povo, que não eram dos filhos de Levi.' },
      { v: 32, en: 'Jeroboam ordained a feast in the eighth month, on the fifteenth day of the month, like the feast that is in Judah, and he went up to the altar. He did so in Bethel, sacrificing to the calves that he had made, and he placed in Bethel the priests of the high places that he had made.', pt: 'E Jeroboão ordenou uma festa no oitavo mês, no dia décimo quinto do mês, como a festa que se celebrava em Judá, e sacrificou no altar. Semelhantemente fez em Betel, sacrificando aos bezerros que tinha feito; também em Betel estabeleceu os sacerdotes dos altos que fizera.' },
      { v: 33, en: 'He went up to the altar which he had made in Bethel on the fifteenth day in the eighth month, even in the month which he had devised of his own heart; and he ordained a feast for the children of Israel, and went up to the altar, to burn incense.', pt: 'Sacrificou, pois, no altar, que fizera em Betel, no dia décimo quinto do oitavo mês, mês que ele tinha escolhido a seu bel prazer; assim ordenou uma festa para os filhos de Israel, e sacrificou no altar, queimando incenso.' },
    ],
    13: [
      { v: 1, en: 'Behold, a man of God came out of Judah by Yahweh’s word to Beth El; and Jeroboam was standing by the altar to burn incense.', pt: 'Eis que, por ordem do Senhor, veio de Judá a Betel um homem de Deus; e Jeroboão estava junto ao altar, para queimar incenso.' },
      { v: 2, en: 'He cried against the altar by Yahweh’s word, and said, “Altar! Altar! Yahweh says: ‘Behold, a son will be born to David’s house, Josiah by name. On you he will sacrifice the priests of the high places who burn incense on you, and they will burn men’s bones on you.’”', pt: 'E o homem clamou contra o altar, por ordem do Senhor, dizendo: Altar, altar! assim diz o Senhor: Eis que um filho nascerá à casa de Davi, cujo nome será Josias; e qual sacrificará sobre ti os sacerdotes dos altos que sobre ti queimam incenso, e ossos de homens se queimarão sobre ti.' },
      { v: 3, en: 'He gave a sign the same day, saying, “This is the sign which Yahweh has spoken: Behold, the altar will be split apart, and the ashes that are on it will be poured out.”', pt: 'E deu naquele mesmo dia um sinal, dizendo: Este é o sinal de que o Senhor falou; Eis que o altar se fenderá, e a cinza que está sobre ele se derramará.' },
      { v: 4, en: 'When the king heard the saying of the man of God, which he cried against the altar in Bethel, Jeroboam put out his hand from the altar, saying, “Seize him!” His hand, which he put out against him, dried up, so that he could not draw it back again to himself.', pt: 'Sucedeu pois que, ouvindo o rei Jeroboão a palavra que o homem de Deus clamara contra o altar de Betel, estendeu a mão de sobre o altar, dizendo: Pegai-o! E logo, a mão que estendera contra ele secou-se, de modo que não podia tornar a trazê-la a si.' },
      { v: 5, en: 'The altar was also split apart, and the ashes poured out from the altar, according to the sign which the man of God had given by Yahweh’s word.', pt: 'E o altar se fendeu, e a cinza se derramou do altar, conforme o sinal que o homem de Deus, por ordem do Senhor, havia dado.' },
      { v: 6, en: 'The king answered the man of God, “Now intercede for the favor of Yahweh your God, and pray for me, that my hand may be restored me again.” The man of God interceded with Yahweh, and the king’s hand was restored to him again, and became as it was before.', pt: 'Então respondeu o rei, e disse ao homem de Deus: Suplica ao Senhor teu Deus, e roga por mim, para que se me restitua a minha mão. Pelo que o homem de Deus suplicou ao Senhor, e a mão do rei se lhe restituiu, e ficou como dantes.' },
      { v: 7, en: 'The king said to the man of God, “Come home with me, and refresh yourself, and I will give you a reward.”', pt: 'Disse então o rei ao homem de Deus: Vem comigo a minha casa, e conforta-te, e dar-te-ei uma recompensa.' },
      { v: 8, en: 'The man of God said to the king, “Even if you gave me half of your house, I would not go in with you, neither would I eat bread nor drink water in this place;', pt: 'Mas o homem de Deus respondeu ao rei: Ainda que me desses metade da tua casa, não iria contigo, nem comeria pão, nem beberia água neste lugar.' },
      { v: 9, en: 'for so was it commanded me by Yahweh’s word, saying, ‘You shall eat no bread, drink no water, and don’t return by the way that you came.’”', pt: 'Porque assim me ordenou o Senhor pela sua palavra, dizendo: Não comas pão, nem bebas água, nem voltes pelo caminho por onde vieste.' },
      { v: 10, en: 'So he went another way, and didn’t return by the way that he came to Bethel.', pt: 'Ele, pois, se foi por outro caminho, e não voltou pelo caminho por onde viera a Betel.' },
      { v: 11, en: 'Now an old prophet lived in Bethel, and one of his sons came and told him all the works that the man of God had done that day in Bethel. They also told their father the words which he had spoken to the king.', pt: 'Ora, morava em Betel um velho profeta. Seus filhos vieram contar-lhe tudo o que o homem de Deus fizera aquele dia em Betel; e as palavras que ele dissera ao rei, contaram-nas também a seu pai.' },
      { v: 12, en: 'Their father said to them, “Which way did he go?” Now his sons had seen which way the man of God went, who came from Judah.', pt: 'Perguntou-lhes seu pai: Por que caminho se foi? pois seus filhos tinham visto o caminho por onde fora o homem de Deus que viera de Judá.' },
      { v: 13, en: 'He said to his sons, “Saddle the donkey for me.” So they saddled the donkey for him; and he rode on it.', pt: 'Então disse a seus filhos: Albardai-me o jumento. E albardaram-lhe o jumento, no qual ele montou.' },
      { v: 14, en: 'He went after the man of God, and found him sitting under an oak. He said to him, “Are you the man of God who came from Judah?” He said, “I am.”', pt: 'E tendo ido após o homem de Deus, achou-o sentado debaixo de um carvalho, e perguntou-lhe: És tu o homem de Deus que vieste de Judá? Respondeu ele: Sou.' },
      { v: 15, en: 'Then he said to him, “Come home with me, and eat bread.”', pt: 'Então lhe disse: Vem comigo a casa, e come pão.' },
      { v: 16, en: 'He said, “I may not return with you, nor go in with you. I will not eat bread or drink water with you in this place.', pt: 'Mas ele tornou: Não posso voltar contigo, nem entrar em tua casa; nem tampouco comerei pão, nem beberei água contigo neste lugar;' },
      { v: 17, en: 'For it was said to me by Yahweh’s word, ‘You shall eat no bread or drink water there, and don’t turn again to go by the way that you came.’”', pt: 'porque me foi mandado pela palavra de Senhor: Ali não comas pão, nem bebas água, nem voltes pelo caminho por onde vieste.' },
      { v: 18, en: 'He said to him, “I also am a prophet as you are; and an angel spoke to me by Yahweh’s word, saying, ‘Bring him back with you into your house, that he may eat bread and drink water.’” He lied to him.', pt: 'Respondeu-lhe o outro: Eu também sou profeta como tu, e um anjo me falou por ordem do Senhor, dizendo: Faze-o voltar contigo a tua casa, para que coma pão e beba água. Mas mentia-lhe.' },
      { v: 19, en: 'So he went back with him, ate bread in his house, and drank water.', pt: 'Assim o homem voltou com ele, comeu pão em sua casa, e bebeu água.' },
      { v: 20, en: 'As they sat at the table, Yahweh’s word came to the prophet who brought him back;', pt: 'Estando eles à mesa, a palavra do Senhor veio ao profeta que o tinha feito voltar;' },
      { v: 21, en: 'and he cried out to the man of God who came from Judah, saying, “Yahweh says, ‘Because you have been disobedient to Yahweh’s mouth, and have not kept the commandment which Yahweh your God commanded you,', pt: 'e ele clamou ao homem de Deus que viera de Judá, dizendo: Assim diz o Senhor: Porquanto foste rebelde à ordem do Senhor, e não guardaste o mandamento que o Senhor teu Deus te mandara,' },
      { v: 22, en: 'but came back, and have eaten bread and drank water in the place of which he said to you, “Eat no bread, and drink no water”; your body will not come to the tomb of your fathers.’”', pt: 'mas voltaste, e comeste pão e bebeste água no lugar de que te dissera: Não comas pão, nem bebas água; o teu cadáver não entrará no sepulcro de teus pais.' },
      { v: 23, en: 'After he had eaten bread, and after he drank, he saddled the donkey for the prophet whom he had brought back.', pt: 'E, havendo eles comido e bebido, albardou o jumento para o profeta que fizera voltar.' },
      { v: 24, en: 'When he had gone, a lion met him by the way and killed him. His body was thrown on the path, and the donkey stood by it. The lion also stood by the body.', pt: 'Este, pois, se foi, e um leão o encontrou no caminho, e o matou; o seu cadáver ficou estendido no caminho, e o jumento estava parado junto a ele, e também o leão estava junto ao cadáver.' },
      { v: 25, en: 'Behold, men passed by, and saw the body thrown on the path, and the lion standing by the body; and they came and told it in the city where the old prophet lived.', pt: 'E, passando por ali alguns homens, viram o cadáver estendido no caminho, e o leão ao lado dele. Foram, pois, e o disseram na cidade onde o velho profeta habitava.' },
      { v: 26, en: 'When the prophet who brought him back from the way heard of it, he said, “It is the man of God who was disobedient to Yahweh’s mouth. Therefore Yahweh has delivered him to the lion, which has mauled him and slain him, according to Yahweh’s word, which he spoke to him.”', pt: 'Quando o profeta que o fizera voltar do caminho ouviu isto, disse: É o homem de Deus, que foi rebelde à palavra do Senhor; por isso o Senhor o entregou ao leão, que o despedaçou e matou, segundo a palavra que o Senhor lhe dissera.' },
      { v: 27, en: 'He said to his sons, saying, “Saddle the donkey for me,” and they saddled it.', pt: 'E disse a seus filhos: Albardai-me e jumento. Eles lho albardaram.' },
      { v: 28, en: 'He went and found his body thrown on the path, and the donkey and the lion standing by the body. The lion had not eaten the body, nor mauled the donkey.', pt: 'Então foi e achou o cadáver estendido no caminho, e o jumento e o leão, que estavam parados junto ao cadáver; o leão não o havia devorado, nem havia despedaçado o jumento.' },
      { v: 29, en: 'The prophet took up the body of the man of God, and laid it on the donkey, and brought it back. He came to the city of the old prophet to mourn, and to bury him.', pt: 'Então e profeta levantou o cadáver do homem de Deus e, pondo-o em cima do jumento, levou-o consigo; assim veio o velho profeta à cidade para o chorar e o sepultar.' },
      { v: 30, en: 'He laid his body in his own grave; and they mourned over him, saying, “Alas, my brother!”', pt: 'E colocou o cadáver no seu próprio sepulcro; e prantearam-no, dizendo: Ah, irmão meu!' },
      { v: 31, en: 'After he had buried him, he spoke to his sons, saying, “When I am dead, bury me in the tomb in which the man of God is buried. Lay my bones beside his bones.', pt: 'Depois de o haver sepultado, disse a seus filhos. Quando eu morrer, sepultai-me no sepulcro em que o homem de Deus está sepultado; ponde os meus ossos junto aos ossos dele.' },
      { v: 32, en: 'For the saying which he cried by Yahweh’s word against the altar in Bethel, and against all the houses of the high places which are in the cities of Samaria, will surely happen.”', pt: 'Porque certamente se cumprirá o que, pela palavra de Senhor, clamou, contra o altar que está em Betel, como tambem contra todas as casas dos altos que estão nas cidades de Samária.' },
      { v: 33, en: 'After this thing Jeroboam didn’t return from his evil way, but again made priests of the high places from among all the people. Whoever wanted to, he consecrated him, that there might be priests of the high places.', pt: 'Nem depois destas coisas deixou Jeroboão e seu mau caminho, porém tornou a fazer dentre todo o povo sacerdotes dos lugares altos; e a qualquer que o queria consagrava sacerdote dos lugares altos.' },
      { v: 34, en: 'This thing became sin to the house of Jeroboam, even to cut it off, and to destroy it from off the surface of the earth.', pt: 'E isso foi causa de pecado à casa de Jeroboão, para destruí-la e extingui-la da face da terra.' },
    ],
    14: [
      { v: 1, en: 'At that time Abijah the son of Jeroboam became sick.', pt: 'Naquele tempo adoeceu Abias, filho de Jeroboão.' },
      { v: 2, en: 'Jeroboam said to his wife, “Please get up and disguise yourself, so that you won’t be recognized as Jeroboam’s wife. Go to Shiloh. Behold, Ahijah the prophet is there, who said that that I would be king over this people.', pt: 'E disse Jeroboão a sua mulher: Levanta-te, e disfarça-te, para que não conheçam que és mulher de Jeroboão, e vai a Siló. Eis que lá está o profeta Aías, o qual falou acerca de mim que eu seria rei sobre este povo.' },
      { v: 3, en: 'Take with you ten loaves of bread, some cakes, and a jar of honey, and go to him. He will tell you what will become of the child.”', pt: 'Leva contigo dez pães, alguns bolos e uma botija de mel, e vai ter com ele; ele te declarará o que há de suceder a este menino.' },
      { v: 4, en: 'Jeroboam’s wife did so, and arose, and went to Shiloh, and came to Ahijah’s house. Now Ahijah could not see; for his eyes were set by reason of his age.', pt: 'Assim, pois, fez a mulher de Jeroboão; e, levantando-se, foi a Siló, e entrou na casa de Aías. Este já não podia ver, pois seus olhos haviam cegado por causa da velhice.' },
      { v: 5, en: 'Yahweh said to Ahijah, “Behold, Jeroboam’s wife is coming to inquire of you concerning her son; for he is sick. Tell her such and such; for it will be, when she comes in, that she will pretend to be another woman.”', pt: 'O Senhor, porém, dissera a Aías: Eis que a mulher de Jeroboão vem consultar-te sobre seu filho, que está doente. Assim e assim lhe falarás; porque há de ser que, entrando ela, fingirá ser outra.' },
      { v: 6, en: 'So when Ahijah heard the sound of her feet as she came in at the door, he said, “Come in, Jeroboam’s wife! Why do you pretend to be another? For I am sent to you with heavy news.', pt: 'Sucedeu que, ouvindo Aías o ruído de seus pés, ao entrar ela pela porta, disse: Entra, mulher de Jeroboão; por que te disfarças assim? Pois eu sou enviado a ti com duras novas.' },
      { v: 7, en: 'Go, tell Jeroboam, ‘Yahweh, the God of Israel, says: “Because I exalted you from among the people, and made you prince over my people Israel,', pt: 'Vai, dize a Jeroboão: Assim diz o Senhor Deus de Israel: Porquanto te exaltei do meio do povo, e te constituí príncipe sobre o meu povo de Israel,' },
      { v: 8, en: 'and tore the kingdom away from David’s house, and gave it you; and yet you have not been as my servant David, who kept my commandments, and who followed me with all his heart, to do that only which was right in my eyes,', pt: 'e rasguei o reino da casa de Davi, e o dei a ti; todavia não tens sido como o meu servo Davi, que guardou os meus mandamentos e que me seguiu de todo o coração para fazer somente o que era reto aos meus olhos;' },
      { v: 9, en: 'but have done evil above all who were before you, and have gone and made for yourself other gods, molten images, to provoke me to anger, and have cast me behind your back;', pt: 'mas tens praticado o mal, pior do que todos os que foram antes de ti, e foste fizeste para ti outros deuses e imagens de fundição, para provocar-me à ira, e me lançaste para trás das tuas costas;' },
      { v: 10, en: 'therefore, behold, I will bring evil on the house of Jeroboam, and will cut off from Jeroboam everyone who urinates on a wall, he who is shut up and he who is left at large in Israel, and will utterly sweep away the house of Jeroboam, as a man sweeps away dung, until it is all gone.', pt: 'portanto, eis que trarei o mal sobre a casa de Jeroboão, e exterminarei de Jeroboão todo homem, escravo ou livre, em Israel, e lançarei fora os remanescentes da casa de Jeroboão, como se lança fora o esterco, até que de todo se acabe.' },
      { v: 11, en: 'The dogs will eat he who belongs to Jeroboam who dies in the city; and the birds of the sky will eat he who dies in the field: for Yahweh has spoken it.”’', pt: 'Quem morrer a Jeroboão na cidade, comê-lo-ão os cães; e o que lhe morrer no campo, comê-lo-ão as aves do céu; porque o Senhor o disse.' },
      { v: 12, en: 'Arise therefore, and go to your house. When your feet enter into the city, the child will die.', pt: 'Levanta-te, pois, e vai-te para tua casa; ao entrarem os teus pés na cidade, o menino morrerá.' },
      { v: 13, en: 'All Israel will mourn for him and bury him; for he only of Jeroboam will come to the grave, because in him there is found some good thing toward Yahweh, the God of Israel, in the house of Jeroboam.', pt: 'E todo o Israel o pranteará, e o sepultará; porque de Jeroboão só este entrará em sepultura, porquanto, dos da casa de Jeroboão, só nele se achou alguma coisa boa para com o Senhor Deus de Israel.' },
      { v: 14, en: 'Moreover Yahweh will raise up a king for himself over Israel, who will cut off the house of Jeroboam. This is the day! What? Even now.', pt: 'O Senhor, porém, levantará para si um rei sobre Israel, que destruirá a casa de Jeroboão nesse dia. - E agora, que será?' },
      { v: 15, en: 'For Yahweh will strike Israel, as a reed is shaken in the water; and he will root up Israel out of this good land which he gave to their fathers, and will scatter them beyond the River, because they have made their Asherah poles, provoking Yahweh to anger.', pt: 'Ferirá o Senhor a Israel, como se agita a cana nas águas; e arrancará a Israel desta boa terra que tinha dado a seus pais, e o espalhará para além do rio, porquanto fizeram os seus aserins, provocando o Senhor à ira.' },
      { v: 16, en: 'He will give Israel up because of the sins of Jeroboam, which he has sinned, and with which he has made Israel to sin.”', pt: 'E entregará Israel por causa dos pecados de Jeroboão, o qual pecou e fez pecar a Israel.' },
      { v: 17, en: 'Jeroboam’s wife arose and departed, and came to Tirzah. As she came to the threshold of the house, the child died.', pt: 'Então a mulher de Jeroboão se levantou e partiu, e veio para Tirza; chegando ela ao limiar da casa, o menino morreu.' },
      { v: 18, en: 'All Israel buried him and mourned for him, according to Yahweh’s word, which he spoke by his servant Ahijah the prophet.', pt: 'E todo o Israel o sepultou e o pranteou, conforme a palavra do Senhor, que ele falara por intermédio de seu servo Aías, o profeta.' },
      { v: 19, en: 'The rest of the acts of Jeroboam, how he fought, and how he reigned, behold, they are written in the book of the chronicles of the kings of Israel.', pt: 'Quanto ao restante dos atos de Jeroboão, como guerreou, e como reinou, eis que está escrito no livro das crônicas dos reis de Israel.' },
      { v: 20, en: 'The days which Jeroboam reigned were twenty two years, then he slept with his fathers, and Nadab his son reigned in his place.', pt: 'E o tempo que Jeroboão reinou foi vinte e dois anos. E dormiu com seus pais; e Nadabe, seu filho, reinou em seu lugar.' },
      { v: 21, en: 'Rehoboam the son of Solomon reigned in Judah. Rehoboam was forty-one years old when he began to reign, and he reigned seventeen years in Jerusalem, the city which Yahweh had chosen out of all the tribes of Israel, to put his name there. His mother’s name was Naamah the Ammonitess.', pt: 'Reinou em Judá Roboão, filho de Salomão. Tinha quarenta e um anos quando começou a reinar, e reinou dezessete anos em Jerusalém, a cidade que o Senhor escolhera dentre todas as tribos de Israel para pôr ali o seu nome. E era o nome de sua mãe Naama, a amonita.' },
      { v: 22, en: 'Judah did that which was evil in Yahweh’s sight, and they provoked him to jealousy with their sins which they committed, above all that their fathers had done.', pt: 'E fez Judá o que era mau aos olhos do Senhor; e, com os seus pecados que cometeram, provocaram-no a zelos, mais do que o fizeram os seus pais.' },
      { v: 23, en: 'For they also built for themselves high places, sacred pillars, and Asherah poles on every high hill and under every green tree.', pt: 'Porque também eles edificaram altos, e colunas, e aserins sobre todo alto outeiro e debaixo de toda árvore frondosa;' },
      { v: 24, en: 'There were also sodomites in the land. They did according to all the abominations of the nations which Yahweh drove out before the children of Israel.', pt: 'e havia também sodomitas na terra: fizeram conforme todas as abominações dos povos que o Senhor tinha expulsado de diante dos filhos de Israel.' },
      { v: 25, en: 'In the fifth year of king Rehoboam, Shishak king of Egypt came up against Jerusalem,', pt: 'Ora, sucedeu que, no quinto ano do rei Roboão, Sisaque, rei do Egito, subiu contra Jerusalém,' },
      { v: 26, en: 'and he took away the treasures of Yahweh’s house, and the treasures of the king’s house. He even took away all of it, including all the gold shields which Solomon had made.', pt: 'e tomou os tesouros da casa de Senhor e os tesouros da casa do rei; levou tudo. Também tomou todos os escudos de ouro que Salomão tinha feito.' },
      { v: 27, en: 'King Rehoboam made shields of brass in their place, and committed them to the hands of the captains of the guard, who kept the door of the king’s house.', pt: 'Em lugar deles, fez o rei Roboão escudos de bronze, e os entregou nas mãos dos capitães da guarda, que guardavam a porta da casa do rei.' },
      { v: 28, en: 'It was so, that as often as the king went into Yahweh’s house, the guard bore them, and brought them back into the guard room.', pt: 'E todas as vezes que o rei entrava na casa do Senhor os da guarda levavam os escudos, e depois tornavam a pô-los na câmara da guarda.' },
      { v: 29, en: 'Now the rest of the acts of Rehoboam, and all that he did, aren’t they written in the book of the chronicles of the kings of Judah?', pt: 'Quanto ao restante dos atos de Reboão, e a tudo quanto fez, porventura não estão escritos no livro das crônicas dos reis de Judá?' },
      { v: 30, en: 'There was war between Rehoboam and Jeroboam continually.', pt: 'Houve guerra continuamente entre Roboão e Jeroboão.' },
      { v: 31, en: 'Rehoboam slept with his fathers, and was buried with his fathers in David’s city. His mother’s name was Naamah the Ammonitess. Abijam his son reigned in his place.', pt: 'E Roboão dormiu com seus pais, e foi sepultado com eles na cidade de Davi. Era o nome de sua mãe Naama, a amonita. E Abião, seu filho, reinou em seu lugar.' },
    ],
    15: [
      { v: 1, en: 'Now in the eighteenth year of king Jeroboam the son of Nebat, Abijam began to reign over Judah.', pt: 'No décimo oitavo ano do rei Jeroboão, filho de Nebate, começou Abião a reinar sobre Judá.' },
      { v: 2, en: 'He reigned three years in Jerusalem. His mother’s name was Maacah the daughter of Abishalom.', pt: 'Reinou três anos em Jerusalém. Era o nome de sua mãe Maacá, filha de Absalão.' },
      { v: 3, en: 'He walked in all the sins of his father, which he had done before him; and his heart was not perfect with Yahweh his God, as the heart of David his father.', pt: 'Ele andou em todos os pecados que seu pai tinha cometido antes dele; o seu coração não foi perfeito para com o Senhor seu Deus como o coração de Davi, seu pai.' },
      { v: 4, en: 'Nevertheless for David’s sake, Yahweh his God gave him a lamp in Jerusalem, to set up his son after him, and to establish Jerusalem;', pt: 'Mas por amor de Davi o Senhor lhe deu uma lâmpada em Jerusalém, levantando a seu filho depois dele, e confirmando a Jerusalem;' },
      { v: 5, en: 'because David did that which was right in Yahweh’s eyes, and didn’t turn away from anything that he commanded him all the days of his life, except only in the matter of Uriah the Hittite.', pt: 'porque Davi fez o que era reto aos olhos do Senhor, e não se desviou de tudo o que lhe ordenou em todos os dias da sua vida, a não ser no caso de Urias, o heteu.' },
      { v: 6, en: 'Now there was war between Rehoboam and Jeroboam all the days of his life.', pt: 'Ora, houve guerra entre Roboão e Jeroboão todos os dias da vida de Roboão.' },
      { v: 7, en: 'The rest of the acts of Abijam, and all that he did, aren’t they written in the book of the chronicles of the kings of Judah? There was war between Abijam and Jeroboam.', pt: 'Quanto ao restante dos atos de Abião, e a tudo quanto fez, porventura não estão escritos no livro das crônicas dos reis de Judá? Também houve guerra entre Abião e Jeroboão.' },
      { v: 8, en: 'Abijam slept with his fathers, and they buried him in David’s city; and Asa his son reigned in his place.', pt: 'Abião dormiu com seus pais, e o sepultaram na cidade de Davi. E Asa, seu filho, reinou em seu lugar.' },
      { v: 9, en: 'In the twentieth year of Jeroboam king of Israel, Asa began to reign over Judah.', pt: 'No vigésimo ano de Jeroboão, rei de Israel, começou Asa a reinar em Judá,' },
      { v: 10, en: 'He reigned forty-one years in Jerusalem. His mother’s name was Maacah the daughter of Abishalom.', pt: 'e reinou quarenta e um anos em Jerusalém. Era o nome de sua mãe Maacá, filha de Absalão.' },
      { v: 11, en: 'Asa did that which was right in Yahweh’s eyes, as David his father did.', pt: 'Asa fez o que era reto aos olhos do Senhor, como Davi, seu pai.' },
      { v: 12, en: 'He put away the sodomites out of the land, and removed all the idols that his fathers had made.', pt: 'Porque tirou da terra os sodomitas, e removeu todos os ídolos que seus pais tinham feito.' },
      { v: 13, en: 'He also removed Maacah his mother from being queen, because she had made an abominable image for an Asherah. Asa cut down her image and burned it at the brook Kidron.', pt: 'E até a Maacá, sua mãe, removeu para que não fosse rainha, porquanto tinha feito um abominável ídolo para servir de Asera; e Asa desfez esse ídolo, e o queimou junto ao ribeiro de Cedrom.' },
      { v: 14, en: 'But the high places were not taken away. Nevertheless the heart of Asa was perfect with Yahweh all his days.', pt: 'Os altos, porém, não foram tirados; todavia o coração de Asa foi reto para com o Senhor todos os seus dias.' },
      { v: 15, en: 'He brought into Yahweh’s house the things that his father had dedicated, and the things that he himself had dedicated: silver, gold, and utensils.', pt: 'E trouxe para a casa do Senhor as coisas que seu pai havia consagrado, e as coisas que ele mesmo consagrara: prata, ouro e vasos.' },
      { v: 16, en: 'There was war between Asa and Baasha king of Israel all their days.', pt: 'Ora, houve guerra entre Asa e Baasa, rei de Israel, todos os seus dias.' },
      { v: 17, en: 'Baasha king of Israel went up against Judah, and built Ramah, that he might not allow anyone to go out or come in to Asa king of Judah.', pt: 'Pois Baasa, rei de Israel, subiu contra Judá, e edificou Ramá, para que a ninguém fosse permitido sair, nem entrar a ter com Asa, rei de Judá.' },
      { v: 18, en: 'Then Asa took all the silver and the gold that was left in the treasures of Yahweh’s house, and the treasures of the king’s house, and delivered it into the hand of his servants. Then King Asa sent them to Ben Hadad, the son of Tabrimmon, the son of Hezion, king of Syria, who lived at Damascus, saying,', pt: 'Então Asa tomou toda a prata e ouro que ficaram nos tesouros da casa do Senhor, e os tesouros da casa do rei, e os entregou nas mãos de seus servos. E o rei Asa os enviou a Bene-Hadade, filho de Tabrimom, filho de Heziom, rei da Síria, que habitava em Damasco, dizendo:' },
      { v: 19, en: '“There is a treaty between me and you, between my father and your father. Behold, I have sent to you a present of silver and gold. Go, break your treaty with Baasha king of Israel, that he may depart from me.”', pt: 'Haja aliança entre mim e ti, como houve entre meu pai e teu pai. Eis que aqui te mando um presente de prata e de ouro; vai, e anula a tua aliança com Baasa, rei de Israel, para que ele se retire de mim.' },
      { v: 20, en: 'Ben Hadad listened to king Asa, and sent the captains of his armies against the cities of Israel, and struck Ijon, and Dan, and Abel Beth Maacah, and all Chinneroth, with all the land of Naphtali.', pt: 'Bene-Hadade, pois, deu ouvidos ao rei Asa, e enviou os capitães dos seus exércitos contra as cidades de Israel; e feriu a Ijom, a Dã, a Abel-Bete-Maacá, e a todo o distrito de Quinerote, com toda a terra de Naftali.' },
      { v: 21, en: 'When Baasha heard of it, he stopped building Ramah, and lived in Tirzah.', pt: 'E sucedeu que, ouvindo-o Baasa, deixou de edificar Ramá, e ficou em Tirza.' },
      { v: 22, en: 'Then king Asa made a proclamation to all Judah. No one was exempted. They carried away the stones of Ramah, and its timber, with which Baasha had built; and king Asa used it to build Geba of Benjamin, and Mizpah.', pt: 'Então o rei Asa fez apregoar por toda a Judá que todos, sem exceção, trouxessem as pedras de Ramá, e a madeira com que Baasa a edificava; e com elas o rei Asa edificou Geba de Benjamim e Mizpá.' },
      { v: 23, en: 'Now the rest of all the acts of Asa, and all his might, and all that he did, and the cities which he built, aren’t they written in the book of the chronicles of the kings of Judah? But in the time of his old age he was diseased in his feet.', pt: 'Quanto ao restante de todos os atos de Asa, e todo o seu poder, e tudo quanto fez, e as cidades que edificou, porventura não estão escritos no livro das crônicas dos reis de Judá? Porém, na velhice, ficou, enfermo dos pés.' },
      { v: 24, en: 'Asa slept with his fathers, and was buried with his fathers in his father David’s city; and Jehoshaphat his son reigned in his place.', pt: 'E Asa dormiu com seus pais, e foi sepultado com eles na cidade de Davi seu pai; e Jeosafá, seu filho reinou em seu lugar.' },
      { v: 25, en: 'Nadab the son of Jeroboam began to reign over Israel in the second year of Asa king of Judah; and he reigned over Israel two years.', pt: 'Nadabe, filho de Jeroboão, começou a reinar sobre Israel no segundo ano de Asa, rei de Judá, e reinou sobre Israel dois anos.' },
      { v: 26, en: 'He did that which was evil in Yahweh’s sight, and walked in the way of his father, and in his sin with which he made Israel to sin.', pt: 'E fez o que era mau aos olhos de Senhor, andando nos caminhos de seu pai, e no seu pecado com que tinha feito Israel pecar.' },
      { v: 27, en: 'Baasha the son of Ahijah, of the house of Issachar, conspired against him; and Baasha struck him at Gibbethon, which belonged to the Philistines; for Nadab and all Israel were besieging Gibbethon.', pt: 'Conspirou contra ele Baasa, filho de Aías, da casa de Issacar, e o feriu em Gibetom, que pertencia aos filisteus; pois Nadabe e todo o Israel sitiavam a Gibetom.' },
      { v: 28, en: 'Even in the third year of Asa king of Judah, Baasha killed him, and reigned in his place.', pt: 'Matou-o, pois, Baasa no terceiro ano de Asa, rei de Judá, e reinou em seu lugar.' },
      { v: 29, en: 'As soon as he was king, he struck all the house of Jeroboam. He didn’t leave to Jeroboam any who breathed, until he had destroyed him; according to the saying of Yahweh, which he spoke by his servant Ahijah the Shilonite;', pt: 'E logo que começou a reinar, feriu toda a casa de Jeroboão; a ninguém de Jeroboão que tivesse fôlego deixou de destruir totalmente, conforme a palavra do Senhor que ele falara por intermédio de seu servo Aías, o silonita,' },
      { v: 30, en: 'for the sins of Jeroboam which he sinned, and with which he made Israel to sin, because of his provocation with which he provoked Yahweh, the God of Israel, to anger.', pt: 'por causa dos pecados que Jeroboão cometera, e com que fizera Israel pecar, e por causa da provocação com que provocara à ira o Senhor Deus de Israel.' },
      { v: 31, en: 'Now the rest of the acts of Nadab, and all that he did, aren’t they written in the book of the chronicles of the kings of Israel?', pt: 'Quanto ao restante dos atos de Nadabe, e a tudo quanto fez, porventura não estão escritos no livro das crônicas dos reis de Israel?' },
      { v: 32, en: 'There was war between Asa and Baasha king of Israel all their days.', pt: 'Houve guerra entre Asa e Baasa, rei de Israel, todos os seus dias.' },
      { v: 33, en: 'In the third year of Asa king of Judah, Baasha the son of Ahijah began to reign over all Israel in Tirzah for twenty-four years.', pt: 'No terceiro ano de Asa, rei de Judá, Baasa, filho de Aías, começou a reinar sobre todo o Israel em Tirza, e reinou vinte e quatro anos.' },
      { v: 34, en: 'He did that which was evil in Yahweh’s sight, and walked in the way of Jeroboam, and in his sin with which he made Israel to sin.', pt: 'E fez o que era mau aos olhos do Senhor, andando no caminho de Jeroboão e no seu pecado com que tinha feito Israel pecar.' },
    ],
    16: [
      { v: 1, en: 'Yahweh’s word came to Jehu the son of Hanani against Baasha, saying,', pt: 'Então veio a palavra do Senhor a Jeú, filho de Hanâni, contra Baasa, dizendo:' },
      { v: 2, en: '“Because I exalted you out of the dust, and made you prince over my people Israel, and you have walked in the way of Jeroboam, and have made my people Israel to sin, to provoke me to anger with their sins;', pt: 'Porquanto te exaltei do pó, e te constituí chefe sobre o meu povo Israel, e tu tens andado no caminho de Jeroboão, e tens feito o meu povo Israel pecar, provocando-me à ira com os seus pecados,' },
      { v: 3, en: 'behold, I will utterly sweep away Baasha and his house; and I will make your house like the house of Jeroboam the son of Nebat.', pt: 'eis que exterminarei os descendentes de Baasa, e os descendentes da casa dele; sim, tornarei a tua casa como a casa de Jeroboão, filho de Nebate.' },
      { v: 4, en: 'The dogs will eat Baasha’s descendants who die in the city; and he who dies of his in the field, the birds of the sky will eat.”', pt: 'Quem morrer a Baasa na cidade, comê-lo-ão os cães; e o que lhe morrer no campo, comê-lo-ão as aves do céu.' },
      { v: 5, en: 'Now the rest of the acts of Baasha, and what he did, and his might, aren’t they written in the book of the chronicles of the kings of Israel?', pt: 'Quanto ao restante dos atos de Baasa, e ao que fez, e ao seu poder, porventura não estão escritos no livro das crônicas dos reis de Israel?' },
      { v: 6, en: 'Baasha slept with his fathers, and was buried in Tirzah; and Elah his son reigned in his place.', pt: 'E Baasa dormiu com seus pais, e foi sepultado em Tirza. Então Elá, seu filho, reinou em seu lugar.' },
      { v: 7, en: 'Moreover Yahweh’s word came by the prophet Jehu the son of Hanani against Baasha and against his house, both because of all the evil that he did in Yahweh’s sight, to provoke him to anger with the work of his hands, in being like the house of Jeroboam, and because he struck him.', pt: 'Assim veio também a palavra do Senhor, por intermédio do profeta Jeú, filho de Hanâni, contra Baasa e contra a casa dele, não somente por causa de todo o mal que fizera aos olhos do Senhor, de modo a provocá-lo à ira com a obra de suas mãos, tornando-se como a casa de Jeroboão, mas também porque exterminara a casa de Jeroboão.' },
      { v: 8, en: 'In the twenty-sixth year of Asa king of Judah, Elah the son of Baasha began to reign over Israel in Tirzah for two years.', pt: 'No ano vinte e seis de Asa, rei de Judá, Elá, filho de Baasa, começou a reinar em Tirza sobre Israel, e reinou dois anos.' },
      { v: 9, en: 'His servant Zimri, captain of half his chariots, conspired against him. Now he was in Tirzah, drinking himself drunk in the house of Arza, who was over the household in Tirzah;', pt: 'E Zinri, seu servo, chefe de metade dos carros, conspirou contra ele. Ora, Elá achava-se em Tirza bebendo e embriagando-se em casa de Arza, que era o seu mordomo em Tirza.' },
      { v: 10, en: 'and Zimri went in and struck him, and killed him, in the twenty-seventh year of Asa king of Judah, and reigned in his place.', pt: 'Entrou, pois, Zinri e o feriu, e o matou, no ano vigésimo sétimo de Asa, rei de Judá, e reinou em seu lugar.' },
      { v: 11, en: 'When he began to reign, as soon as he sat on his throne, he attacked all the house of Baasha. He didn’t leave him a single one who urinates on a wall among his relatives or his friends.', pt: 'Quando ele começou a reinar, logo que se assentou no seu trono, feriu toda a casa de Baasa; não lhe deixou homem algum, nem de seus parentes, nem de seus amigos.' },
      { v: 12, en: 'Thus Zimri destroyed all the house of Baasha, according to Yahweh’s word, which he spoke against Baasha by Jehu the prophet,', pt: 'Assim destruiu Zinri toda a casa de Baasa, conforme a palavra do Senhor, que ele falara contra Baasa por intermédio do profeta Jeú,' },
      { v: 13, en: 'for all the sins of Baasha, and the sins of Elah his son, which they sinned, and with which they made Israel to sin, to provoke Yahweh, the God of Israel, to anger with their vanities.', pt: 'por causa de todos os pecados de Baasa, e dos pecados de Elá, seu filho, com que pecaram, e com que fizeram Israel pecar, provocando à ira, com as suas vaidades, o Senhor Deus de Israel.' },
      { v: 14, en: 'Now the rest of the acts of Elah, and all that he did, aren’t they written in the book of the chronicles of the kings of Israel?', pt: 'Quanto ao restante dos atos de Elá, e a tudo quanto fez, porventura não estão escritos no livro das crônicas dos reis de Israel?' },
      { v: 15, en: 'In the twenty-seventh year of Asa king of Judah, Zimri reigned seven days in Tirzah. Now the people were encamped against Gibbethon, which belonged to the Philistines.', pt: 'No ano vigésimo sétimo de Asa, rei de Judá, reinou Zinri sete dias em Tirza. Estava o povo acampado contra Gibetom, que pertencia aos filisteus.' },
      { v: 16, en: 'The people who were encamped heard that Zimri had conspired, and had also killed the king. Therefore all Israel made Omri, the captain of the army, king over Israel that day in the camp.', pt: 'E o povo que estava acampado ouviu dizer: Zinri conspirou, e matou o rei; pelo que no mesmo dia, no arraial, todo o Israel constituiu rei sobre Israel a Onri, chefe do exercito.' },
      { v: 17, en: 'Omri went up from Gibbethon, and all Israel with him, and they besieged Tirzah.', pt: 'Então Onri subiu de Gibetom com todo o Israel, e cercaram Tirza.' },
      { v: 18, en: 'When Zimri saw that the city was taken, he went into the fortified part of the king’s house, and burned the king’s house over him with fire, and died,', pt: 'Vendo Zinri que a cidade era tomada, entrou no castelo da casa do rei, e queimou-a sobre si; e morreu,' },
      { v: 19, en: 'for his sins which he sinned in doing that which was evil in Yahweh’s sight, in walking in the way of Jeroboam, and in his sin which he did, to make Israel to sin.', pt: 'por causa dos pecados que cometera, fazendo o que era mau aos olhos do Senhor, andando no caminho de Jeroboão, e no pecado que este cometera, fazendo Israel pecar.' },
      { v: 20, en: 'Now the rest of the acts of Zimri, and his treason that he committed, aren’t they written in the book of the chronicles of the kings of Israel?', pt: 'Quanto ao restante dos atos de Zinri, e à conspiração que fez, porventura não estão escritos no livro das crônicas dos reis de Israel?' },
      { v: 21, en: 'Then the people of Israel were divided into two parts: half of the people followed Tibni the son of Ginath, to make him king; and half followed Omri.', pt: 'Então o povo de Israel se dividiu em dois partidos: metade do povo seguia a Tíbni, filho de Ginate, para fazê-lo rei, e a outra metade seguia a Onri.' },
      { v: 22, en: 'But the people who followed Omri prevailed against the people who followed Tibni the son of Ginath; so Tibni died, and Omri reigned.', pt: 'Mas o povo que seguia a Onri prevaleceu contra o que seguia a Tíbni, filho de Ginate; de sorte que Tíbni morreu, e Onri reinou.' },
      { v: 23, en: 'In the thirty-first year of Asa king of Judah, Omri began to reign over Israel for twelve years. He reigned six years in Tirzah.', pt: 'No trigésimo primeiro ano de Asa, rei de Judá, Onri começou a reinar sobre Israel, e reinou doze anos. Reinou seis anos em Tirza.' },
      { v: 24, en: 'He bought the hill Samaria of Shemer for two talents of silver; and he built on the hill, and called the name of the city which he built Samaria, after the name of Shemer, the owner of the hill.', pt: 'E de Semer comprou o outeiro de Samária por dois talentos de prata, e edificou nele; e chamou a cidade que edificou Samária, do nome de Semer, dono do outeiro.' },
      { v: 25, en: 'Omri did that which was evil in Yahweh’s sight, and dealt wickedly above all who were before him.', pt: 'E fez Onri o que era mau aos olhos do Senhor; pior mesmo do que todos os que o antecederam.' },
      { v: 26, en: 'For he walked in all the way of Jeroboam the son of Nebat, and in his sins with which he made Israel to sin, to provoke Yahweh, the God of Israel, to anger with their vanities.', pt: 'Pois ele andou em todos os caminhos de Jeroboão, filho de Nebate, como também nos pecados com que este fizera Israel pecar, provocando à ira, com as suas vaidades, o Senhor Deus de Israel.' },
      { v: 27, en: 'Now the rest of the acts of Omri which he did, and his might that he showed, aren’t they written in the book of the chronicles of the kings of Israel?', pt: 'Quanto ao restante dos atos que Onri fez, e ao poder que manifestou, porventura não estão escritos no livro das crônicas dos reis de Israel?' },
      { v: 28, en: 'So Omri slept with his fathers, and was buried in Samaria; and Ahab his son reigned in his place.', pt: 'Onri dormiu com seus pais, e foi sepultado em Samária. E Acabe, seu filho, reinou em seu ugar.' },
      { v: 29, en: 'In the thirty-eighth year of Asa king of Judah, Ahab the son of Omri began to reign over Israel. Ahab the son of Omri reigned over Israel in Samaria twenty-two years.', pt: 'No trigésimo oitavo ano de Asa, rei de Judá, começou Acabe, filho de Onri, a reinar sobre Israel; e reinou sobre Israel em Samária vinte e dois anos.' },
      { v: 30, en: 'Ahab the son of Omri did that which was evil in Yahweh’s sight above all that were before him.', pt: 'E fez Acabe, filho de Onri, o que era mau aos olhos do Senhor, mais do que todos os que o antecederam.' },
      { v: 31, en: 'As if it had been a light thing for him to walk in the sins of Jeroboam the son of Nebat, he took as wife Jezebel the daughter of Ethbaal king of the Sidonians, and went and served Baal, and worshiped him.', pt: 'E, como se fosse pouco andar nos pecados de Jeroboão, filho de Nebate, ainda tomou por mulher a Jezabel, filha de Etbaal, rei dos sidônios, e foi e serviu a Baal, e o adorou;' },
      { v: 32, en: 'He raised up an altar for Baal in the house of Baal, which he had built in Samaria.', pt: 'e levantou um altar a Baal na casa de Baal que ele edificara em Samária;' },
      { v: 33, en: 'Ahab made the Asherah; and Ahab did more yet to provoke Yahweh, the God of Israel, to anger than all the kings of Israel who were before him.', pt: 'também fez uma asera. De maneira que Acabe fez muito mais para provocar à ira o Senhor Deus de Israel do que todos os reis de Israel que o antecederam.' },
      { v: 34, en: 'In his days Hiel the Bethelite built Jericho. He laid its foundation with the loss of Abiram his firstborn, and set up its gates with the loss of his youngest son Segub, according to Yahweh’s word, which he spoke by Joshua the son of Nun.', pt: 'Em seus dias Hiel, o betelita, edificou Jericó. Quando lançou os seus alicerces, morreu-lhe Abirão, seu primogênito; e quando colocou as suas portas, morreu-lhe Segube, seu filho mais moço; conforme a palavra do Senhor, que ele falara por intermédio de Josué, filho de Num.' },
    ],
    17: [
      { v: 1, en: 'Elijah the Tishbite, who was one of the settlers of Gilead, said to Ahab, “As Yahweh, the God of Israel, lives, before whom I stand, there shall not be dew nor rain these years, but according to my word.”', pt: 'Então Elias, o tisbita, que habitava em Gileade, disse a Acabe: Vive o Senhor, Deus de Israel, em cuja presença estou, que nestes anos não haverá orvalho nem chuva, senão segundo a minha palavra.' },
      { v: 2, en: 'Then Yahweh’s word came to him, saying,', pt: 'Depois veio a Elias a palavra do Senhor, dizendo:' },
      { v: 3, en: '“Go away from here, turn eastward, and hide yourself by the brook Cherith, that is before the Jordan.', pt: 'Retira-te daqui, vai para a banda de oriente, e esconde-te junto ao ribeiro de Querite, que está ao oriente do Jordão.' },
      { v: 4, en: 'You shall drink from the brook. I have commanded the ravens to feed you there.”', pt: 'Beberás do ribeiro; e eu tenho ordenado aos corvos que ali te sustentem.' },
      { v: 5, en: 'So he went and did according to Yahweh’s word; for he went and lived by the brook Cherith that is before the Jordan.', pt: 'Partiu, pois, e fez conforme a palavra do Senhor; foi habitar junto ao ribeiro de Querite, que está ao oriente do Jordão.' },
      { v: 6, en: 'The ravens brought him bread and meat in the morning, and bread and meat in the evening; and he drank from the brook.', pt: 'E os corvos lhe traziam pão e carne pela manhã, como também pão e carne à tarde; e ele bebia do ribeiro.' },
      { v: 7, en: 'After a while, the brook dried up, because there was no rain in the land.', pt: 'Mas, decorridos alguns dias, o ribeiro secou, porque não tinha havido chuva na terra.' },
      { v: 8, en: 'Yahweh’s word came to him, saying,', pt: 'Veio-lhe então a palavra do Senhor, dizendo:' },
      { v: 9, en: '“Arise, go to Zarephath, which belongs to Sidon, and stay there. Behold, I have commanded a widow there to sustain you.”', pt: 'Levanta-te, vai para Sarepta, que pertence a Sidom, e habita ali; eis que eu ordenei a uma mulher viúva ali que te sustente.' },
      { v: 10, en: 'So he arose and went to Zarephath; and when he came to the gate of the city, behold, a widow was there gathering sticks. He called to her, and said, “Please get me a little water in a jar, that I may drink.”', pt: 'Levantou-se, pois, e foi para Sarepta. Chegando ele à porta da cidade, eis que estava ali uma mulher viúva apanhando lenha; ele a chamou e lhe disse: Traze-me, peço-te, num vaso um pouco d\'água, para eu beber.' },
      { v: 11, en: 'As she was going to get it, he called to her, and said, “Please bring me a morsel of bread in your hand.”', pt: 'Quando ela ia buscá-la, ele a chamou e lhe disse: Traze-me também um bocado de pão contigo.' },
      { v: 12, en: 'She said, “As Yahweh your God lives, I don’t have a cake, but a handful of meal in a jar, and a little oil in a jar. Behold, I am gathering two sticks, that I may go in and bake it for me and my son, that we may eat it, and die.”', pt: 'Ela, porém, respondeu: Vive o Senhor teu Deus, que não tenho nem um bolo, senão somente um punhado de farinha na vasilha, e um pouco de azeite na botija; e eis que estou apanhando uns dois gravetos, para ir prepará-lo para mim e para meu filho, a fim de que o comamos, e morramos.' },
      { v: 13, en: 'Elijah said to her, “Don’t be afraid. Go and do as you have said; but make me a little cake from it first, and bring it out to me, and afterward make some for you and for your son.', pt: 'Ao que lhe disse Elias: Não temas; vai, faze como disseste; porém, faze disso primeiro para mim um bolo pequeno, e traze-mo aqui; depois o farás para ti e para teu filho.' },
      { v: 14, en: 'For Yahweh, the God of Israel says, ‘The jar of meal will not run out, and the jar of oil will not fail, until the day that Yahweh sends rain on the earth.’”', pt: 'Pois assim diz o Senhor Deus de Israel: A farinha da vasilha não se acabará, e o azeite da botija não faltará, até o dia em que o Senhor dê chuva sobre a terra.' },
      { v: 15, en: 'She went and did according to the saying of Elijah; and she, and he, and her house, ate many days.', pt: 'Ela foi e fez conforme a palavra de Elias; e assim comeram, ele, e ela e a sua casa, durante muitos dias.' },
      { v: 16, en: 'The jar of meal didn’t run out, and the jar of oil did not fail, according to Yahweh’s word, which he spoke by Elijah.', pt: 'Da vasilha a farinha não se acabou, e da botija o azeite não faltou, conforme a palavra do Senhor, que ele falara por intermédio de Elias.' },
      { v: 17, en: 'After these things, the son of the woman, the mistress of the house, became sick; and his sickness was so severe that there was no breath left in him.', pt: 'Depois destas coisas aconteceu adoecer o filho desta mulher, dona da casa; e a sua doença se agravou tanto, que nele não ficou mais fôlego.' },
      { v: 18, en: 'She said to Elijah, “What have I to do with you, you man of God? You have come to me to bring my sin to memory, and to kill my son!”', pt: 'Então disse ela a Elias: Que tenho eu contigo, ó homem de Deus? Vieste tu a mim para trazeres à memória a minha iniqüidade, e matares meu filho?' },
      { v: 19, en: 'He said to her, “Give me your son.” He took him out of her bosom, and carried him up into the room where he stayed, and laid him on his own bed.', pt: 'Respondeu-lhe ele: Dá-me o teu filho. E ele o tomou do seu regaço, e o levou para cima, ao quarto onde ele mesmo habitava, e o deitou em sua cama.' },
      { v: 20, en: 'He cried to Yahweh, and said, “Yahweh my God, have you also brought evil on the widow with whom I am staying, by killing her son?”', pt: 'E, clamando ao Senhor, disse: ç Senhor meu Deus, até sobre esta viúva, que me hospeda, trouxeste o mal, matando-lhe o filho?' },
      { v: 21, en: 'He stretched himself on the child three times, and cried to Yahweh, and said, “Yahweh my God, please let this child’s soul come into him again.”', pt: 'Então se estendeu sobre o menino três vezes, e clamou ao Senhor, dizendo: ç Senhor meu Deus, faze que a vida deste menino torne a entrar nele.' },
      { v: 22, en: 'Yahweh listened to the voice of Elijah; and the soul of the child came into him again, and he revived.', pt: 'O Senhor ouviu a voz de Elias, e a vida do menino tornou a entrar nele, e ele reviveu.' },
      { v: 23, en: 'Elijah took the child, and brought him down out of the room into the house, and delivered him to his mother; and Elijah said, “Behold, your son lives.”', pt: 'E Elias tomou o menino, trouxe-o do quarto à casa, e o entregou a sua mãe; e disse Elias: Vês aí, teu filho vive:' },
      { v: 24, en: 'The woman said to Elijah, “Now I know that you are a man of God, and that Yahweh’s word in your mouth is truth.”', pt: 'Então a mulher disse a Elias: Agora sei que tu és homem de Deus, e que a palavra do Senhor na tua boca é verdade.' },
    ],
    18: [
      { v: 1, en: 'After many days, Yahweh’s word came to Elijah, in the third year, saying, “Go, show yourself to Ahab; and I will send rain on the earth.”', pt: 'Depois de muitos dias veio a Elias a palavra do Senhor, no terceiro ano, dizendo: Vai, apresenta-te a Acabe; e eu mandarei chuva sobre a terra.' },
      { v: 2, en: 'Elijah went to show himself to Ahab. The famine was severe in Samaria.', pt: 'Então Elias foi apresentar-se a Acabe. E a fome era extrema em Samária.' },
      { v: 3, en: 'Ahab called Obadiah, who was over the household. (Now Obadiah feared Yahweh greatly;', pt: 'Acabe chamou a Obadias, o mordomo (ora, Obadias temia muito ao Senhor;' },
      { v: 4, en: 'for when Jezebel cut off Yahweh’s prophets, Obadiah took one hundred prophets, and hid them by fifty in a cave, and fed them with bread and water.)', pt: 'pois sucedeu que, destruindo Jezabel os profetas do Senhor, Obadias tomou cem profetas e os escondeu, cinqüenta numa cova e cinqüenta noutra, e os sustentou com pão e água);' },
      { v: 5, en: 'Ahab said to Obadiah, “Go through the land, to all the springs of water, and to all the brooks. Perhaps we may find grass and save the horses and mules alive, that we not lose all the animals.”', pt: 'e disse Acabe a Obadias: Vai pela terra a todas as fontes de água, e a todos os rios. Pode ser ser que achemos erva para salvar a vida dos cavalos e mulas, de maneira que não percamos todos os os animais.' },
      { v: 6, en: 'So they divided the land between them to pass throughout it. Ahab went one way by himself, and Obadiah went another way by himself.', pt: 'E repartiram entre si a terra, para a percorrerem; e foram a sós, Acabe por um caminho, e Obadias por outro.' },
      { v: 7, en: 'As Obadiah was on the way, behold, Elijah met him. He recognized him, and fell on his face, and said, “Is it you, my lord Elijah?”', pt: 'Quando, pois, Obadias já estava em caminho, eis que Elias se encontrou com ele; e Obadias, reconhecendo-o, prostrou-se com o rosto em terra e disse: És tu, meu senhor Elias?' },
      { v: 8, en: 'He answered him, “It is I. Go, tell your lord, ‘Behold, Elijah is here!’”', pt: 'Respondeu-lhe ele: Sou eu. Vai, dize a teu senhor: Eis que Elias está aqui.' },
      { v: 9, en: 'He said, “How have I sinned, that you would deliver your servant into the hand of Ahab, to kill me?', pt: 'Ele, porém, disse: Em que pequei, para que entregues teu servo na mão de Acabe, para ele me matar?' },
      { v: 10, en: 'As Yahweh your God lives, there is no nation or kingdom where my lord has not sent to seek you. When they said, ‘He is not here,’ he took an oath of the kingdom and nation, that they didn’t find you.', pt: 'Vive o Senhor teu Deus, que não há nação nem reino aonde o meu senhor não tenha mandado em busca de ti; e dizendo eles: Aqui não está; então fazia-os jurar que não te haviam achado.' },
      { v: 11, en: 'Now you say, ‘Go, tell your lord, “Behold, Elijah is here.”’', pt: 'Agora tu dizes: Vai, dize a teu senhor: Eis que Elias está aqui.' },
      { v: 12, en: 'It will happen, as soon as I leave you, that Yahweh’s Spirit will carry you I don’t know where; and so when I come and tell Ahab, and he can’t find you, he will kill me. But I, your servant, have feared Yahweh from my youth.', pt: 'E será que, apartando-me eu de ti, o Espírito do Senhor te levará não sei para onde; e, vindo eu dar as novas a Acabe, e não te achando ele, matar-me-á. Todavia eu, teu servo, temo ao Senhor desde a minha mocidade.' },
      { v: 13, en: 'Wasn’t it told my lord what I did when Jezebel killed Yahweh’s prophets, how I hid one hundred men of Yahweh’s prophets with fifty to a cave, and fed them with bread and water?', pt: 'Porventura não disseram a meu senhor o que fiz, quando Jezabel matava os profetas do Senhor, como escondi cem dos profetas do Senhor, cinqüenta numa cova e cinqüenta noutra, e os sustentei com pão e água:' },
      { v: 14, en: 'Now you say, ‘Go, tell your lord, “Behold, Elijah is here”.’ He will kill me.”', pt: 'E agora tu dizes: Vai, dize a teu senhor: Eis que Elias está aqui! Ele me matará.' },
      { v: 15, en: 'Elijah said, “As Yahweh of Armies lives, before whom I stand, I will surely show myself to him today.”', pt: 'E disse Elias: Vive o Senhor dos exércitos, em cuja presença estou, que dereras hoje hei de apresentar-me a ele.' },
      { v: 16, en: 'So Obadiah went to meet Ahab, and told him; and Ahab went to meet Elijah.', pt: 'Então foi Obadias encontrar-se com Acabe, e lho anunciou; e Acabe foi encontrar-se com Elias.' },
      { v: 17, en: 'When Ahab saw Elijah, Ahab said to him, “Is that you, you troubler of Israel?”', pt: 'E sucedeu que, vendo Acabe a Elias, disse-lhe: És tu, perturbador de Israel?' },
      { v: 18, en: 'He answered, “I have not troubled Israel; but you, and your father’s house, in that you have forsaken Yahweh’s commandments, and you have followed the Baals.', pt: 'Respondeu Elias: Não sou eu que tenho perturbado a Israel, mas és tu e a casa de teu pai, por terdes deixado os mandamentos do Senhor, e por teres tu seguido os baalins.' },
      { v: 19, en: 'Now therefore send, and gather to me all Israel to Mount Carmel, and four hundred fifty of the prophets of Baal, and four hundred of the prophets of the Asherah, who eat at Jezebel’s table.”', pt: 'Agora pois manda reunir-se a mim todo o Israel no monte Carmelo, como também os quatrocentos e cinquenta profetas de Baal, e os quatrocentos profetas de Asera, que comem da mesa de Jezabel.' },
      { v: 20, en: 'So Ahab sent to all the children of Israel, and gathered the prophets together to Mount Carmel.', pt: 'Então Acabe convocou todos os filhos de Israel, e reuniu os profetas no monte Carmelo.' },
      { v: 21, en: 'Elijah came near to all the people, and said, “How long will you waver between the two sides? If Yahweh is God, follow him; but if Baal, then follow him.” The people didn’t say a word.', pt: 'E Elias se chegou a todo o povo, e disse: Até quando coxeareis entre dois pensamentos? Se o Senhor é Deus, segui-o; mas se Baal, segui-o. O povo, porém, não lhe respondeu nada.' },
      { v: 22, en: 'Then Elijah said to the people, “I, even I only, am left as a prophet of Yahweh; but Baal’s prophets are four hundred fifty men.', pt: 'Então disse Elias ao povo: Só eu fiquei dos profetas do Senhor; mas os profetas de Baal são quatrocentos e cinqüenta homens.' },
      { v: 23, en: 'Let them therefore give us two bulls; and let them choose one bull for themselves, and cut it in pieces, and lay it on the wood, and put no fire under; and I will dress the other bull, and lay it on the wood, and put no fire under it.', pt: 'Dêem-se-nos, pois, dois novilhos; e eles escolham para si um dos novilhos, e o dividam em pedaços, e o ponham sobre a lenha, porém não lhe metam fogo; e eu prepararei o outro novilho, e o porei sobre a lenha, e não lhe meterei fogo.' },
      { v: 24, en: 'You call on the name of your god, and I will call on Yahweh’s name. The God who answers by fire, let him be God.” All the people answered, “What you say is good.”', pt: 'Então invocai o nome do vosso deus, e eu invocarei o nome do Senhor; e há de ser que o deus que responder por meio de fogo, esse será Deus. E todo o povo respondeu, dizendo: É boa esta palavra.' },
      { v: 25, en: 'Elijah said to the prophets of Baal, “Choose one bull for yourselves, and dress it first; for you are many; and call on the name of your god, but put no fire under it.”', pt: 'Disse, pois, Elias aos profetas de Baal: Escolhei para vós: um dos novilhos, e preparai-o primeiro, porque sois muitos, e invocai o nome do Senhor, vosso deus, mas não metais fogo ao sacrifício.' },
      { v: 26, en: 'They took the bull which was given them, and they dressed it, and called on the name of Baal from morning even until noon, saying, “Baal, hear us!” But there was no voice, and nobody answered. They leaped about the altar which was made.', pt: 'E, tomando o novilho que se lhes dera, prepararam-no, e invocaram o nome de Baal, desde a manhã até o meio-dia, dizendo: Ah Baal, responde-nos! Porém não houve voz; ninguém respondeu. E saltavam em volta do altar que tinham feito.' },
      { v: 27, en: 'At noon, Elijah mocked them, and said, “Cry aloud; for he is a god. Either he is deep in thought, or he has gone somewhere, or he is on a journey, or perhaps he sleeps and must be awakened.”', pt: 'Sucedeu que, ao meio-dia, Elias zombava deles, dizendo: Clamai em altas vozes, porque ele é um deus; pode ser que esteja falando, ou que tenha alguma coisa que fazer, ou que intente alguma viagem; talvez esteja dormindo, e necessite de que o acordem.' },
      { v: 28, en: 'They cried aloud, and cut themselves in their way with knives and lances, until the blood gushed out on them.', pt: 'E eles clamavam em altas vozes e, conforme o seu costume, se retalhavam com facas e com lancetas, até correr o sangue sobre eles.' },
      { v: 29, en: 'When midday was past, they prophesied until the time of the evening offering; but there was no voice, no answer, and nobody paid attention.', pt: 'Também sucedeu que, passado o meio dia, profetizaram eles até a hora de se oferecer o sacrifício da tarde. Porém não houve voz; ninguém respondeu, nem atendeu.' },
      { v: 30, en: 'Elijah said to all the people, “Come near to me!”; and all the people came near to him. He repaired Yahweh’s altar that had been thrown down.', pt: 'Então Elias disse a todo o povo: chegai-vos a mim. E todo o povo se chegou a ele. E Elias reparou o altar do Senhor, que havia sido derrubado.' },
      { v: 31, en: 'Elijah took twelve stones, according to the number of the tribes of the sons of Jacob, to whom Yahweh’s word came, saying, “Israel shall be your name.”', pt: 'Tomou doze pedras, conforme o número das tribos dos filhos de Jacó, ao qual viera a palavra do Senhor, dizendo: Israel será o teu nome;' },
      { v: 32, en: 'With the stones he built an altar in Yahweh’s name. He made a trench around the altar, large enough to contain two seahs of seed.', pt: 'e com as pedras edificou o altar em nome do Senhor; depois fez em redor do altar um rego, em que podiam caber duas medidas de semente.' },
      { v: 33, en: 'He put the wood in order, and cut the bull in pieces, and laid it on the wood. He said, “Fill four jars with water, and pour it on the burnt offering, and on the wood.”', pt: 'Então armou a lenha, e dividiu o novilho em pedaços, e o pôs sobre a lenha, e disse: Enchei de água quatro cântaros, e derramai-a sobre o holocausto e sobre a lenha.' },
      { v: 34, en: 'He said, “Do it a second time”; and they did it the second time. He said, “Do it a third time”; and they did it the third time.', pt: 'Disse ainda: fazei-o segunda vez; e o fizeram segunda vez. De novo disse: Fazei-o terceira vez; e o fizeram terceira vez.' },
      { v: 35, en: 'The water ran around the altar; and he also filled the trench with water.', pt: 'De maneira que a água corria ao redor do altar; e ele encheu de água também o rego.' },
      { v: 36, en: 'At the time of the evening offering, Elijah the prophet came near, and said, “Yahweh, the God of Abraham, of Isaac, and of Israel, let it be known today that you are God in Israel, and that I am your servant, and that I have done all these things at your word.', pt: 'Sucedeu pois que, sendo já hora de se oferecer o sacrifício da tarde, o profeta Elias se chegou, e disse: ç Senhor, Deus de Abraão, de Isaque, e de Israel, seja manifestado hoje que tu és Deus em Israel, e que eu sou teu servo, e que conforme a tua palavra tenho feito todas estas coisas.' },
      { v: 37, en: 'Hear me, Yahweh, hear me, that this people may know that you, Yahweh, are God, and that you have turned their heart back again.”', pt: 'Responde-me, ó Senhor, responde-me para que este povo conheça que tu, ó Senhor, és Deus, e que tu fizeste voltar o seu coração.' },
      { v: 38, en: 'Then Yahweh’s fire fell, and consumed the burnt offering, the wood, the stones, and the dust, and licked up the water that was in the trench.', pt: 'Então caiu fogo do Senhor, e consumiu o holocausto, a lenha, as pedras, e o pó, e ainda lambeu a água que estava no rego.' },
      { v: 39, en: 'When all the people saw it, they fell on their faces. They said, “Yahweh, he is God! Yahweh, he is God!”', pt: 'Quando o povo viu isto, prostraram-se todos com o rosto em terra e disseram: O senhor é Deus! O Senhor é Deus!' },
      { v: 40, en: 'Elijah said to them, “Seize the prophets of Baal! Don’t let one of them escape!” They seized them; and Elijah brought them down to the brook Kishon, and killed them there.', pt: 'Disse-lhes Elias: Agarrai os profetas de Baal! que nenhum deles escape: Agarraram-nos; e Elias os fez descer ao ribeiro de Quisom, onde os matou.' },
      { v: 41, en: 'Elijah said to Ahab, “Get up, eat and drink; for there is the sound of abundance of rain.”', pt: 'Então disse Elias a Acabe: Sobe, come e bebe, porque há ruído de abundante chuva.' },
      { v: 42, en: 'So Ahab went up to eat and to drink. Elijah went up to the top of Carmel; and he bowed himself down on the earth, and put his face between his knees.', pt: 'Acabe, pois, subiu para comer e beber; mas Elias subiu ao cume do Carmelo e, inclinando-se por terra, meteu o rosto entre os joelhos.' },
      { v: 43, en: 'He said to his servant, “Go up now, and look toward the sea.” He went up, and looked, and said, “There is nothing.” He said, “Go again” seven times.', pt: 'E disse ao seu moço: Sobe agora, e olha para a banda do mar. E ele subiu, olhou, e disse: Não há nada. Então disse Elias: Volta lá sete vezes.' },
      { v: 44, en: 'On the seventh time, he said, “Behold, a small cloud, like a man’s hand, is rising out of the sea.” He said, “Go up, tell Ahab, ‘Get ready and go down, so that the rain doesn’t stop you.’”', pt: 'Sucedeu que, à sétima vez, disse: Eis que se levanta do mar uma nuvem, do tamanho da mão dum homem: Então disse Elias: Sobe, e dize a Acabe: Aparelha o teu carro, e desce, para que a chuva não te impeça.' },
      { v: 45, en: 'In a little while, the sky grew black with clouds and wind, and there was a great rain. Ahab rode, and went to Jezreel.', pt: 'E sucedeu que em pouco tempo o céu se enegreceu de nuvens e vento, e caiu uma grande chuva. Acabe, subindo ao carro, foi para Jizreel:' },
      { v: 46, en: 'Yahweh’s hand was on Elijah; and he tucked his cloak into his belt and ran before Ahab to the entrance of Jezreel.', pt: 'E a mão do Senhor estava sobre Elias, o qual cingiu os lombos, e veio correndo perante Acabe, até a entrada de Jizreel.' },
    ],
    19: [
      { v: 1, en: 'Ahab told Jezebel all that Elijah had done, and how he had killed all the prophets with the sword.', pt: 'Ora, Acabe fez saber a Jezabel tudo quanto Elias havia feito, e como matara à espada todos os profetas.' },
      { v: 2, en: 'Then Jezebel sent a messenger to Elijah, saying, “So let the gods do to me, and more also, if I don’t make your life as the life of one of them by tomorrow about this time!”', pt: 'Então Jezabel mandou um mensageiro a Elias, a dizer-lhe: Assim me façam os deuses, e outro tanto, se até amanhã a estas horas eu não fizer a tua vida como a de um deles.' },
      { v: 3, en: 'When he saw that, he arose, and ran for his life, and came to Beersheba, which belongs to Judah, and left his servant there.', pt: 'Quando ele viu isto, levantou-se e, para escapar com vida, se foi. E chegando a Berseba, que pertence a Judá, deixou ali o seu moço.' },
      { v: 4, en: 'But he himself went a day’s journey into the wilderness, and came and sat down under a juniper tree. Then he requested for himself that he might die, and said, “It is enough. Now, O Yahweh, take away my life; for I am not better than my fathers.”', pt: 'Ele, porém, entrou pelo deserto caminho de um dia, e foi sentar-se debaixo de um zimbro; e pediu para si a morte, dizendo: Já basta, ó Senhor; toma agora a minha vida, pois não sou melhor do que meus pais.' },
      { v: 5, en: 'He lay down and slept under a juniper tree; and behold, an angel touched him, and said to him, “Arise and eat!”', pt: 'E deitando-se debaixo do zimbro, dormiu; e eis que um anjo o tocou, e lhe disse: Levanta-te e come.' },
      { v: 6, en: 'He looked, and behold, there was at his head a cake baked on the coals, and a jar of water. He ate and drank, and lay down again.', pt: 'Ele olhou, e eis que à sua cabeceira estava um pão cozido sobre as brasas, e uma botija de água. Tendo comido e bebido, tornou a deitar-se.' },
      { v: 7, en: 'Yahweh’s angel came again the second time, and touched him, and said, “Arise and eat, because the journey is too great for you.”', pt: 'O anjo do Senhor veio segunda vez, tocou-o, e lhe disse: Levanta-te e come, porque demasiado longa te será a viagem.' },
      { v: 8, en: 'He arose, and ate and drank, and went in the strength of that food forty days and forty nights to Horeb, God’s Mountain.', pt: 'Levantou-se, pois, e comeu e bebeu; e com a força desse alimento caminhou quarenta dias e quarenta noites até Horebe, o monte de Deus.' },
      { v: 9, en: 'He came to a cave there, and camped there; and behold, Yahweh’s word came to him, and he said to him, “What are you doing here, Elijah?”', pt: 'Ali entrou numa caverna, onde passou a noite. E eis que lhe veio a palavra do Senhor, dizendo: Que fazes aqui, Elias?' },
      { v: 10, en: 'He said, “I have been very jealous for Yahweh, the God of Armies; for the children of Israel have forsaken your covenant, thrown down your altars, and killed your prophets with the sword. I, even I only, am left; and they seek my life, to take it away.”', pt: 'Respondeu ele: Tenho sido muito zeloso pelo Senhor Deus dos exércitos; porque os filhos de Israel deixaram o teu pacto, derrubaram os teus altares, e mataram os teus profetas à espada; e eu, somente eu, fiquei, e buscam a minha vida para ma tirarem.' },
      { v: 11, en: 'He said, “Go out, and stand on the mountain before Yahweh.” Behold, Yahweh passed by, and a great and strong wind tore the mountains, and broke in pieces the rocks before Yahweh; but Yahweh was not in the wind. After the wind there was an earthquake; but Yahweh was not in the earthquake.', pt: 'Ao que Deus lhe disse: Vem cá fora, e põe-te no monte perante o Senhor: E eis que o Senhor passou; e um grande e forte vento fendia os montes e despedaçava as penhas diante do Senhor, porém o Senhor não estava no vento; e depois do vento um terremoto, porém o Senhor não estava no terremoto;' },
      { v: 12, en: 'After the earthquake a fire passed; but Yahweh was not in the fire. After the fire, there was a still small voice.', pt: 'e depois do terremoto um fogo, porém o Senhor não estava no fogo; e ainda depois do fogo uma voz mansa e delicada.' },
      { v: 13, en: 'When Elijah heard it, he wrapped his face in his mantle, went out, and stood in the entrance of the cave. Behold, a voice came to him, and said, “What are you doing here, Elijah?”', pt: 'E ao ouvi-la, Elias cobriu o rosto com a capa e, saindo, pôs-se à entrada da caverna. E eis que lhe veio uma voz, que dizia: Que fazes aqui, Elias?' },
      { v: 14, en: 'He said, “I have been very jealous for Yahweh, the God of Armies; for the children of Israel have forsaken your covenant, thrown down your altars, and killed your prophets with the sword. I, even I only, am left; and they seek my life, to take it away.”', pt: 'Respondeu ele: Tenho sido muito zeloso pelo Senhor Deus dos exércitos; porque os filhos de Israel deixaram o teu pacto, derrubaram os teus altares, e mataram os teus profetas à espada; e eu, somente eu, fiquei, e buscam a minha vida para ma tirarem.' },
      { v: 15, en: 'Yahweh said to him, “Go, return on your way to the wilderness of Damascus. When you arrive, anoint Hazael to be king over Syria.', pt: 'Então o Senhor lhe disse: Vai, volta pelo teu caminho para o deserto de Damasco; quando lá chegares, ungirás a Hazael para ser rei sobre a Síria.' },
      { v: 16, en: 'Anoint Jehu the son of Nimshi to be king over Israel; and anoint Elisha the son of Shaphat of Abel Meholah to be prophet in your place.', pt: 'E a Jeú, filho de Ninsi, ungirás para ser rei sobre Israel; bem como a Eliseu, filho de Safate de Abel-Meolá, ungirás para ser profeta em teu lugar.' },
      { v: 17, en: 'He who escapes from the sword of Hazael, Jehu will kill; and he who escapes from the sword of Jehu, Elisha will kill.', pt: 'E há de ser que o que escapar da espada de Hazael, matá-lo-á Jeú; e o que escapar da espada de Jeú, matá-lo-á Eliseu.' },
      { v: 18, en: 'Yet I reserved seven thousand in Israel, all the knees of which have not bowed to Baal, and every mouth which has not kissed him.”', pt: 'Todavia deixarei em Israel sete mil: todos os joelhos que não se dobraram a Baal, e toda boca que não o beijou.' },
      { v: 19, en: 'So he departed from there, and found Elisha the son of Shaphat, who was plowing with twelve yoke of oxen before him, and he with the twelfth. Elijah went over to him, and put his mantle on him.', pt: 'Partiu, pois, Elias dali e achou Eliseu, filho de Safate, que andava lavrando com doze juntas de bois adiante dele, estando ele com a duodécima; chegando-se Elias a Eliseu, lançou a sua capa sobre ele.' },
      { v: 20, en: 'Elisha left the oxen, and ran after Elijah, and said, “Let me please kiss my father and my mother, and then I will follow you.” He said to him, “Go back again; for what have I done to you?”', pt: 'Então, deixando este os bois, correu após Elias, e disse: Deixa-me beijar a meu pai e a minha mãe, e então te seguirei. Respondeu-lhe Elias: Vai, volta; pois, que te fiz eu?' },
      { v: 21, en: 'He returned from following him, and took the yoke of oxen, and killed them, and boiled their meat with the instruments of the oxen, and gave to the people, and they ate. Then he arose, and went after Elijah, and served him.', pt: 'Voltou, pois, de o seguir, tomou a junta de bois, e os matou, e com os aparelhos dos bois cozeu a carne, e a deu ao povo, e comeram. Então se levantou e seguiu a Elias, e o servia.' },
    ],
    20: [
      { v: 1, en: 'Ben Hadad the king of Syria gathered all his army together; and there were thirty-two kings with him, with horses and chariots. He went up and besieged Samaria, and fought against it.', pt: 'Ora, Bene-Hadade, rei da Síria, ajuntou todo o seu exército; e havia com ele trinta e dois reis, e cavalos e carros. Então subiu, cercou a Samária, e pelejou contra ela.' },
      { v: 2, en: 'He sent messengers to Ahab king of Israel, into the city, and said to him, “Thus says Ben Hadad,', pt: 'E enviou à cidade mensageiros a Acabe, rei de Israel, a dizer-lhe: Assim diz: Bene-Hadade:' },
      { v: 3, en: '‘Your silver and your gold is mine. Your wives also and your children, even the best, are mine.’”', pt: 'A tua prata e o teu ouro são meus; e também, das tuas mulheres e dos teus filhos, os melhores são meus.' },
      { v: 4, en: 'The king of Israel answered, “It is according to your saying, my lord, O king. I am yours, and all that I have.”', pt: 'Ao que respondeu o rei de Israel, dizendo: Conforme a tua palavra, ó rei meu senhor, sou teu, com tudo quanto tenho.' },
      { v: 5, en: 'The messengers came again, and said, “Ben Hadad says, ‘I sent indeed to you, saying, “You shall deliver me your silver, and your gold, and your wives, and your children;', pt: 'Tornaram a vir os mensageiros, e disseram: Assim fala Bene-Hadade, dizendo: Enviei-te, na verdade, mensageiros que dissessem: Tu me hás de entregar a tua prata e o teu ouro, as tuas mulheres e os teus filhos;' },
      { v: 6, en: 'but I will send my servants to you tomorrow about this time, and they will search your house, and the houses of your servants; whatever is pleasant in your eyes, they will put it in their hand, and take it away.”’”', pt: 'todavia amanhã a estas horas te enviarei os meus servos, os quais esquadrinharão a tua casa, e as casas dos teus servos; e há de ser que tudo o que de precioso tiveres, eles tomarão consigo e o levarão.' },
      { v: 7, en: 'Then the king of Israel called all the elders of the land, and said, “Please notice how this man seeks mischief; for he sent to me for my wives, and for my children, and for my silver, and for my gold; and I didn’t deny him.”', pt: 'Então o rei de Israel chamou todos os anciãos da terra, e disse: Notai agora, e vede como esse homem procura o mal; pois mandou pedir-me as minhas mulheres, os meus filhos, a minha prata e o meu ouro, e não os neguei.' },
      { v: 8, en: 'All the elders and all the people said to him, “Don’t listen, and don’t consent.”', pt: 'Responderam-lhe todos os anciãos e todo o povo: Não lhe dês ouvidos, nem consintas.' },
      { v: 9, en: 'Therefore he said to the messengers of Ben Hadad, “Tell my lord the king, ‘All that you sent for to your servant at the first I will do; but this thing I cannot do.’” The messengers departed, and brought him back the message.', pt: 'Pelo que disse aos mensageiros de Bene-Hadade: Dizei ao rei, meu senhor: Tudo o que a princípio mandaste pedir a teu servo, farei; porém isto não posso fazer. Voltaram os mensageiros, e lhe levaram a resposta.' },
      { v: 10, en: 'Ben Hadad sent to him, and said, “The gods do so to me, and more also, if the dust of Samaria will be enough for handfuls for all the people who follow me.”', pt: 'Tornou Bene-Hadade a enviar-lhe mensageiros, e disse: Assim me façam os deuses, e outro tanto, se o pó de Samária bastar para encher as mãos de todo o povo que me segue.' },
      { v: 11, en: 'The king of Israel answered, “Tell him, ‘Don’t let him who puts on his armor brag like he who takes it off.’”', pt: 'O rei de Israel, porém, respondeu: Dizei-lhe: Não se gabe quem se cinge das armas como aquele que as depõe.' },
      { v: 12, en: 'When Ben Hadad heard this message, as he was drinking, he and the kings, in the pavilions, he said to his servants, “Prepare to attack!” They prepared to attack the city.', pt: 'E sucedeu que, ouvindo ele esta palavra, estando a beber com os reis nas tendas, disse aos seus servos: Ponde-vos em ordem. E eles se puseram em ordem contra a cidade.' },
      { v: 13, en: 'Behold, a prophet came near to Ahab king of Israel, and said, “Yahweh says, ‘Have you seen all this great multitude? Behold, I will deliver it into your hand today. Then you will know that I am Yahweh.’”', pt: 'E eis que um profeta, chegando-se a Acabe, rei de Israel, lhe disse: Assim diz o Senhor: Viste toda esta grande multidão eis que hoje ta entregarei nas mãos, e saberás que eu sou o Senhor.' },
      { v: 14, en: 'Ahab said, “By whom?” He said, “Yahweh says, ‘By the young men of the princes of the provinces.’” Then he said, “Who shall begin the battle?” He answered, “You.”', pt: 'Perguntou Acabe: Por quem? Respondeu ele: Assim diz o Senhor: Pelos moços dos chefes das províncias. Ainda perguntou Acabe: Quem começará a peleja? Respondeu ele: Tu.' },
      { v: 15, en: 'Then he mustered the young men of the princes of the provinces, and they were two hundred and thirty-two. After them, he mustered all the people, even all the children of Israel, being seven thousand.', pt: 'Então contou os moços dos chefes das províncias, e eram duzentos e trinta e dois; e depois deles contou todo o povo, a saber, todos os filhos de Israel, e eram sete mil.' },
      { v: 16, en: 'They went out at noon. But Ben Hadad was drinking himself drunk in the pavilions, he and the kings, the thirty-two kings who helped him.', pt: 'Saíram, pois, ao meio-dia. Bene-Hadade, porém, estava bebendo e se embriagando nas tendas, com os reis, os trinta e dois reis que o ajudavam.' },
      { v: 17, en: 'The young men of the princes of the provinces went out first; and Ben Hadad sent out, and they told him, saying, “Men are coming out from Samaria.”', pt: 'E os moços dos chefes das províncias saíram primeiro; e Bene-Hadade enviou espias, que lhe deram aviso, dizendo: Saíram de Samária uns homens.' },
      { v: 18, en: 'He said, “If they have come out for peace, take them alive; or if they have come out for war, take them alive.”', pt: 'Ao que ele disse: Quer venham eles tratar de paz, quer venham à peleja, to-mai-os vivos.' },
      { v: 19, en: 'So these went out of the city, the young men of the princes of the provinces, and the army which followed them.', pt: 'Saíram, pois, da cidade os moços dos chefes das provincias, e o exército que os seguia.' },
      { v: 20, en: 'They each killed his man. The Syrians fled, and Israel pursued them. Ben Hadad the king of Syria escaped on a horse with horsemen.', pt: 'E eles mataram cada um o seu adversário. Então os sírios fugiram, e Israel os perseguiu; mas Bene-Hadade, rei da Síria, escapou a cavalo, com alguns cavaleiros.' },
      { v: 21, en: 'The king of Israel went out, and struck the horses and chariots, and killed the Syrians with a great slaughter.', pt: 'E saindo o rei de Israel, destruiu os cavalos e os carros, e infligiu aos sírios grande derrota.' },
      { v: 22, en: 'The prophet came near to the king of Israel, and said to him, “Go, strengthen yourself, and mark, and see what you do; for at the return of the year the king of Syria will come up against you.”', pt: 'Então o profeta chegou-se ao rei de Israel e lhe disse: Vai, fortalece-te; atenta bem para o que hás de fazer; porque decorrido um ano, o rei da Síria subirá contra ti.' },
      { v: 23, en: 'The servants of the king of Syria said to him, “Their god is a god of the hills; therefore they were stronger than we. But let us fight against them in the plain, and surely we will be stronger than they.', pt: 'Os servos do rei da Síria lhe disseram: Seus deuses são deuses dos montes, por isso eles foram mais fortes do que nós; mas pelejemos com eles na planície, e por certo prevaleceremos contra eles.' },
      { v: 24, en: 'Do this thing: take the kings away, every man out of his place, and put captains in their place.', pt: 'Faze, pois, isto: tira os reis, cada um do seu lugar, e substitui-os por capitães;' },
      { v: 25, en: 'Muster an army, like the army that you have lost, horse for horse, and chariot for chariot. We will fight against them in the plain, and surely we will be stronger than them.” He listened to their voice, and did so.', pt: 'arregimenta outro exército, igual ao exército que perdeste, cavalo por cavalo, e carro por carro; pelejemos com eles na planicie, e por certo prevaleceremos contra eles. Ele deu ouvidos ao que disseram, e assim fez.' },
      { v: 26, en: 'At the return of the year, Ben Hadad mustered the Syrians, and went up to Aphek, to fight against Israel.', pt: 'Passado um ano, Bene-Hadade arregimentou os sírios, e subiu a Afeque, para pelejar contra Israel.' },
      { v: 27, en: 'The children of Israel were mustered and given provisions, and went against them. The children of Israel encamped before them like two little flocks of young goats; but the Syrians filled the country.', pt: 'Também os filhos de Israel foram arregimentados e, providos de víveres, marcharam contra eles. E os filhos de Israel acamparam-se defronte deles, como dois pequenos rebanhos de cabras; mas os sírios enchiam a terra.' },
      { v: 28, en: 'A man of God came near and spoke to the king of Israel, and said, “Yahweh says, ‘Because the Syrians have said, “Yahweh is a god of the hills, but he is not a god of the valleys”; therefore I will deliver all this great multitude into your hand, and you shall know that I am Yahweh.’”', pt: 'Nisso chegou o homem de Deus, e disse ao rei de Israel: Assim diz o Senhor: Porquanto os sírios disseram: O Senhor é Deus dos montes, e não Deus dos vales, entregarei nas tuas mãos toda esta grande multidão, e saberás que eu sou o Senhor.' },
      { v: 29, en: 'They encamped opposite each other for seven days. So it was, that in the seventh day the battle was joined; and the children of Israel killed one hundred thousand footmen of the Syrians in one day.', pt: 'Assim, pois, estiveram acampados sete dias, uns defronte dos outros. Ao sétimo dia a peleja começou, e num só dia os filhos de Israel mataram dos sírios cem mil homens da infantaria.' },
      { v: 30, en: 'But the rest fled to Aphek, into the city; and the wall fell on twenty-seven thousand men who were left. Ben Hadad fled, and came into the city, into an inner room.', pt: 'E os restantes fugiram para Afeque, e entraram na cidade; e caiu o muro sobre vinte e sete mil homens que restavam. Bene-Hadade, porém, fugiu, e veio à cidade, onde se meteu numa câmara interior.' },
      { v: 31, en: 'His servants said to him, “See now, we have heard that the kings of the house of Israel are merciful kings. Please let us put sackcloth on our bodies, and ropes on our heads, and go out to the king of Israel. Maybe he will save your life.”', pt: 'Disseram-lhe os seus servos: Eis que temos ouvido dizer que os reis da casa de Israel são reis clementes; ponhamos, pois, sacos aos lombos, e cordas aos pescoços, e saiamos ao rei de Israel; pode ser que ele te poupe a vida.' },
      { v: 32, en: 'So they put sackcloth on their bodies and ropes on their heads, and came to the king of Israel, and said, “Your servant Ben Hadad says, ‘Please let me live.’” He said, “Is he still alive? He is my brother.”', pt: 'Então cingiram sacos aos lombos e cordas aos pescoços e, indo ter com o rei de Israel, disseram-lhe: Diz o teu servo Bene-Hadade: Deixa-me viver, rogo-te. Ao que disse Acabe: Pois ainda vive? É meu irmão.' },
      { v: 33, en: 'Now the men observed diligently, and hurried to take this phrase; and they said, “Your brother Ben Hadad.” Then he said, “Go, bring him.” Then Ben Hadad came out to him; and he caused him to come up into the chariot.', pt: 'Aqueles homens, tomando isto por bom presságio, apressaram- se em apanhar a sua palavra, e disseram: Bene-Hadade é teu irmão! Respondeu-lhes ele: Ide, trazei-me. Veio, pois, Bene-Hadade à presença de Acabe; e este o fez subir ao carro.' },
      { v: 34, en: 'Ben Hadad said to him, “The cities which my father took from your father I will restore. You shall make streets for yourself in Damascus, as my father made in Samaria.” “I”, said Ahab, “will let you go with this covenant.” So he made a covenant with him, and let him go.', pt: 'Então lhe disse Bene-Hadade: Eu te restituirei as cidades que meu pai tomou a teu pai; e farás para ti praças em Damasco, como meu pai as fez em Samária. E eu, respondeu Acabe, com esta aliança te deixarei ir. E fez com ele aliança e o deixou ir.' },
      { v: 35, en: 'A certain man of the sons of the prophets said to his fellow by Yahweh’s word, “Please strike me!” The man refused to strike him.', pt: 'Ora, certo homem dentre os filhos dos profetas disse ao seu companheiro, pela palavra do Senhor: Fere-me, peço-te. Mas o homem recusou feri-lo.' },
      { v: 36, en: 'Then he said to him, “Because you have not obeyed Yahweh’s voice, behold, as soon as you have departed from me, a lion will kill you.” As soon as he had departed from him, a lion found him and killed him.', pt: 'Pelo que ele lhe disse: Porquanto não obedeceste à voz do Senhor, eis que, em te apartando de mim, um leão te matará. E logo que se apartou dele um leão o encontrou e o matou.' },
      { v: 37, en: 'Then he found another man, and said, “Please strike me.” The man struck him and wounded him.', pt: 'Depois o profeta encontrou outro homem, e disse-lhe: Fere-me, peço-te. E aquele homem deu nele e o feriu.' },
      { v: 38, en: 'So the prophet departed, and waited for the king by the way, and disguised himself with his headband over his eyes.', pt: 'Então foi o profeta, pôs-se a esperar e rei no caminho, e disfarçou-se, cobrindo os olhos com o seu turbante.' },
      { v: 39, en: 'As the king passed by, he cried to the king; and he said, “Your servant went out into the middle of the battle; and behold, a man came over, and brought a man to me, and said, ‘Guard this man! If by any means he is missing, then your life shall be for his life, or else you shall pay a talent of silver.’', pt: 'E passando o rei, clamou ele ao rei, dizendo: Teu servo estava no meio da peleja; e eis que um homem, voltando-se, me trouxe um outro, e disse: Guarda-me este homem; se ele de qualquer maneira vier a faltar, a tua vida responderá pela vida dele, ou então pagarás um talento de prata.' },
      { v: 40, en: 'As your servant was busy here and there, he was gone.” The king of Israel said to him, “So shall your judgment be. You yourself have decided it.”', pt: 'E estando o teu servo ocupado de uma e de outra parte, eis que o homem desapareceu. Ao que lhe respondeu o rei de Israel: Esta é a tua sentença; tu mesmo a pronunciaste.' },
      { v: 41, en: 'He hurried, and took the headband away from his eyes; and the king of Israel recognized that he was one of the prophets.', pt: 'Então ele se apressou, e tirou o turbante de sobre os seus olhos; e o rei de Israel o reconheceu, que era um dos profetas.' },
      { v: 42, en: 'He said to him, “Yahweh says, ‘Because you have let go out of your hand the man whom I had devoted to destruction, therefore your life will take the place of his life, and your people take the place of his people.’”', pt: 'E disse ele ao rei: Assim diz o Senhor: Porquanto deixaste escapar da mão o homem que eu havia posto para destruição, a tua vida responderá pela sua vida, e o teu povo pelo seu povo.' },
      { v: 43, en: 'The king of Israel went to his house sullen and angry, and came to Samaria.', pt: 'E o rei de Israel seguiu para sua casa, desgostoso e indignado, e veio a Samária.' },
    ],
    21: [
      { v: 1, en: 'After these things, Naboth the Jezreelite had a vineyard, which was in Jezreel, next to the palace of Ahab king of Samaria.', pt: 'Sucedeu depois destas coisas que, tendo Nabote, o jizreelita, uma vinha em Jizrreel, junto ao palácio de Acabe, rei de Samária,' },
      { v: 2, en: 'Ahab spoke to Naboth, saying, “Give me your vineyard, that I may have it for a garden of herbs, because it is near my house; and I will give you for it a better vineyard than it. Or, if it seems good to you, I will give you its worth in money.”', pt: 'falou este a Nabote, dizendo: Dá-me a tua vinha, para que me sirva de horta, porque está vizinha, ao pé da minha casa; e te darei por ela outra vinha melhor; ou, se desejares, dar-te-ei o seu valor em dinheiro.' },
      { v: 3, en: 'Naboth said to Ahab, “May Yahweh forbid me, that I should give the inheritance of my fathers to you!”', pt: 'Respondeu, porém, Nabote a Acabe: Guarde-me o Senhor de que eu te dê a herança de meus pais.' },
      { v: 4, en: 'Ahab came into his house sullen and angry because of the word which Naboth the Jezreelite had spoken to him; for he had said, “I will not give you the inheritance of my fathers.” He laid himself down on his bed, and turned away his face, and would eat no bread.', pt: 'Então Acabe veio para sua casa, desgostoso e indignado, por causa da palavra que Nabote, o jizreelita, lhe falara; pois este lhe dissera: Não te darei a herança de meus pais. Tendo-se deitado na sua cama, virou a rosto, e não quis comer.' },
      { v: 5, en: 'But Jezebel his wife came to him, and said to him, “Why is your spirit so sad, that you eat no bread?”', pt: 'Mas, vindo a ele Jezabel, sua mulher, lhe disse: Por que está o teu espírito tão desgostoso que não queres comer?' },
      { v: 6, en: 'He said to her, “Because I spoke to Naboth the Jezreelite, and said to him, ‘Give me your vineyard for money; or else, if it pleases you, I will give you another vineyard for it.’ He answered, ‘I will not give you my vineyard.’”', pt: 'Ele lhe respondeu: Porque falei a Nabote, o jizreelita, e lhe disse: Dá-me a tua vinha por dinheiro; ou, se te apraz, te darei outra vinha em seu lugar. Ele, porém, disse: Não te darei a minha vinha.' },
      { v: 7, en: 'Jezebel his wife said to him, “Do you now govern the kingdom of Israel? Arise, and eat bread, and let your heart be merry. I will give you the vineyard of Naboth the Jezreelite.”', pt: 'Ao que Jezabel, sua mulher, lhe disse: Governas tu agora no reino de Israel? Levanta-te, come, e alegre-se o teu coração; eu te darei a vinha de Nabote, o jizreelita.' },
      { v: 8, en: 'So she wrote letters in Ahab’s name, and sealed them with his seal, and sent the letters to the elders and to the nobles who were in his city, who lived with Naboth.', pt: 'Então escreveu cartas em nome de Acabe e, selando-as com o sinete dele, mandou-as aos anciãos e aos nobres que habitavam com Nabote na sua cidade.' },
      { v: 9, en: 'She wrote in the letters, saying, “Proclaim a fast, and set Naboth on high among the people.', pt: 'Assim escreveu nas cartas: Apregoai um jejum, e ponde Nabote diante do povo.' },
      { v: 10, en: 'Set two men, wicked fellows, before him, and let them testify against him, saying, ‘You cursed God and the king!’ Then carry him out, and stone him to death.”', pt: 'E ponde defronte dele dois homens, filhos de Belial, que testemunhem contra ele, dizendo: Blasfemaste contra Deus e contra o rei. Depois conduzi-o para fora, e apedrejai-o até que morra.' },
      { v: 11, en: 'The men of his city, even the elders and the nobles who lived in his city, did as Jezebel had instructed them in the letters which she had written and sent to them.', pt: 'Pelo que os homens da cidade dele, isto é, os anciãos e os nobres que habitavam na sua cidade, fizeram como Jezabel lhes ordenara, conforme estava escrito nas cartas que ela lhes mandara.' },
      { v: 12, en: 'They proclaimed a fast, and set Naboth on high among the people.', pt: 'Apregoaram um jejum, e puseram Nabote diante do povo.' },
      { v: 13, en: 'The two men, the wicked fellows, came in and sat before him. The wicked fellows testified against him, even against Naboth, in the presence of the people, saying, “Naboth cursed God and the king!” Then they carried him out of the city and stoned him to death with stones.', pt: 'Também vieram dois homens, filhos de Belial, e sentaram-se defronte dele; e estes filhos de Belial testemunharam contra Nabote perante o povo, dizendo: Nabote blasfemou contra Deus e contra o rei. Então o conduziram para fora da cidade e o apedrejaram, de sorte que morreu.' },
      { v: 14, en: 'Then they sent to Jezebel, saying, “Naboth has been stoned, and is dead.”', pt: 'Depois mandaram dizer a Jezabel : Nabote foi apedrejado e morreu.' },
      { v: 15, en: 'When Jezebel heard that Naboth had been stoned, and was dead, Jezebel said to Ahab, “Arise, take possession of the vineyard of Naboth the Jezreelite, which he refused to give you for money; for Naboth is not alive, but dead.”', pt: 'Ora, ouvindo Jezabel que Nabote fora apedrejado e morrera, disse a Acabe: Levanta-te e toma posse da vinha de Nabote, e jizreelita, a qual ele recusou dar-te por dinheiro; porque Nabote já não vive, mas é morto.' },
      { v: 16, en: 'When Ahab heard that Naboth was dead, Ahab rose up to go down to the vineyard of Naboth the Jezreelite, to take possession of it.', pt: 'Quando Acabe ouviu que Nabote já era morto, levantou-se para descer à vinha de Nabote, o jizreelita, a fim de tomar posse dela.' },
      { v: 17, en: 'Yahweh’s word came to Elijah the Tishbite, saying,', pt: 'Então veio a palavra do Senhor a Elias, o tisbita, dizendo:' },
      { v: 18, en: '“Arise, go down to meet Ahab king of Israel, who dwells in Samaria. Behold, he is in the vineyard of Naboth, where he has gone down to take possession of it.', pt: 'Levanta-te, desce para encontrar-te com Acabe, rei de Israel, que está em Samária. Eis que está na vinha de Nabote, aonde desceu a fim de tomar posse dela.' },
      { v: 19, en: 'You shall speak to him, saying, ‘Yahweh says, “Have you killed and also taken possession?”’ You shall speak to him, saying, ‘Yahweh says, “In the place where dogs licked the blood of Naboth, dogs will lick your blood, even yours.”’”', pt: 'E falar-lhe-ás, dizendo: Assim diz o Senhor: Porventura não mataste e tomaste a herança? Falar-lhe-ás mais, dizendo: Assim diz o Senhor: No lugar em que os cães lamberam o sangue de Nabote, lamberão também o teu próprio sangue.' },
      { v: 20, en: 'Ahab said to Elijah, “Have you found me, my enemy?” He answered, “I have found you, because you have sold yourself to do that which is evil in Yahweh’s sight.', pt: 'Ao que disse Acabe a Elias: Já me achaste, ó inimigo meu? Respondeu ele: Achei-te; porque te vendeste para fazeres o que é mau aos olhos do Senhor.' },
      { v: 21, en: 'Behold, I will bring evil on you, and will utterly sweep you away and will cut off from Ahab everyone who urinates against a wall, and him who is shut up and him who is left at large in Israel.', pt: 'Eis que trarei o mal sobre ti; lançarei fora a tua posteridade, e arrancarei de Acabe todo homem, escravo ou livre, em Israel;' },
      { v: 22, en: 'I will make your house like the house of Jeroboam the son of Nebat, and like the house of Baasha the son of Ahijah for the provocation with which you have provoked me to anger, and have made Israel to sin.”', pt: 'e farei a tua casa como a casa de Jeroboão, filho de Nebate, e como a casa de Baasa, filho de Aías, por causa da provocação com que me provocaste à ira, fazendo Israel pecar.' },
      { v: 23, en: 'Yahweh also spoke of Jezebel, saying, “The dogs will eat Jezebel by the rampart of Jezreel.', pt: 'Também acerca de Jezabel falou o Senhor, dizendo: Os cães comerão Jezabel junto ao antemuro de Jizreel.' },
      { v: 24, en: 'The dogs will eat he who dies of Ahab in the city; and the birds of the sky will eat he who dies in the field.”', pt: 'Quem morrer a Acabe na cidade, os cães o comerão; e o que lhe morrer no campo, as aves do céu o comerão.' },
      { v: 25, en: 'But there was no one like Ahab, who sold himself to do that which was evil in Yahweh’s sight, whom Jezebel his wife stirred up.', pt: '(Não houve, porém, ninguém como Acabe, que se vendeu para fazer o que era mau aos olhos do Senhor, sendo instigado por Jezabel, sua mulher.' },
      { v: 26, en: 'He did very abominably in following idols, according to all that the Amorites did, whom Yahweh cast out before the children of Israel.', pt: 'E fez grandes abominações, seguindo os ídolos, conforme tudo o que fizeram os amorreus, os quais o Senhor lançou fora da sua possessão, de diante dos filhos de Israel.)' },
      { v: 27, en: 'When Ahab heard those words, he tore his clothes, and put sackcloth on his flesh, and fasted, and lay in sackcloth, and went softly.', pt: 'Sucedeu, pois, que Acabe, ouvindo estas palavras, rasgou as suas vestes, cobriu de saco a sua carne, e jejuou; e jazia em saco, e andava humildemente.' },
      { v: 28, en: 'Yahweh’s word came to Elijah the Tishbite, saying,', pt: 'Então veio a palavra do Senhor a Elias, o tisbita, dizendo:' },
      { v: 29, en: '“See how Ahab humbles himself before me? Because he humbles himself before me, I will not bring the evil in his days; but I will bring the evil on his house in his son’s day.”', pt: 'Não viste que Acabe se humilha perante mim? Por isso, porquanto se humilha perante mim, não trarei o mal enquanto ele viver, mas nos dias de seu filho trarei o mal sobre a sua casa.' },
    ],
    22: [
      { v: 1, en: 'They continued three years without war between Syria and Israel.', pt: 'Passaram-se três anos sem haver guerra entre a Síria e Israel.' },
      { v: 2, en: 'In the third year, Jehoshaphat the king of Judah came down to the king of Israel.', pt: 'No terceiro ano, porém, desceu Jeosafá, rei de Judá, a ter com o rei de Israel.' },
      { v: 3, en: 'The king of Israel said to his servants, “You know that Ramoth Gilead is ours, and we do nothing, and don’t take it out of the hand of the king of Syria?”', pt: 'E o rei de Israel disse aos seus servos: Não sabeis vós que Ramote-Gileade é nossa, e nós estamos quietos, sem a tomar da mão do rei da Síria?' },
      { v: 4, en: 'He said to Jehoshaphat, “Will you go with me to battle to Ramoth Gilead?” Jehoshaphat said to the king of Israel, “I am as you are, my people as your people, my horses as your horses.”', pt: 'Então perguntou a Jeosafá: Irás tu comigo à peleja, a Ramote-Gileade? Respondeu Jeosafá ao rei de Israel: Como tu és sou eu, o meu povo como o teu povo, e os meus cavalos como os teus cavalos.' },
      { v: 5, en: 'Jehoshaphat said to the king of Israel, “Please inquire first for Yahweh’s word.”', pt: 'Disse mais Jeosafá ao rei de Israel: Rogo-te, porém, que primeiro consultes a palavra do Senhor.' },
      { v: 6, en: 'Then the king of Israel gathered the prophets together, about four hundred men, and said to them, “Should I go against Ramoth Gilead to battle, or should I refrain?” They said, “Go up; for the Lord will deliver it into the hand of the king.”', pt: 'Então o rei de Israel ajuntou os profetas, cerca de quatrocentos homens, e perguntou-lhes: Irei à peleja contra Ramote- Gileade, ou deixarei de ir? Responderam eles: Sobe, porque o Senhor a entregará nas mãos do rei.' },
      { v: 7, en: 'But Jehoshaphat said, “Isn’t there here a prophet of Yahweh, that we may inquire of him?”', pt: 'Disse, porém, Jeosafá: Não há aqui ainda algum profeta do Senhor, ao qual possamos consultar?' },
      { v: 8, en: 'The king of Israel said to Jehoshaphat, “There is yet one man by whom we may inquire of Yahweh, Micaiah the son of Imlah; but I hate him, for he does not prophesy good concerning me, but evil.” Jehoshaphat said, “Don’t let the king say so.”', pt: 'Então disse o rei de Israel a Jeosafá: Ainda há um homem por quem podemos consultar ao Senhor - Micaías, filho de Inlá; porém eu o odeio, porque nunca profetiza o bem a meu respeito, mas somente o mal. Ao que disse Jeosafá: Não fale o rei assim.' },
      { v: 9, en: 'Then the king of Israel called an officer, and said, “Quickly get Micaiah the son of Imlah.”', pt: 'Então o rei de Israel chamou um eunuco, e disse: Traze-me depressa Micaías, filho de Inlá.' },
      { v: 10, en: 'Now the king of Israel and Jehoshaphat the king of Judah were sitting each on his throne, arrayed in their robes, in an open place at the entrance of the gate of Samaria; and all the prophets were prophesying before them.', pt: 'Ora, o rei de Israel e Jeosafá, rei de Judá, vestidos de seus trajes reais, estavam assentados cada um no seu trono, na praça à entrada da porta de Samária; e todos os profetas profetizavam diante deles.' },
      { v: 11, en: 'Zedekiah the son of Chenaanah made himself horns of iron, and said, “Yahweh says, ‘With these you will push the Syrians, until they are consumed.’”', pt: 'E Zedequias, filho de Quenaaná, fez para si uns chifres de ferro, e disse: Assim diz o Senhor: Com estes ferirás os sírios, até que sejam consumidos.' },
      { v: 12, en: 'All the prophets prophesied so, saying, “Go up to Ramoth Gilead, and prosper; for Yahweh will deliver it into the hand of the king.”', pt: 'Do mesmo modo também profetizavam todos os profetas, dizendo: Sobe a Ramote-Gileade, e serás bem sucedido; porque o Senhor a entregará nas mãos do rei.' },
      { v: 13, en: 'The messenger who went to call Micaiah spoke to him, saying, “See now, the prophets declare good to the king with one mouth. Please let your word be like the word of one of them, and speak good.”', pt: 'O mensageiro que fora chamar Micaías falou-lhe, dizendo: Eis que as palavras dos profetas, a uma voz, são favoráveis ao rei; seja, pois, a tua palavra como a de um deles, e fala o que é bom.' },
      { v: 14, en: 'Micaiah said, “As Yahweh lives, what Yahweh says to me, that I will speak.”', pt: 'Micaías, porém, disse: Vive o Senhor, que o que o Senhor me disser, isso falarei.' },
      { v: 15, en: 'When he had come to the king, the king said to him, “Micaiah, shall we go to Ramoth Gilead to battle, or shall we forbear?” He answered him, “Go up and prosper; and Yahweh will deliver it into the hand of the king.”', pt: 'Quando ele chegou à presença do rei, este lhe disse: Micaías, iremos a Ramote-Gileade à peleja, ou deixaremos de ir? Respondeu-lhe ele: Sobe, e serás bem sucedido, porque o Senhor a entregará nas mãos do rei.' },
      { v: 16, en: 'The king said to him, “How many times do I have to adjure you that you speak to me nothing but the truth in Yahweh’s name?”', pt: 'E o rei lhe disse: Quantas vezes hei de conjurar-te que não me fales senão a verdade em nome do Senhor?' },
      { v: 17, en: 'He said, “I saw all Israel scattered on the mountains, as sheep that have no shepherd. Yahweh said, ‘These have no master. Let them each return to his house in peace.’”', pt: 'Então disse ele: Vi todo o Israel disperso pelos montes, como ovelhas que não têm pastor; e disse o Senhor: Estes não têm senhor; torne cada um em paz para sua casa.' },
      { v: 18, en: 'The king of Israel said to Jehoshaphat, “Didn’t I tell you that he would not prophesy good concerning me, but evil?”', pt: 'Disse o rei de Israel a Jeosafá: Não te disse eu que ele não profetizaria o bem a meu respeito, mas somente o mal?' },
      { v: 19, en: 'Micaiah said, “Therefore hear Yahweh’s word. I saw Yahweh sitting on his throne, and all the army of heaven standing by him on his right hand and on his left.', pt: 'Micaías prosseguiu: Ouve, pois, a palavra do Senhor! Vi o Senhor assentado no seu trono, e todo o exército celestial em pé junto a ele, à sua direita e à sua esquerda.' },
      { v: 20, en: 'Yahweh said, ‘Who will entice Ahab, that he may go up and fall at Ramoth Gilead?’ One said one thing; and another said another.', pt: 'E o Senhor perguntou: Quem induzirá Acabe a subir, para que caia em Ramote-Gileade? E um respondia de um modo, e outro de outro.' },
      { v: 21, en: 'A spirit came out and stood before Yahweh, and said, ‘I will entice him.’', pt: 'Então saiu um espírito, apresentou-se diante do Senhor, e disse: Eu o induzirei. E o Senhor lhe perguntou: De que modo?' },
      { v: 22, en: 'Yahweh said to him, ‘How?’ He said, ‘I will go out and will be a lying spirit in the mouth of all his prophets.’ He said, ‘You will entice him, and will also prevail. Go out and do so.’', pt: 'Respondeu ele: Eu sairei, e serei um espírito mentiroso na boca de todos os seus profetas. Ao que disse o Senhor: Tu o induzirás, e prevalecerás; sai, e faze assim.' },
      { v: 23, en: 'Now therefore, behold, Yahweh has put a lying spirit in the mouth of all these your prophets; and Yahweh has spoken evil concerning you.”', pt: 'Agora, pois, eis que o Senhor pôs um espírito mentiroso na boca dentes da casa dele; sim, tornarei a tua casa como a casa de respeito de ti.' },
      { v: 24, en: 'Then Zedekiah the son of Chenaanah came near, and struck Micaiah on the cheek, and said, “Which way did Yahweh’s Spirit go from me to speak to you?”', pt: 'Então Zedequias, filho de Quenaaná, chegando-se, feriu a Micaías na face e disse: Por onde passou de mim o Espírito do Senhor para falar a ti?' },
      { v: 25, en: 'Micaiah said, “Behold, you will see on that day, when you go into an inner room to hide yourself.”', pt: 'Respondeu Micaías: Eis que tu o verás naquele dia, quando entrares numa câmara interior, para te esconderes.' },
      { v: 26, en: 'The king of Israel said, “Take Micaiah, and carry him back to Amon the governor of the city, and to Joash the king’s son.', pt: 'Então disse o rei de Israel: Tomai Micaías, e tornai a levá-lo a Amom, o governador da cidade, e a Joás, filho do rei,' },
      { v: 27, en: 'Say, ‘Thus says the king, “Put this fellow in the prison, and feed him with bread of affliction and with water of affliction, until I come in peace.”’”', pt: 'dizendo-lhes: Assim diz o rei: Metei este homem no cárcere, e sustentai-o a pão e água, até que eu volte em paz.' },
      { v: 28, en: 'Micaiah said, “If you return at all in peace, Yahweh has not spoken by me.” He said, “Listen, all you people!”', pt: 'Replicou Micaías: Se tu voltares em paz, o senhor não tem falado por mim. Disse mais: Ouvi, povos todos!' },
      { v: 29, en: 'So the king of Israel and Jehoshaphat the king of Judah went up to Ramoth Gilead.', pt: 'Assim o rei de Israel e Jeosafá, rei de Judá, subiram a Ramote-Gileade.' },
      { v: 30, en: 'The king of Israel said to Jehoshaphat, “I will disguise myself, and go into the battle; but you put on your robes.” The king of Israel disguised himself, and went into the battle.', pt: 'E disse o rei de Israel a Jeosafá: Eu me disfarçarei, e entrarei na peleja; tu, porém, veste os teus trajes reais. Disfarçou-se, pois, o rei de Israel, e entrou na peleja.' },
      { v: 31, en: 'Now the king of Syria had commanded the thirty-two captains of his chariots, saying, “Don’t fight with small nor great, except only with the king of Israel.”', pt: 'Ora, o rei da Síria tinha ordenado aos capitães dos carros, que eram trinta e dois, dizendo: Não pelejeis nem contra pequeno nem contra grande, senão só contra o rei de Israel.' },
      { v: 32, en: 'When the captains of the chariots saw Jehoshaphat, they said, “Surely that is the king of Israel!” and they came over to fight against him. Jehoshaphat cried out.', pt: 'E sucedeu que, vendo os capitães dos carros a Jeosafá, disseram: Certamente este é o rei de Israel. Viraram-se, pois, para pelejar com ele, e Jeosafá gritou.' },
      { v: 33, en: 'When the captains of the chariots saw that it was not the king of Israel, they turned back from pursuing him.', pt: 'Vendo os capitães dos carros que não era o rei de Israel, deixaram de segui-lo.' },
      { v: 34, en: 'A certain man drew his bow at random, and struck the king of Israel between the joints of the armor. Therefore he said to the driver of his chariot, “Turn your hand, and carry me out of the battle; for I am severely wounded.”', pt: 'Então um homem entesou o seu arco, e atirando a esmo, feriu o rei de Israel por entre a couraça e a armadura abdominal. Pelo que ele disse ao seu carreteiro: Dá volta, e tira-me do exército, porque estou gravemente ferido.' },
      { v: 35, en: 'The battle increased that day. The king was propped up in his chariot facing the Syrians, and died at evening. The blood ran out of the wound into the bottom of the chariot.', pt: 'E a peleja tornou-se renhida naquele dia; contudo o rei foi sustentado no carro contra os sírios; porém à tarde ele morreu; e o sangue da ferida corria para o fundo do carro.' },
      { v: 36, en: 'A cry went throughout the army about the going down of the sun, saying, “Every man to his city, and every man to his country!”', pt: 'Ao pôr do sol passou pelo exército a palavra: Cada um para a sua cidade, e cada um para a sua terra!' },
      { v: 37, en: 'So the king died, and was brought to Samaria; and they buried the king in Samaria.', pt: 'Morreu, pois, o rei, e o levaram para Samária, e ali o sepultaram.' },
      { v: 38, en: 'They washed the chariot by the pool of Samaria; and the dogs licked up his blood where the prostitutes washed themselves; according to Yahweh’s word which he spoke.', pt: 'E lavaram o seu carro junto ao tanque de Samária, e os cães lamberam-lhe o sangue, conforme a palavra que o Senhor tinha dito; ora, as prostitutas se banhavam ali.' },
      { v: 39, en: 'Now the rest of the acts of Ahab, and all that he did, and the ivory house which he built, and all the cities that he built, aren’t they written in the book of the chronicles of the kings of Israel?', pt: 'Quanto ao restante dos atos de Acabe, e a tudo quanto fez, e à casa de marfim que construiu, e a todas as cidades que edificou, porventura não estão escritos no livro das crônicas dos reis de Israel?' },
      { v: 40, en: 'So Ahab slept with his fathers; and Ahaziah his son reigned in his place.', pt: 'Assim dormiu Acabe com seus pais. E Acazias, seu filho, reinou em seu lugar.' },
      { v: 41, en: 'Jehoshaphat the son of Asa began to reign over Judah in the fourth year of Ahab king of Israel.', pt: 'Ora, Jeosafá, filho de Asa, começou a reinar sobre Judá no quarto ano de Acabe, rei de Israel.' },
      { v: 42, en: 'Jehoshaphat was thirty-five years old when he began to reign; and he reigned twenty-five years in Jerusalem. His mother’s name was Azubah the daughter of Shilhi.', pt: 'Era Jeosafá da idade de trinta e cinco anos quando começou a reinar, e reinou vinte e cinco anos em Jerusalém. Era o nome de sua mãe Azuba, filha de Sili.' },
      { v: 43, en: 'He walked in all the way of Asa his father. He didn’t turn away from it, doing that which was right in Yahweh’s eyes. However the high places were not taken away. The people still sacrificed and burned incense on the high places.', pt: 'E andou em todos os caminhos de seu pai Asa; não se desviou deles, mas fez o que era reto aos olhos do Senhor. Todavia os altos não foram tirados e o povo ainda sacrificava e queimava incenso nos altos.' },
      { v: 44, en: 'Jehoshaphat made peace with the king of Israel.', pt: 'E Jeosafá teve paz com o rei de Israel.' },
      { v: 45, en: 'Now the rest of the acts of Jehoshaphat, and his might that he showed, and how he fought, aren’t they written in the book of the chronicles of the kings of Judah?', pt: 'Quanto ao restante dos atos de Jeosafá, e ao poder que mostrou, e como guerreou, porventura não estão escritos no livro das crônicas dos reis de Judá?' },
      { v: 46, en: 'The remnant of the sodomites, that remained in the days of his father Asa, he put away out of the land.', pt: 'Também expulsou da terra o restante dos sodomitas, que ficaram nos dias de seu pai Asa' },
      { v: 47, en: 'There was no king in Edom. A deputy ruled.', pt: 'Nesse tempo não havia rei em Edom; um vice-rei governava.' },
      { v: 48, en: 'Jehoshaphat made ships of Tarshish to go to Ophir for gold, but they didn’t go; for the ships wrecked at Ezion Geber.', pt: 'E Jeosafá construiu navios de Társis para irem a Ofir em busca de ouro; porém não foram, porque os navios se quebraram em Eziom-Geber.' },
      { v: 49, en: 'Then Ahaziah the son of Ahab said to Jehoshaphat, “Let my servants go with your servants in the ships.” But Jehoshaphat would not.', pt: 'Então Acazias, filho de Acabe, disse a Jeosafá: Vão os meus servos com os teus servos nos navios. Jeosafá, porém, não quis.' },
      { v: 50, en: 'Jehoshaphat slept with his fathers, and was buried with his fathers in his father David’s city. Jehoram his son reigned in his place.', pt: 'Depois Jeosafá dormiu com seus pais, e foi sepultado junto a eles na cidade de Davi, seu pai. E em seu lugar reinou seu filho Jeorão.' },
      { v: 51, en: 'Ahaziah the son of Ahab began to reign over Israel in Samaria in the seventeenth year of Jehoshaphat king of Judah, and he reigned two years over Israel.', pt: 'Ora, Acazias, filho de Acabe, começou a reinar em Samaria no ano dezessete de Jeosafá, rei de Judá, e reinou dois anos sobre Israel.' },
      { v: 52, en: 'He did that which was evil in Yahweh’s sight, and walked in the way of his father, and in the way of his mother, and in the way of Jeroboam the son of Nebat, in which he made Israel to sin.', pt: 'E fez o que era mau aos olhos do Senhor; porque andou no caminho de seu pai, como também no caminho de sua mãe, e no caminho de Jeroboão, filho de Nebate, que fez Israel pecar.' },
      { v: 53, en: 'He served Baal and worshiped him, and provoked Yahweh, the God of Israel, to anger, in all the ways that his father had done so.', pt: 'Serviu a Baal, e o adorou, provocando à ira o Senhor Deus de Israel, conforme tudo quanto seu pai fizera.' },
    ],
  },
};

export default book;
